    setTasks(prev => prev.map(t => t.id === id ? { ...t, status: action === 'approve' ? TaskStatus.COMPLETED : TaskStatus.REJECTED } : t));
    setSelectedTask(null);
  };

  return (
    <div className="flex h-[calc(100vh-140px)] flex-col lg:flex-row gap-6 animate-fade-in">
