            <Filter size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto">
          {tasks.map(task => (
            <div 
              key={task.id}
              onClick={() => setSelectedTask(task)}
              className={`p-4 border-b border-slate-100 hover:bg-slate-50 cursor-pointer transition-colors ${selectedTask?.id === task.id ? 'bg-blue-50/50 border-l-4 border-l-brand-500' : 'border-l-4 border-l-transparent'}`}
            >
