import React, { useState } from 'react';
import { generateProcessWorkflow } from '../services/geminiService';
import { ProcessStep } from '../types';
import { Wand2, Plus, Save, Play, Settings, ArrowRight, User, Cog, GitBranch, Flag } from 'lucide-react';

export const ProcessDesigner: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleGenerate = async () => {
    if (!prompt.trim()) return;
    setLoading(true);
    setError('');
    try {
      const generatedSteps = await generateProcessWorkflow(prompt);
      setSteps(generatedSteps);
    } catch (e) {
      setError('Failed to generate workflow. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const getStepIcon = (type: string) => {
    switch (type) {
      case 'start': return <Play size={18} />;
      case 'end': return <Flag size={18} />;
      case 'user-task': return <User size={18} />;
      case 'service-task': return <Cog size={18} />;
      case 'decision': return <GitBranch size={18} />;
      default: return <Settings size={18} />;
    }
  };

  const getStepColor = (type: string) => {
    switch (type) {
      case 'start': return 'bg-green-100 text-green-700 border-green-200';
      case 'end': return 'bg-slate-800 text-white border-slate-800';
      case 'user-task': return 'bg-blue-50 text-blue-700 border-blue-200';
      case 'service-task': return 'bg-purple-50 text-purple-700 border-purple-200';
      case 'decision': return 'bg-amber-50 text-amber-700 border-amber-200';
      default: return 'bg-slate-50 text-slate-700 border-slate-200';
    }
  };

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col gap-6 animate-fade-in">
      {/* Header / Input Area */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 mb-2">AI Process Architect</h2>
        <p className="text-slate-500 text-sm mb-4">Describe your desired business process, and Gemini will engineer the workflow structure automatically.</p>

        <div className="flex gap-2">
          <input 
            type="text" 
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
            placeholder="e.g., 'Employee onboarding process for remote engineers' or 'CapEx approval chain > $10k'"
            className="flex-1 px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-brand-500 transition-all"
          />
          <button 
            onClick={handleGenerate}
            disabled={loading || !prompt}
            className="px-6 py-3 bg-brand-600 text-white rounded-lg font-medium text-sm flex items-center gap-2 hover:bg-brand-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-sm"
          >
            {loading ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <Wand2 size={18} />}
            Generate
          </button>
        </div>
        {error && <p className="text-red-500 text-xs mt-2">{error}</p>}
      </div>

      {/* Canvas Area */}
      <div className="flex-1 bg-slate-50 rounded-xl border border-slate-200 overflow-hidden relative flex flex-col">
        {steps.length === 0 ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400 p-8 text-center">
            <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-4">
              <Settings size={32} className="opacity-50" />
            </div>
            <h3 className="text-lg font-medium text-slate-600">Workflow Canvas Empty</h3>
            <p className="max-w-md mt-2 text-sm">Start by describing a process above. The AI will generate compliant BPMN 2.0 structure for you to refine.</p>
          </div>
        ) : (
          <div className="flex-1 overflow-y-auto p-8">
            <div className="max-w-3xl mx-auto relative pb-20">
              {/* Connecting Line */}
              <div className="absolute left-8 top-8 bottom-0 w-0.5 bg-slate-200 -z-10"></div>

              {steps.map((step, index) => (
                <div key={step.id || index} className="relative pl-20 mb-8 last:mb-0 group">
                  {/* Step Connector Node */}
                  <div className={`absolute left-[22px] top-8 w-5 h-5 rounded-full border-4 border-white ${index === steps.length - 1 ? 'bg-slate-800' : 'bg-brand-500'} shadow-sm z-10 ring-4 ring-slate-50`}></div>

                  {/* Card */}
                  <div className="bg-white p-5 rounded-lg border border-slate-200 shadow-sm hover:shadow-md transition-shadow cursor-default group-hover:border-brand-300">
                    <div className="flex justify-between items-start mb-2">
                      <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-md ${getStepColor(step.type)}`}>
                          {getStepIcon(step.type)}
                        </div>
                        <div>
                          <h4 className="font-bold text-slate-800 text-sm">{step.name}</h4>
                          <span className="text-[10px] uppercase font-bold tracking-wider text-slate-400">{step.type}</span>
                        </div>
                      </div>
                      {step.role && (
                        <span className="text-xs bg-slate-100 text-slate-600 px-2 py-1 rounded border border-slate-200">
                          {step.role}
                        </span>
                      )}
                    </div>
                    <p className="text-sm text-slate-600 leading-relaxed pl-[52px]">
                      {step.description}
                    </p>
                  </div>

                  {/* Arrow for flow */}
                  {index < steps.length - 1 && (
                     <div className="absolute left-8 -bottom-6 text-slate-300">
                       <ArrowRight className="rotate-90" size={16} />
                     </div>
                  )}
                </div>
              ))}

              <div className="mt-8 pl-20">
                 <button className="w-full py-3 border-2 border-dashed border-slate-200 rounded-lg text-slate-400 hover:text-brand-600 hover:border-brand-200 hover:bg-brand-50 transition-colors flex items-center justify-center gap-2 text-sm font-medium">
                    <Plus size={18} /> Add Manual Step
                 </button>
              </div>
            </div>
          </div>
        )}

        {/* Toolbar */}
        {steps.length > 0 && (
          <div className="p-4 bg-white border-t border-slate-200 flex justify-end gap-3">
             <button className="px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 font-medium text-sm transition-colors">
                Discard
             </button>
             <button className="px-4 py-2 bg-brand-600 text-white rounded-lg hover:bg-brand-700 font-medium text-sm flex items-center gap-2 shadow-sm transition-colors">
                <Save size={16} /> Deploy Process
             </button>
          </div>
        )}
      </div>
    </div>
  );
};

