export enum TaskStatus {
  PENDING = 'Pending',
  IN_PROGRESS = 'In Progress',
  COMPLETED = 'Completed',
  REJECTED = 'Rejected'
}

export enum TaskPriority {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export interface Task {
  id: string;
  title: string;
  processName: string;
  processInstanceId: string;
  assignee: string;
  dueDate: string;
  status: TaskStatus;
  priority: TaskPriority;
  description?: string;
  stepId: string;
  data?: any;
}

export interface ProcessStep {
  id: string;
  name: string;
  type: 'start' | 'user-task' | 'service-task' | 'decision' | 'end';
  description: string;
  role?: string;
}

export interface ProcessDefinition {
  id: string;
  name: string;
  description: string;
  steps: ProcessStep[];
  createdAt: string;
  deployedBy: string;
}

export interface TaskHistory {
  id: string;
  stepName: string;
  action: string;
  performer: string;
  timestamp: string;
  comments?: string;
}

export interface ProcessInstance {
  id: string;
  definitionId: string;
  definitionName: string;
  status: 'Active' | 'Completed' | 'Terminated';
  currentStepId: string | null;
  startDate: string;
  endDate?: string;
  history: TaskHistory[];
}

export type ViewState = 'dashboard' | 'inbox' | 'processes' | 'designer' | 'analytics';

import React, { createContext, useContext, useState, ReactNode } from 'react';
import { ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, ProcessStep, TaskHistory } from '../types';

interface BPMContextType {
