  instances: ProcessInstance[];
  tasks: Task[];
  deployProcess: (process: Omit<ProcessDefinition, 'id' | 'createdAt'>) => void;
  startProcess: (definitionId: string, inputData: any) => string;
  completeTask: (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => void;
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

// Initial Mock Data
const MOCK_PROCESSES: ProcessDefinition[] = [
  {
    id: 'proc-1',
