export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [processes, setProcesses] = useState<ProcessDefinition[]>(MOCK_PROCESSES);
  const [instances, setInstances] = useState<ProcessInstance[]>(MOCK_INSTANCES);
  const [tasks, setTasks] = useState<Task[]>(MOCK_TASKS);

  const deployProcess = (processData: Omit<ProcessDefinition, 'id' | 'createdAt'>) => {
    const newProcess: ProcessDefinition = {
      ...processData,
      id: `proc-${Date.now()}`,
      createdAt: new Date().toISOString(),
    };
    setProcesses(prev => [...prev, newProcess]);
  };

  const startProcess = (definitionId: string, inputData: any) => {
    const definition = processes.find(p => p.id === definitionId);
    if (!definition) throw new Error('Process definition not found');

    const instanceId = `inst-${Date.now()}`;
    const newInstance: ProcessInstance = {
      id: instanceId,
      definitionId,
      definitionName: definition.name,
      status: 'Active',
      currentStepId: definition.steps[0].id,
      startDate: new Date().toISOString(),
      history: [{
        id: `hist-${Date.now()}`,
        stepName: 'Start',
        action: 'Started',
        performer: 'User',
        timestamp: new Date().toISOString(),
        comments: inputData.summary
      }]
    };

    setInstances(prev => [newInstance, ...prev]);

    // Advance to first actionable step
    advanceWorkflow(newInstance, definition);
    return instanceId;
  };

  const completeTask = (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;

    // Update task status
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: TaskStatus.COMPLETED } : t));

    // Update Instance History
    const instance = instances.find(i => i.id === task.processInstanceId);
    if (instance) {
      const definition = processes.find(p => p.id === instance.definitionId);
      if (definition) {
        const historyEntry: TaskHistory = {
          id: `hist-${Date.now()}`,
          stepName: task.title,
          action: action,
          performer: 'CurrentUser', // In a real app, from auth
          timestamp: new Date().toISOString(),
          comments
        };

        const updatedInstance = {
          ...instance,
          history: [...instance.history, historyEntry]
        };

        // Handle Rejection (Terminate or Loop back - Simulating Termination for now)
        if (action === 'reject') {
           updatedInstance.status = 'Terminated';
           updatedInstance.endDate = new Date().toISOString();
           setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));
           return;
        }

        // Advance
        setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));
        advanceWorkflow(updatedInstance, definition);
      }
    }
  };

  // Engine Logic: Move to next step
  const advanceWorkflow = (instance: ProcessInstance, definition: ProcessDefinition) => {
    // Current step index
    const currentIndex = definition.steps.findIndex(s => s.id === instance.currentStepId);
    if (currentIndex === -1) return;

    const nextStep = definition.steps[currentIndex + 1];

    if (!nextStep || nextStep.type === 'end') {
      // Finish Process
      setInstances(prev => prev.map(i => i.id === instance.id ? { 
        ...i, 
        status: 'Completed', 
        endDate: new Date().toISOString(),
        currentStepId: nextStep ? nextStep.id : null
      } : i));
      return;
    }

    // Update Instance current step
    setInstances(prev => prev.map(i => i.id === instance.id ? { ...i, currentStepId: nextStep.id } : i));

    if (nextStep.type === 'user-task') {
      // Create Task
      const newTask: Task = {
        id: `T-${Date.now()}`,
        title: nextStep.name,
        processName: definition.name,
        processInstanceId: instance.id,
        assignee: nextStep.role || 'Unassigned',
        dueDate: new Date(Date.now() + 86400000 * 3).toISOString().split('T')[0], // +3 days
        status: TaskStatus.PENDING,
        priority: TaskPriority.MEDIUM,
        description: nextStep.description,
        stepId: nextStep.id
      };
      setTasks(prev => [newTask, ...prev]);
    } else if (nextStep.type === 'service-task') {
      // Auto-execute Service Task
      setTimeout(() => {
        // Log auto execution
        setInstances(prev => {
           const current = prev.find(i => i.id === instance.id);
           if(!current) return prev;
           return prev.map(i => i.id === instance.id ? {
             ...i,
             history: [...i.history, {
               id: `hist-${Date.now()}`,
               stepName: nextStep.name,
               action: 'System Executed',
               performer: 'System',
               timestamp: new Date().toISOString()
             }]
           } : i);
        });
        // Recursively advance
        // Note: In a real app we'd need to fetch the fresh instance state, but here we pass the derived state
        // To keep it simple, we just call advance again with the *next* step logic conceptually
        // For this mock, we actually need to grab the fresh state or pass the modified objects.
        // Let's simplified: just call advance again with updated "current step" pointer in a new tick
        const nextInstanceMock = { ...instance, currentStepId: nextStep.id }; 
        advanceWorkflow(nextInstanceMock, definition);
      }, 2000);
    }
  };

  return (
    <BPMContext.Provider value={{ processes, instances, tasks, deployProcess, startProcess, completeTask }}>
      {children}
    </BPMContext.Provider>
  );
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

