export const ProcessDesigner: React.FC = () => {
  const { deployProcess } = useBPM();
  const [prompt, setPrompt] = useState('');
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleGenerate = async () => {
    if (!prompt.trim()) return;
    setLoading(true);
    setError('');
    try {
      const generatedSteps = await generateProcessWorkflow(prompt);
      setSteps(generatedSteps);
    } catch (e) {
      setError('Failed to generate workflow. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleDeploy = () => {
    if (steps.length === 0) return;
    deployProcess({
      name: prompt.length > 30 ? prompt.substring(0, 30) + '...' : prompt,
      description: `Generated from prompt: ${prompt}`,
      deployedBy: 'Admin',
      steps: steps
    });
    alert('Process deployed successfully to the Repository.');
    setSteps([]);
    setPrompt('');
  };

  const getStepIcon = (type: string) => {
    switch (type) {
      case 'start': return <Play size={18} />;
      case 'end': return <Flag size={18} />;
      case 'user-task': return <User size={18} />;
      case 'service-task': return <Cog size={18} />;
      case 'decision': return <GitBranch size={18} />;
      default: return <Settings size={18} />;
    }
  };

  const getStepColor = (type: string) => {
    switch (type) {
      case 'start': return 'bg-green-100 text-green-700 border-green-200';
      case 'end': return 'bg-slate-800 text-white border-slate-800';
      case 'user-task': return 'bg-blue-50 text-blue-700 border-blue-200';
      case 'service-task': return 'bg-purple-50 text-purple-700 border-purple-200';
      case 'decision': return 'bg-amber-50 text-amber-700 border-amber-200';
      default: return 'bg-slate-50 text-slate-700 border-slate-200';
    }
  };

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col gap-6 animate-fade-in">
      {/* Header / Input Area */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 mb-2">AI Process Architect</h2>
        <p className="text-slate-500 text-sm mb-4">Describe your desired business process, and Gemini will engineer the workflow structure automatically.</p>

        <div className="flex gap-2">
          <input 
            type="text" 
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
            placeholder="e.g., 'Employee onboarding process for remote engineers' or 'CapEx approval chain > $10k'"
            className="flex-1 px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-brand-500 transition-all"
          />
          <button 
            onClick={handleGenerate}
            disabled={loading || !prompt}
