import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, TaskHistory } from '../types';
import { dbService } from '../services/dbService';

interface BPMContextType {
  processes: ProcessDefinition[];
  instances: ProcessInstance[];
  tasks: Task[];
  loading: boolean;
  deployProcess: (process: Omit<ProcessDefinition, 'id' | 'createdAt'>) => Promise<void>;
  startProcess: (definitionId: string, inputData: any) => Promise<string>;
  completeTask: (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => Promise<void>;

  // Data Management
  resetSystem: () => Promise<void>;
  reseedSystem: () => Promise<void>;
  exportData: () => Promise<void>;
  importData: (file: File) => Promise<void>;
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [processes, setProcesses] = useState<ProcessDefinition[]>([]);
  const [instances, setInstances] = useState<ProcessInstance[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [loading, setLoading] = useState(true);

  // Initial Data Load
  const loadData = async () => {
    setLoading(true);
    try {
      // Ensure DB is open and populated if empty
      const existingProcs = await dbService.getAll<ProcessDefinition>('processes');
      if (existingProcs.length === 0) {
        await dbService.reseed();
      }

      const p = await dbService.getAll<ProcessDefinition>('processes');
      const i = await dbService.getAll<ProcessInstance>('instances');
      const t = await dbService.getAll<Task>('tasks');

      setProcesses(p);
      setInstances(i);
      setTasks(t);
    } catch (e) {
      console.error("Failed to load data from DB", e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const deployProcess = async (processData: Omit<ProcessDefinition, 'id' | 'createdAt'>) => {
    const newProcess: ProcessDefinition = {
      ...processData,
      id: `proc-${Date.now()}`,
      createdAt: new Date().toISOString(),
    };
    await dbService.add('processes', newProcess);
    setProcesses(prev => [...prev, newProcess]);
  };

  const startProcess = async (definitionId: string, inputData: any) => {
    const definition = processes.find(p => p.id === definitionId);
    if (!definition) throw new Error('Process definition not found');

    const instanceId = `inst-${Date.now()}`;
    const newInstance: ProcessInstance = {
      id: instanceId,
      definitionId,
      definitionName: definition.name,
      status: 'Active',
      currentStepId: definition.steps[0].id,
      startDate: new Date().toISOString(),
      history: [{
        id: `hist-${Date.now()}`,
        stepName: 'Start',
        action: 'Started',
        performer: 'User',
        timestamp: new Date().toISOString(),
        comments: inputData.summary
      }]
    };

    await dbService.add('instances', newInstance);
    setInstances(prev => [newInstance, ...prev]);

    // Advance to first actionable step
    await advanceWorkflow(newInstance, definition);
    return instanceId;
  };

  const completeTask = async (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;

    // Update task status
    const updatedTask = { ...task, status: TaskStatus.COMPLETED };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));

    // Update Instance History
    const instance = instances.find(i => i.id === task.processInstanceId);
    if (instance) {
      const definition = processes.find(p => p.id === instance.definitionId);
      if (definition) {
        const historyEntry: TaskHistory = {
          id: `hist-${Date.now()}`,
          stepName: task.title,
          action: action,
          performer: 'CurrentUser',
          timestamp: new Date().toISOString(),
          comments
        };

        let updatedInstance = {
          ...instance,
          history: [...instance.history, historyEntry]
        };

        if (action === 'reject') {
           updatedInstance.status = 'Terminated';
           updatedInstance.endDate = new Date().toISOString();
           await dbService.add('instances', updatedInstance);
           setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));
           return;
        }

        await dbService.add('instances', updatedInstance);
        setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));

        await advanceWorkflow(updatedInstance, definition);
      }
    }
  };

  const advanceWorkflow = async (instance: ProcessInstance, definition: ProcessDefinition) => {
    const currentIndex = definition.steps.findIndex(s => s.id === instance.currentStepId);
    if (currentIndex === -1) return;

    const nextStep = definition.steps[currentIndex + 1];

    if (!nextStep || nextStep.type === 'end') {
      const completedInstance: ProcessInstance = { 
        ...instance, 
        status: 'Completed', 
        endDate: new Date().toISOString(),
        currentStepId: nextStep ? nextStep.id : null
      };
      await dbService.add('instances', completedInstance);
      setInstances(prev => prev.map(i => i.id === instance.id ? completedInstance : i));
      return;
    }

    const nextInstanceState = { ...instance, currentStepId: nextStep.id };
    await dbService.add('instances', nextInstanceState);
    setInstances(prev => prev.map(i => i.id === instance.id ? nextInstanceState : i));

    if (nextStep.type === 'user-task') {
      const newTask: Task = {
        id: `T-${Date.now()}`,
        title: nextStep.name,
        processName: definition.name,
        processInstanceId: instance.id,
        assignee: nextStep.role || 'Unassigned',
        dueDate: new Date(Date.now() + 86400000 * 3).toISOString().split('T')[0],
        status: TaskStatus.PENDING,
        priority: TaskPriority.MEDIUM,
        description: nextStep.description,
        stepId: nextStep.id
      };
      await dbService.add('tasks', newTask);
      setTasks(prev => [newTask, ...prev]);
    } else if (nextStep.type === 'service-task') {
      // Auto-execute Service Task with a delay
      setTimeout(async () => {
        // We need to fetch the LATEST instance state from DB or Context to avoid stale closures
        // For simplicity in this mock, we assume 'nextInstanceState' is valid base

        // Log auto execution
        const historyEntry: TaskHistory = {
             id: `hist-${Date.now()}`,
             stepName: nextStep.name,
             action: 'System Executed',
             performer: 'System',
             timestamp: new Date().toISOString()
        };

        // Get fresh state reference for next recursion
        const freshInstance = {
            ...nextInstanceState,
            history: [...nextInstanceState.history, historyEntry]
        };

        await dbService.add('instances', freshInstance);
        setInstances(prev => prev.map(i => i.id === instance.id ? freshInstance : i));

        await advanceWorkflow(freshInstance, definition);
      }, 2000);
    }
  };

  // --- Management Methods ---

  const resetSystem = async () => {
    setLoading(true);
    await dbService.resetDB();
    // After delete, reload will reseed automatically in loadData
    await loadData();
    setLoading(false);
  };

  const reseedSystem = async () => {
    setLoading(true);
    await dbService.reseed();
    await loadData();
    setLoading(false);
  };

  const exportData = async () => {
    const json = await dbService.exportData();
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `nexflow_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importData = async (file: File) => {
    return new Promise<void>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = async (e) => {
        try {
           const json = e.target?.result as string;
           await dbService.importData(json);
           await loadData();
           resolve();
        } catch (err) {
           reject(err);
        }
      };
      reader.onerror = reject;
      reader.readAsText(file);
    });
  };

  return (
    <BPMContext.Provider value={{ 
      processes, 
      instances, 
      tasks, 
      loading, 
      deployProcess, 
      startProcess, 
      completeTask,
      resetSystem,
      reseedSystem,
      exportData,
      importData
    }}>
      {children}
    </BPMContext.Provider>
  );
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

export enum TaskStatus {
  PENDING = 'Pending',
  IN_PROGRESS = 'In Progress',
  COMPLETED = 'Completed',
  REJECTED = 'Rejected'
}

export enum TaskPriority {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export interface Task {
  id: string;
  title: string;
  processName: string;
  processInstanceId: string;
  assignee: string;
  dueDate: string;
  status: TaskStatus;
  priority: TaskPriority;
  description?: string;
  stepId: string;
  data?: any;
}

export interface ProcessStep {
  id: string;
  name: string;
  type: 'start' | 'user-task' | 'service-task' | 'decision' | 'end';
  description: string;
  role?: string;
  // Graph execution properties
  nextStepId?: string;
  position?: { x: number; y: number };
}

export interface ProcessDefinition {
  id: string;
  name: string;
  description: string;
  steps: ProcessStep[];
  createdAt: string;
  deployedBy: string;
}

export interface TaskHistory {
  id: string;
  stepName: string;
  action: string;
  performer: string;
  timestamp: string;
  comments?: string;
}

export interface ProcessInstance {
  id: string;
  definitionId: string;
  definitionName: string;
  status: 'Active' | 'Completed' | 'Terminated';
  currentStepId: string | null;
  startDate: string;
  endDate?: string;
  history: TaskHistory[];
}

export type ViewState = 'dashboard' | 'inbox' | 'processes' | 'designer' | 'analytics' | 'settings';

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, TaskHistory, ProcessStep } from '../types';
import { dbService } from '../services/dbService';

interface BPMContextType {
  processes: ProcessDefinition[];
  instances: ProcessInstance[];
  tasks: Task[];
  loading: boolean;
  deployProcess: (process: Omit<ProcessDefinition, 'id' | 'createdAt'>) => Promise<void>;
  startProcess: (definitionId: string, inputData: any) => Promise<string>;
  completeTask: (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => Promise<void>;

  // Data Management
  resetSystem: () => Promise<void>;
  reseedSystem: () => Promise<void>;
  exportData: () => Promise<void>;
  importData: (file: File) => Promise<void>;
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [processes, setProcesses] = useState<ProcessDefinition[]>([]);
  const [instances, setInstances] = useState<ProcessInstance[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [loading, setLoading] = useState(true);

  // Initial Data Load
  const loadData = async () => {
    setLoading(true);
    try {
      // Ensure DB is open and populated if empty
      const existingProcs = await dbService.getAll<ProcessDefinition>('processes');
      if (existingProcs.length === 0) {
        await dbService.reseed();
      }

      const p = await dbService.getAll<ProcessDefinition>('processes');
      const i = await dbService.getAll<ProcessInstance>('instances');
      const t = await dbService.getAll<Task>('tasks');

      setProcesses(p);
      setInstances(i);
      setTasks(t);
    } catch (e) {
      console.error("Failed to load data from DB", e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const deployProcess = async (processData: Omit<ProcessDefinition, 'id' | 'createdAt'>) => {
    const newProcess: ProcessDefinition = {
      ...processData,
      id: `proc-${Date.now()}`,
      createdAt: new Date().toISOString(),
    };
    await dbService.add('processes', newProcess);
    setProcesses(prev => [...prev, newProcess]);
  };

  const startProcess = async (definitionId: string, inputData: any) => {
    const definition = processes.find(p => p.id === definitionId);
    if (!definition) throw new Error('Process definition not found');

    const instanceId = `inst-${Date.now()}`;
    const newInstance: ProcessInstance = {
      id: instanceId,
      definitionId,
      definitionName: definition.name,
      status: 'Active',
      currentStepId: definition.steps[0].id,
      startDate: new Date().toISOString(),
      history: [{
        id: `hist-${Date.now()}`,
        stepName: 'Start',
        action: 'Started',
        performer: 'User',
        timestamp: new Date().toISOString(),
        comments: inputData.summary
      }]
    };

    await dbService.add('instances', newInstance);
    setInstances(prev => [newInstance, ...prev]);

    // Advance to first actionable step
    await advanceWorkflow(newInstance, definition);
    return instanceId;
  };

  const completeTask = async (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;

    // Update task status
    const updatedTask = { ...task, status: TaskStatus.COMPLETED };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));

    // Update Instance History
    const instance = instances.find(i => i.id === task.processInstanceId);
    if (instance) {
      const definition = processes.find(p => p.id === instance.definitionId);
      if (definition) {
        const historyEntry: TaskHistory = {
          id: `hist-${Date.now()}`,
          stepName: task.title,
          action: action,
          performer: 'CurrentUser',
          timestamp: new Date().toISOString(),
          comments
        };

        let updatedInstance = {
          ...instance,
          history: [...instance.history, historyEntry]
        };

        if (action === 'reject') {
           updatedInstance.status = 'Terminated';
           updatedInstance.endDate = new Date().toISOString();
           await dbService.add('instances', updatedInstance);
           setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));
           return;
        }

        await dbService.add('instances', updatedInstance);
        setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));

        await advanceWorkflow(updatedInstance, definition);
      }
    }
  };

  const advanceWorkflow = async (instance: ProcessInstance, definition: ProcessDefinition) => {
    const currentStep = definition.steps.find(s => s.id === instance.currentStepId);
    if (!currentStep) return;

    let nextStep: ProcessStep | undefined;

    // 1. Graph Mode: Check if there is an explicit link
    if (currentStep.nextStepId) {
      nextStep = definition.steps.find(s => s.id === currentStep.nextStepId);
    } 
    // 2. Legacy/List Mode: Fallback to array order
    else {
      const currentIndex = definition.steps.findIndex(s => s.id === instance.currentStepId);
      if (currentIndex !== -1 && currentIndex < definition.steps.length - 1) {
        nextStep = definition.steps[currentIndex + 1];
      }
    }

    if (!nextStep || nextStep.type === 'end') {
      const completedInstance: ProcessInstance = { 
        ...instance, 
        status: 'Completed', 
        endDate: new Date().toISOString(),
        currentStepId: nextStep ? nextStep.id : null
      };
      await dbService.add('instances', completedInstance);
      setInstances(prev => prev.map(i => i.id === instance.id ? completedInstance : i));
      return;
    }

    const nextInstanceState = { ...instance, currentStepId: nextStep.id };
    await dbService.add('instances', nextInstanceState);
    setInstances(prev => prev.map(i => i.id === instance.id ? nextInstanceState : i));

    if (nextStep.type === 'user-task') {
      const newTask: Task = {
        id: `T-${Date.now()}`,
        title: nextStep.name,
        processName: definition.name,
        processInstanceId: instance.id,
        assignee: nextStep.role || 'Unassigned',
        dueDate: new Date(Date.now() + 86400000 * 3).toISOString().split('T')[0],
        status: TaskStatus.PENDING,
        priority: TaskPriority.MEDIUM,
        description: nextStep.description,
        stepId: nextStep.id
      };
      await dbService.add('tasks', newTask);
      setTasks(prev => [newTask, ...prev]);
    } else if (nextStep.type === 'service-task') {
      // Auto-execute Service Task with a delay
      setTimeout(async () => {
        // Log auto execution
        const historyEntry: TaskHistory = {
             id: `hist-${Date.now()}`,
             stepName: nextStep!.name,
             action: 'System Executed',
             performer: 'System',
             timestamp: new Date().toISOString()
        };

        // Get fresh state reference for next recursion
        const freshInstance = {
            ...nextInstanceState,
            history: [...nextInstanceState.history, historyEntry]
        };

        await dbService.add('instances', freshInstance);
        setInstances(prev => prev.map(i => i.id === instance.id ? freshInstance : i));

        await advanceWorkflow(freshInstance, definition);
      }, 2000);
    }
  };

  // --- Management Methods ---

  const resetSystem = async () => {
    setLoading(true);
    await dbService.resetDB();
    // After delete, reload will reseed automatically in loadData
    await loadData();
    setLoading(false);
  };

  const reseedSystem = async () => {
    setLoading(true);
    await dbService.reseed();
    await loadData();
    setLoading(false);
  };

  const exportData = async () => {
    const json = await dbService.exportData();
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `nexflow_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importData = async (file: File) => {
    return new Promise<void>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = async (e) => {
        try {
           const json = e.target?.result as string;
           await dbService.importData(json);
           await loadData();
           resolve();
        } catch (err) {
           reject(err);
        }
      };
      reader.onerror = reject;
      reader.readAsText(file);
    });
  };

  return (
    <BPMContext.Provider value={{ 
      processes, 
      instances, 
      tasks, 
      loading, 
      deployProcess, 
      startProcess, 
      completeTask,
      resetSystem,
      reseedSystem,
      exportData,
      importData
    }}>
      {children}
    </BPMContext.Provider>
  );
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

import React, { useState, useRef, useEffect } from 'react';
import { generateProcessWorkflow } from '../services/geminiService';
import { ProcessStep } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { Wand2, Save, Play, Settings, User, Cog, GitBranch, Flag, Plus, Trash2, GripHorizontal, Move, ArrowRight } from 'lucide-react';

const GRID_SIZE = 40;

export const ProcessDesigner: React.FC = () => {
  const { deployProcess } = useBPM();
  const [mode, setMode] = useState<'ai' | 'visual'>('visual');
  const [processName, setProcessName] = useState('New Process');

  // --- AI State ---
  const [prompt, setPrompt] = useState('');
  const [aiLoading, setAiLoading] = useState(false);

  // --- Visual Editor State ---
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [viewport, setViewport] = useState({ x: 0, y: 0, zoom: 1 });
  const [selectedStepId, setSelectedStepId] = useState<string | null>(null);

  // Interaction Refs
  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'connection'>('viewport');
  const activeNodeId = useRef<string | null>(null);
  const connectionStart = useRef<{x: number, y: number} | null>(null);
  const lastTouchDistance = useRef<number | null>(null);
  const tempConnectionLine = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  // --- AI Handlers ---
  const handleAiGenerate = async () => {
    if (!prompt.trim()) return;
    setAiLoading(true);
    try {
      const generatedSteps = await generateProcessWorkflow(prompt);
      // Auto-layout AI steps in a vertical column
      const layoutSteps = generatedSteps.map((step, idx) => ({
        ...step,
        position: { x: 400, y: 100 + (idx * 160) },
        // Link sequentially by default
        nextStepId: idx < generatedSteps.length - 1 ? generatedSteps[idx + 1].id : undefined
      }));
      setSteps(layoutSteps);
      setProcessName(prompt.substring(0, 30));
      setMode('visual'); // Switch to visual editor
    } catch (e) {
      alert('Failed to generate workflow.');
    } finally {
      setAiLoading(false);
    }
  };

  // --- Visual Editor Handlers ---

  const addStep = (type: ProcessStep['type']) => {
    // Add to center of viewport
    const centerX = (-viewport.x + (canvasRef.current?.clientWidth || 800) / 2) / viewport.zoom;
    const centerY = (-viewport.y + (canvasRef.current?.clientHeight || 600) / 2) / viewport.zoom;

    // Snap
    const snapX = Math.round(centerX / GRID_SIZE) * GRID_SIZE;
    const snapY = Math.round(centerY / GRID_SIZE) * GRID_SIZE;

    const newStep: ProcessStep = {
      id: `step-${Date.now()}`,
      name: `New ${type}`,
      type,
      description: 'Configure this step',
      position: { x: snapX, y: snapY }
    };
    setSteps(prev => [...prev, newStep]);
    setSelectedStepId(newStep.id);
  };

  const updateSelectedStep = (updates: Partial<ProcessStep>) => {
    if (!selectedStepId) return;
    setSteps(prev => prev.map(s => s.id === selectedStepId ? { ...s, ...updates } : s));
  };

  const deleteSelectedStep = () => {
    if (!selectedStepId) return;
    setSteps(prev => prev.filter(s => s.id !== selectedStepId));
    setSelectedStepId(null);
  };

  const handleDeploy = () => {
    if (steps.length === 0) return;
    deployProcess({
      name: processName,
      description: `Created via Visual Designer`,
      deployedBy: 'Admin',
      steps: steps
    });
    alert('Process deployed successfully.');
    setSteps([]);
    setProcessName('New Process');
  };

  // --- Gesture Logic ---

  const getClientCoordinates = (e: React.PointerEvent | PointerEvent) => {
    return { x: e.clientX, y: e.clientY };
  };

  const screenToWorld = (sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return {
      x: (sx - rect.left - viewport.x) / viewport.zoom,
      y: (sy - rect.top - viewport.y) / viewport.zoom
    };
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    e.preventDefault();
    isDragging.current = true;
    dragStart.current = { x: e.clientX, y: e.clientY };

    const target = e.target as HTMLElement;
    const nodeElement = target.closest('[data-node-id]');
    const handleElement = target.closest('[data-handle-id]');

    if (handleElement) {
      dragTarget.current = 'connection';
      activeNodeId.current = handleElement.getAttribute('data-handle-id');
      // Set start point for connection line
      const rect = handleElement.getBoundingClientRect();
      const worldPos = screenToWorld(rect.left + rect.width/2, rect.top + rect.height/2);
      connectionStart.current = worldPos;
    } else if (nodeElement) {
      dragTarget.current = 'node';
      activeNodeId.current = nodeElement.getAttribute('data-node-id');
      setSelectedStepId(activeNodeId.current);
    } else {
      dragTarget.current = 'viewport';
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    e.preventDefault();

    const dx = e.clientX - dragStart.current.x;
    const dy = e.clientY - dragStart.current.y;

    if (dragTarget.current === 'viewport') {
      setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy }));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } 
    else if (dragTarget.current === 'node' && activeNodeId.current) {
       // Move Node
       const zoomDx = dx / viewport.zoom;
       const zoomDy = dy / viewport.zoom;

       setSteps(prev => prev.map(s => {
         if (s.id === activeNodeId.current && s.position) {
           return {
             ...s,
             position: { x: s.position.x + zoomDx, y: s.position.y + zoomDy }
           };
         }
         return s;
       }));
       dragStart.current = { x: e.clientX, y: e.clientY };
    }
    else if (dragTarget.current === 'connection' && connectionStart.current) {
       // Draw temp line
       const worldPos = screenToWorld(e.clientX, e.clientY);
       tempConnectionLine.current = {
         x1: connectionStart.current.x,
         y1: connectionStart.current.y,
         x2: worldPos.x,
         y2: worldPos.y
       };
       // Force re-render for line
       setViewport(prev => ({...prev}));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    isDragging.current = false;
    tempConnectionLine.current = null;

    // Snap to Grid logic for nodes
    if (dragTarget.current === 'node' && activeNodeId.current) {
       setSteps(prev => prev.map(s => {
         if (s.id === activeNodeId.current && s.position) {
           return {
             ...s,
             position: { 
               x: Math.round(s.position.x / GRID_SIZE) * GRID_SIZE,
               y: Math.round(s.position.y / GRID_SIZE) * GRID_SIZE
             }
           };
         }
         return s;
       }));
    }

    // Connect Logic
    if (dragTarget.current === 'connection' && activeNodeId.current) {
       const target = document.elementFromPoint(e.clientX, e.clientY);
       const targetNode = target?.closest('[data-node-id]');
       if (targetNode) {
         const targetId = targetNode.getAttribute('data-node-id');
         if (targetId && targetId !== activeNodeId.current) {
           // Create Link
           setSteps(prev => prev.map(s => s.id === activeNodeId.current ? { ...s, nextStepId: targetId } : s));
         }
       }
    }

    activeNodeId.current = null;
    connectionStart.current = null;
    lastTouchDistance.current = null;
  };

  // Zoom Gesture (Pinch)
  const handleTouchMove = (e: React.TouchEvent) => {
    if (e.touches.length === 2) {
      e.preventDefault();
      const dist = Math.hypot(
        e.touches[0].clientX - e.touches[1].clientX,
        e.touches[0].clientY - e.touches[1].clientY
      );

      if (lastTouchDistance.current) {
        const delta = dist - lastTouchDistance.current;
        const zoomFactor = delta * 0.005;
        setViewport(prev => ({ ...prev, zoom: Math.min(Math.max(0.2, prev.zoom + zoomFactor), 3) }));
      }
      lastTouchDistance.current = dist;
    }
  };

  const handleWheel = (e: React.WheelEvent) => {
    // e.preventDefault(); // React passive event issue, handled via container
    const zoomFactor = -e.deltaY * 0.001;
    setViewport(prev => ({ ...prev, zoom: Math.min(Math.max(0.2, prev.zoom + zoomFactor), 3) }));
  };


  // --- Render Helpers ---

  const getStepColor = (type: string) => {
    switch (type) {
      case 'start': return 'bg-green-100 border-green-500 text-green-900';
      case 'end': return 'bg-slate-800 border-slate-900 text-white';
      case 'user-task': return 'bg-white border-blue-400 text-slate-800';
      case 'service-task': return 'bg-white border-purple-400 text-slate-800';
      case 'decision': return 'bg-amber-50 border-amber-500 text-amber-900';
      default: return 'bg-white border-slate-300';
    }
  };

  const getStepIcon = (type: string) => {
    switch (type) {
      case 'start': return <Play size={16} />;
      case 'end': return <Flag size={16} />;
      case 'user-task': return <User size={16} />;
      case 'service-task': return <Cog size={16} />;
      case 'decision': return <GitBranch size={16} />;
      default: return <Settings size={16} />;
    }
  };

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col bg-slate-100 rounded-xl overflow-hidden border border-slate-200 relative animate-fade-in touch-none">

      {/* Top Toolbar */}
      <div className="h-14 bg-white border-b border-slate-200 flex items-center justify-between px-4 z-20 shadow-sm">
        <div className="flex items-center gap-2">
           <div className="flex bg-slate-100 rounded-lg p-1 border border-slate-200">
             <button 
               onClick={() => setMode('visual')}
               className={`px-3 py-1.5 rounded-md text-xs font-bold transition-colors ${mode === 'visual' ? 'bg-white shadow text-brand-600' : 'text-slate-500'}`}
             >
               Visual Editor
             </button>
             <button 
               onClick={() => setMode('ai')}
               className={`px-3 py-1.5 rounded-md text-xs font-bold transition-colors ${mode === 'ai' ? 'bg-white shadow text-brand-600' : 'text-slate-500'}`}
             >
               AI Architect
             </button>
           </div>
           <div className="h-6 w-px bg-slate-200 mx-2"></div>
           <input 
             value={processName}
             onChange={e => setProcessName(e.target.value)}
             className="text-sm font-semibold bg-transparent border-none focus:ring-0 text-slate-700 w-32 md:w-48 truncate"
           />
        </div>
        <button 
          onClick={handleDeploy}
          className="bg-brand-600 text-white px-3 py-1.5 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-brand-700 active:scale-95 transition-all shadow-sm"
        >
          <Save size={16} /> <span className="hidden md:inline">Deploy</span>
        </button>
      </div>

      {mode === 'ai' ? (
        <div className="flex-1 flex flex-col items-center justify-center p-8 bg-slate-50">
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200 max-w-lg w-full text-center">
             <div className="w-16 h-16 bg-brand-50 text-brand-600 rounded-full flex items-center justify-center mx-auto mb-6">
                <Wand2 size={32} />
             </div>
             <h2 className="text-xl font-bold text-slate-800 mb-2">AI Workflow Generation</h2>
             <p className="text-slate-500 mb-6">Describe your process in natural language.</p>
             <textarea 
               className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl text-sm mb-4 focus:ring-2 focus:ring-brand-500 focus:outline-none resize-none"
               rows={4}
               placeholder="E.g. Create an expense approval process where amounts under $500 are auto-approved, and over $500 require Manager review."
               value={prompt}
               onChange={e => setPrompt(e.target.value)}
             />
             <button 
               onClick={handleAiGenerate}
               disabled={aiLoading || !prompt}
               className="w-full py-3 bg-brand-600 text-white rounded-xl font-medium flex items-center justify-center gap-2 hover:bg-brand-700 disabled:opacity-50"
             >
               {aiLoading ? "Generating..." : "Generate Workflow"}
             </button>
          </div>
        </div>
      ) : (
        <div className="flex-1 relative overflow-hidden bg-slate-100">
           {/* Canvas */}
           <div 
             ref={canvasRef}
             className="absolute inset-0 touch-none cursor-move"
             onPointerDown={handlePointerDown}
             onPointerMove={handlePointerMove}
             onPointerUp={handlePointerUp}
             onPointerLeave={handlePointerUp}
             onWheel={handleWheel}
             onTouchMove={handleTouchMove}
             style={{
               backgroundImage: 'radial-gradient(#cbd5e1 1px, transparent 1px)',
               backgroundSize: `${GRID_SIZE * viewport.zoom}px ${GRID_SIZE * viewport.zoom}px`,
               backgroundPosition: `${viewport.x}px ${viewport.y}px`
             }}
           >
              <div 
                style={{
                  transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`,
                  transformOrigin: '0 0',
                  width: '100%',
                  height: '100%'
                }}
              >
                 {/* Connection Lines (SVG Layer) */}
                 <svg className="overflow-visible absolute top-0 left-0 pointer-events-none" style={{width: 1, height: 1}}>
                    {/* Render existing connections */}
                    {steps.map(step => {
                      if (!step.nextStepId || !step.position) return null;
                      const target = steps.find(s => s.id === step.nextStepId);
                      if (!target || !target.position) return null;

                      // Bezier Curve
                      const x1 = step.position.x + 180; // Right side of source
                      const y1 = step.position.y + 40;  // Center Y
                      const x2 = target.position.x;     // Left side of target
                      const y2 = target.position.y + 40;

                      const path = `M ${x1} ${y1} C ${x1 + 50} ${y1}, ${x2 - 50} ${y2}, ${x2} ${y2}`;

                      return (
                        <g key={`${step.id}-${target.id}`}>
                           <path d={path} stroke="#94a3b8" strokeWidth="2" fill="none" />
                           <polygon points={`${x2},${y2} ${x2-10},${y2-5} ${x2-10},${y2+5}`} fill="#94a3b8" />
                        </g>
                      );
                    })}

                    {/* Temp Drag Line */}
                    {tempConnectionLine.current && (
                       <line 
                         x1={tempConnectionLine.current.x1} 
                         y1={tempConnectionLine.current.y1}
                         x2={tempConnectionLine.current.x2}
                         y2={tempConnectionLine.current.y2}
                         stroke="#3b82f6" 
                         strokeWidth="2" 
                         strokeDasharray="5,5"
                       />
                    )}
                 </svg>

                 {/* Nodes */}
                 {steps.map(step => (
                   <div 
