           {/* Property Panel (Slide up) */}
           {selectedStepId && (
              <div className="absolute top-4 right-4 w-64 bg-white rounded-xl shadow-lg border border-slate-200 p-4 z-20 animate-slide-in">
                 <div className="flex justify-between items-center mb-4">
                   <h3 className="font-bold text-slate-700">Properties</h3>
                   <button onClick={() => deleteSelectedStep()} className="text-red-500 hover:bg-red-50 p-1.5 rounded-lg">
                     <Trash2 size={16} />
                   </button>
                 </div>

                 <div className="space-y-3">
                    <div>
                       <label className="text-xs font-bold text-slate-500 block mb-1">Name</label>
                       <input 
                         className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm" 
                         value={steps.find(s => s.id === selectedStepId)?.name}
                         onChange={e => updateSelectedStep({ name: e.target.value })}
                       />
                    </div>
                    <div>
                       <label className="text-xs font-bold text-slate-500 block mb-1">Description</label>
                       <textarea 
                         className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm resize-none" 
                         rows={2}
                         value={steps.find(s => s.id === selectedStepId)?.description}
                         onChange={e => updateSelectedStep({ description: e.target.value })}
                       />
                    </div>
                    {steps.find(s => s.id === selectedStepId)?.type === 'user-task' && (
                       <div>
                         <label className="text-xs font-bold text-slate-500 block mb-1">Role</label>
                         <input 
                           className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm" 
                           value={steps.find(s => s.id === selectedStepId)?.role || ''}
                           onChange={e => updateSelectedStep({ role: e.target.value })}
                         />
                      </div>
                    )}
                 </div>
              </div>
           )}

           {/* Grid Info / Hint */}
           <div className="absolute bottom-4 right-4 text-[10px] text-slate-400 font-medium select-none pointer-events-none bg-white/50 px-2 py-1 rounded">
              Zoom: {Math.round(viewport.zoom * 100)}% | Grid: {GRID_SIZE}px
           </div>
        </div>
      )}
    </div>
  );
};

export enum TaskStatus {
  PENDING = 'Pending',
  IN_PROGRESS = 'In Progress',
  COMPLETED = 'Completed',
  REJECTED = 'Rejected'
}

export enum TaskPriority {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export interface Task {
  id: string;
  title: string;
  processName: string;
  processInstanceId: string;
  assignee: string;
  dueDate: string;
  status: TaskStatus;
  priority: TaskPriority;
  description?: string;
  stepId: string;
  data?: any;
}

export interface ProcessStep {
  id: string;
  name: string;
  type: 'start' | 'user-task' | 'service-task' | 'decision' | 'parallel-gateway' | 'end';
  description: string;
  role?: string;
  // Graph execution properties
  nextStepIds?: string[]; // Array to support 1-to-many connections
  position?: { x: number; y: number };
}

export interface ProcessDefinition {
  id: string;
  name: string;
  description: string;
  steps: ProcessStep[];
