  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'connection'>('viewport');
  const activeNodeId = useRef<string | null>(null);
  const connectionStart = useRef<{x: number, y: number} | null>(null);
  const lastTouchDistance = useRef<number | null>(null);
  const tempConnectionLine = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  // --- AI Handlers ---
  const handleAiGenerate = async () => {
    if (!prompt.trim()) return;
    setAiLoading(true);
    try {
      const generatedSteps = await generateProcessWorkflow(prompt);
      // Auto-layout AI steps in a vertical column
      const layoutSteps = generatedSteps.map((step, idx) => ({
        ...step,
        position: { x: 400, y: 100 + (idx * 160) },
        // Link sequentially by default
        nextStepIds: idx < generatedSteps.length - 1 ? [generatedSteps[idx + 1].id] : []
      }));
      setSteps(layoutSteps);
      setProcessName(prompt.substring(0, 30));
      setMode('visual'); // Switch to visual editor
    } catch (e) {
      alert('Failed to generate workflow.');
    } finally {
      setAiLoading(false);
    }
  };

  // --- Visual Editor Handlers ---

  const addStep = (type: ProcessStep['type']) => {
    // Add to center of viewport
    const centerX = (-viewport.x + (canvasRef.current?.clientWidth || 800) / 2) / viewport.zoom;
    const centerY = (-viewport.y + (canvasRef.current?.clientHeight || 600) / 2) / viewport.zoom;

    // Snap
    const snapX = Math.round(centerX / GRID_SIZE) * GRID_SIZE;
    const snapY = Math.round(centerY / GRID_SIZE) * GRID_SIZE;

    const newStep: ProcessStep = {
      id: `step-${Date.now()}`,
      name: type === 'parallel-gateway' ? 'Split' : `New ${type}`,
      type,
      description: 'Configure this step',
      position: { x: snapX, y: snapY },
      nextStepIds: []
    };
    setSteps(prev => [...prev, newStep]);
    setSelectedStepId(newStep.id);
  };

  const updateSelectedStep = (updates: Partial<ProcessStep>) => {
    if (!selectedStepId) return;
    setSteps(prev => prev.map(s => s.id === selectedStepId ? { ...s, ...updates } : s));
  };

  const deleteSelectedStep = () => {
    if (!selectedStepId) return;
    setSteps(prev => prev.filter(s => s.id !== selectedStepId));
    setSelectedStepId(null);
  };

  const handleDeploy = () => {
    if (steps.length === 0) return;
    deployProcess({
      name: processName,
      description: `Created via Visual Designer`,
      deployedBy: 'Admin',
      steps: steps
    });
    alert('Process deployed successfully.');
    setSteps([]);
    setProcessName('New Process');
  };

  // --- Gesture Logic ---

  const screenToWorld = (sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return {
      x: (sx - rect.left - viewport.x) / viewport.zoom,
      y: (sy - rect.top - viewport.y) / viewport.zoom
    };
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    e.preventDefault();
    isDragging.current = true;
    dragStart.current = { x: e.clientX, y: e.clientY };

    const target = e.target as HTMLElement;
    const nodeElement = target.closest('[data-node-id]');
    const handleElement = target.closest('[data-handle-id]');

    if (handleElement) {
      dragTarget.current = 'connection';
      activeNodeId.current = handleElement.getAttribute('data-handle-id');
      // Set start point for connection line
      const rect = handleElement.getBoundingClientRect();
      const worldPos = screenToWorld(rect.left + rect.width/2, rect.top + rect.height/2);
      connectionStart.current = worldPos;
    } else if (nodeElement) {
      dragTarget.current = 'node';
      activeNodeId.current = nodeElement.getAttribute('data-node-id');
      setSelectedStepId(activeNodeId.current);
    } else {
      dragTarget.current = 'viewport';
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    e.preventDefault();

    const dx = e.clientX - dragStart.current.x;
    const dy = e.clientY - dragStart.current.y;

    if (dragTarget.current === 'viewport') {
      setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy }));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } 
    else if (dragTarget.current === 'node' && activeNodeId.current) {
       // Move Node
       const zoomDx = dx / viewport.zoom;
       const zoomDy = dy / viewport.zoom;

       setSteps(prev => prev.map(s => {
         if (s.id === activeNodeId.current && s.position) {
           return {
             ...s,
             position: { x: s.position.x + zoomDx, y: s.position.y + zoomDy }
           };
         }
         return s;
       }));
       dragStart.current = { x: e.clientX, y: e.clientY };
    }
    else if (dragTarget.current === 'connection' && connectionStart.current) {
       // Draw temp line
       const worldPos = screenToWorld(e.clientX, e.clientY);
       tempConnectionLine.current = {
         x1: connectionStart.current.x,
         y1: connectionStart.current.y,
         x2: worldPos.x,
         y2: worldPos.y
       };
       // Force re-render for line
       setViewport(prev => ({...prev}));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    isDragging.current = false;
    tempConnectionLine.current = null;

    // Snap to Grid logic for nodes
    if (dragTarget.current === 'node' && activeNodeId.current) {
       setSteps(prev => prev.map(s => {
         if (s.id === activeNodeId.current && s.position) {
           return {
             ...s,
             position: { 
               x: Math.round(s.position.x / GRID_SIZE) * GRID_SIZE,
               y: Math.round(s.position.y / GRID_SIZE) * GRID_SIZE
             }
           };
         }
         return s;
       }));
    }

    // Connect Logic
    if (dragTarget.current === 'connection' && activeNodeId.current) {
       const target = document.elementFromPoint(e.clientX, e.clientY);
       const targetNode = target?.closest('[data-node-id]');
       if (targetNode) {
         const targetId = targetNode.getAttribute('data-node-id');
         if (targetId && targetId !== activeNodeId.current) {
           // Create Link Logic
           setSteps(prev => prev.map(s => {
             if (s.id === activeNodeId.current) {
               const isGateway = s.type === 'parallel-gateway';
               const currentNext = s.nextStepIds || [];

               // Avoid duplicates
               if (currentNext.includes(targetId)) return s;

               // If Gateway, append. If Task, replace (unless we want implicit split)
               // For now, allow 1:N always, but visual style might differ.
               // Let's enforce Single Output for non-gateways to encourage good design? 
               // Nah, flexibility is better.
               return { ...s, nextStepIds: isGateway ? [...currentNext, targetId] : [targetId] };
             }
             return s;
           }));
         }
       }
    }

    activeNodeId.current = null;
    connectionStart.current = null;
    lastTouchDistance.current = null;
  };

  // Zoom Gesture (Pinch)
  const handleTouchMove = (e: React.TouchEvent) => {
    if (e.touches.length === 2) {
      e.preventDefault();
      const dist = Math.hypot(
        e.touches[0].clientX - e.touches[1].clientX,
        e.touches[0].clientY - e.touches[1].clientY
      );

      if (lastTouchDistance.current) {
        const delta = dist - lastTouchDistance.current;
        const zoomFactor = delta * 0.005;
        setViewport(prev => ({ ...prev, zoom: Math.min(Math.max(0.2, prev.zoom + zoomFactor), 3) }));
      }
      lastTouchDistance.current = dist;
    }
  };

  const handleWheel = (e: React.WheelEvent) => {
    const zoomFactor = -e.deltaY * 0.001;
    setViewport(prev => ({ ...prev, zoom: Math.min(Math.max(0.2, prev.zoom + zoomFactor), 3) }));
  };


  // --- Render Helpers ---

  const getStepColor = (type: string) => {
    switch (type) {
      case 'start': return 'bg-green-100 border-green-500 text-green-900';
      case 'end': return 'bg-slate-800 border-slate-900 text-white';
      case 'user-task': return 'bg-white border-blue-400 text-slate-800';
      case 'service-task': return 'bg-white border-purple-400 text-slate-800';
      case 'decision': return 'bg-amber-50 border-amber-500 text-amber-900';
      case 'parallel-gateway': return 'bg-orange-100 border-orange-500 text-orange-900 rotate-45 scale-75';
      default: return 'bg-white border-slate-300';
    }
  };

  const getStepIcon = (type: string) => {
    switch (type) {
      case 'start': return <Play size={16} />;
      case 'end': return <Flag size={16} />;
      case 'user-task': return <User size={16} />;
      case 'service-task': return <Cog size={16} />;
      case 'decision': return <GitBranch size={16} />;
      case 'parallel-gateway': return <Split size={16} className="-rotate-45" />;
      default: return <Settings size={16} />;
    }
  };

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col bg-slate-100 rounded-xl overflow-hidden border border-slate-200 relative animate-fade-in touch-none">

      {/* Top Toolbar */}
      <div className="h-14 bg-white border-b border-slate-200 flex items-center justify-between px-4 z-20 shadow-sm">
        <div className="flex items-center gap-2">
           <div className="flex bg-slate-100 rounded-lg p-1 border border-slate-200">
             <button 
               onClick={() => setMode('visual')}
               className={`px-3 py-1.5 rounded-md text-xs font-bold transition-colors ${mode === 'visual' ? 'bg-white shadow text-brand-600' : 'text-slate-500'}`}
             >
               Visual Editor
             </button>
             <button 
               onClick={() => setMode('ai')}
               className={`px-3 py-1.5 rounded-md text-xs font-bold transition-colors ${mode === 'ai' ? 'bg-white shadow text-brand-600' : 'text-slate-500'}`}
             >
               AI Architect
             </button>
           </div>
           <div className="h-6 w-px bg-slate-200 mx-2"></div>
           <input 
             value={processName}
             onChange={e => setProcessName(e.target.value)}
             className="text-sm font-semibold bg-transparent border-none focus:ring-0 text-slate-700 w-32 md:w-48 truncate"
           />
        </div>
        <button 
          onClick={handleDeploy}
          className="bg-brand-600 text-white px-3 py-1.5 rounded-lg text-sm font-medium flex items-center gap-2 hover:bg-brand-700 active:scale-95 transition-all shadow-sm"
        >
          <Save size={16} /> <span className="hidden md:inline">Deploy</span>
        </button>
      </div>

      {mode === 'ai' ? (
        <div className="flex-1 flex flex-col items-center justify-center p-8 bg-slate-50">
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200 max-w-lg w-full text-center">
             <div className="w-16 h-16 bg-brand-50 text-brand-600 rounded-full flex items-center justify-center mx-auto mb-6">
                <Wand2 size={32} />
             </div>
             <h2 className="text-xl font-bold text-slate-800 mb-2">AI Workflow Generation</h2>
             <p className="text-slate-500 mb-6">Describe your process in natural language.</p>
             <textarea 
               className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl text-sm mb-4 focus:ring-2 focus:ring-brand-500 focus:outline-none resize-none"
               rows={4}
               placeholder="E.g. Create an expense approval process where amounts under $500 are auto-approved, and over $500 require Manager review."
               value={prompt}
               onChange={e => setPrompt(e.target.value)}
             />
             <button 
               onClick={handleAiGenerate}
               disabled={aiLoading || !prompt}
               className="w-full py-3 bg-brand-600 text-white rounded-xl font-medium flex items-center justify-center gap-2 hover:bg-brand-700 disabled:opacity-50"
             >
               {aiLoading ? "Generating..." : "Generate Workflow"}
             </button>
          </div>
        </div>
      ) : (
        <div className="flex-1 relative overflow-hidden bg-slate-100">
           {/* Canvas */}
           <div 
             ref={canvasRef}
             className="absolute inset-0 touch-none cursor-move"
             onPointerDown={handlePointerDown}
             onPointerMove={handlePointerMove}
             onPointerUp={handlePointerUp}
             onPointerLeave={handlePointerUp}
             onWheel={handleWheel}
             onTouchMove={handleTouchMove}
             style={{
               backgroundImage: 'radial-gradient(#cbd5e1 1px, transparent 1px)',
               backgroundSize: `${GRID_SIZE * viewport.zoom}px ${GRID_SIZE * viewport.zoom}px`,
               backgroundPosition: `${viewport.x}px ${viewport.y}px`
             }}
           >
              <div 
                style={{
                  transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`,
                  transformOrigin: '0 0',
                  width: '100%',
                  height: '100%'
                }}
              >
                 {/* Connection Lines (SVG Layer) */}
                 <svg className="overflow-visible absolute top-0 left-0 pointer-events-none" style={{width: 1, height: 1}}>
                    {/* Render existing connections */}
                    {steps.flatMap(step => {
                      if (!step.nextStepIds || !step.position) return [];
                      return step.nextStepIds.map(targetId => {
                         const target = steps.find(s => s.id === targetId);
                         if (!target || !target.position) return null;
                         if (!step.position) return null;

                         const isGateway = step.type === 'parallel-gateway';

                         // Bezier Curve
                         const x1 = step.position.x + (isGateway ? 90 : 180); 
                         const y1 = step.position.y + 40;  
                         const x2 = target.position.x;     
                         const y2 = target.position.y + 40;

                         const path = `M ${x1} ${y1} C ${x1 + 50} ${y1}, ${x2 - 50} ${y2}, ${x2} ${y2}`;

                         return (
                            <g key={`${step.id}-${target.id}`}>
                               <path d={path} stroke="#94a3b8" strokeWidth="2" fill="none" />
                               <polygon points={`${x2},${y2} ${x2-10},${y2-5} ${x2-10},${y2+5}`} fill="#94a3b8" />
                            </g>
                         );
                      });
                    })}

                    {/* Temp Drag Line */}
                    {tempConnectionLine.current && (
                       <line 
                         x1={tempConnectionLine.current.x1} 
                         y1={tempConnectionLine.current.y1}
                         x2={tempConnectionLine.current.x2}
                         y2={tempConnectionLine.current.y2}
                         stroke="#3b82f6" 
                         strokeWidth="2" 
                         strokeDasharray="5,5"
                       />
                    )}
                 </svg>

                 {/* Nodes */}
                 {steps.map(step => (
                   <div 
                     key={step.id}
                     data-node-id={step.id}
                     className={`absolute w-[180px] h-[80px] rounded-lg border-2 shadow-sm flex flex-col p-3 transition-shadow select-none ${getStepColor(step.type)} ${selectedStepId === step.id ? 'ring-2 ring-brand-400 shadow-md z-10' : ''}`}
                     style={{
                        left: step.position?.x || 0,
                        top: step.position?.y || 0
                     }}
                   >
                      <div className={`flex items-center gap-2 mb-1 pointer-events-none ${step.type === 'parallel-gateway' ? '-rotate-45 translate-x-3 translate-y-3' : ''}`}>
                         {getStepIcon(step.type)}
                         <span className="text-xs font-bold uppercase tracking-wide opacity-70">{step.type === 'parallel-gateway' ? 'Parallel' : step.type}</span>
                      </div>
                      <div className={`font-semibold text-sm truncate pointer-events-none ${step.type === 'parallel-gateway' ? '-rotate-45 translate-x-4 translate-y-4' : ''}`}>{step.name}</div>

                      {/* Output Handle */}
                      <div 
                        data-handle-id={step.id}
                        className={`absolute -right-3 top-1/2 -translate-y-1/2 w-6 h-6 bg-white border-2 border-slate-400 rounded-full flex items-center justify-center hover:scale-110 hover:border-brand-500 transition-transform cursor-crosshair z-20 ${step.type === 'parallel-gateway' ? 'right-[-25px] top-[50%]' : ''}`}
                      >
                         <div className="w-2 h-2 bg-slate-400 rounded-full pointer-events-none" />
                      </div>
                   </div>
                 ))}
              </div>
           </div>

           {/* Editor Overlay Controls */}
           <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white rounded-full shadow-lg border border-slate-200 p-2 flex items-center gap-4 px-6 z-20 overflow-x-auto max-w-[90vw]">
              <button onClick={() => addStep('start')} className="p-2 hover:bg-slate-100 rounded-full text-green-600 tooltip" title="Start">
                <Play size={20} />
              </button>
              <button onClick={() => addStep('user-task')} className="p-2 hover:bg-slate-100 rounded-full text-blue-600" title="User Task">
                <User size={20} />
              </button>
              <button onClick={() => addStep('service-task')} className="p-2 hover:bg-slate-100 rounded-full text-purple-600" title="Service Task">
                <Cog size={20} />
              </button>
              <button onClick={() => addStep('parallel-gateway')} className="p-2 hover:bg-slate-100 rounded-full text-orange-600" title="Parallel Gateway">
                <Split size={20} />
              </button>
              <button onClick={() => addStep('end')} className="p-2 hover:bg-slate-100 rounded-full text-slate-800" title="End">
                <Flag size={20} />
              </button>
           </div>

           {/* Property Panel (Slide up) */}
           {selectedStepId && (
              <div className="absolute top-4 right-4 w-64 bg-white rounded-xl shadow-lg border border-slate-200 p-4 z-20 animate-slide-in">
                 <div className="flex justify-between items-center mb-4">
                   <h3 className="font-bold text-slate-700">Properties</h3>
                   <button onClick={() => deleteSelectedStep()} className="text-red-500 hover:bg-red-50 p-1.5 rounded-lg">
                     <Trash2 size={16} />
                   </button>
                 </div>

                 <div className="space-y-3">
                    <div>
                       <label className="text-xs font-bold text-slate-500 block mb-1">Name</label>
                       <input 
                         className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm" 
                         value={steps.find(s => s.id === selectedStepId)?.name}
                         onChange={e => updateSelectedStep({ name: e.target.value })}
                       />
                    </div>
                    {steps.find(s => s.id === selectedStepId)?.type !== 'parallel-gateway' && (
                        <div>
                           <label className="text-xs font-bold text-slate-500 block mb-1">Description</label>
                           <textarea 
                             className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm resize-none" 
                             rows={2}
                             value={steps.find(s => s.id === selectedStepId)?.description}
                             onChange={e => updateSelectedStep({ description: e.target.value })}
                           />
                        </div>
                    )}
                    {steps.find(s => s.id === selectedStepId)?.type === 'user-task' && (
                       <div>
                         <label className="text-xs font-bold text-slate-500 block mb-1">Role</label>
                         <input 
                           className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm" 
                           value={steps.find(s => s.id === selectedStepId)?.role || ''}
                           onChange={e => updateSelectedStep({ role: e.target.value })}
                         />
                      </div>
                    )}
                 </div>
              </div>
           )}

           {/* Grid Info / Hint */}
           <div className="absolute bottom-4 right-4 text-[10px] text-slate-400 font-medium select-none pointer-events-none bg-white/50 px-2 py-1 rounded">
              Zoom: {Math.round(viewport.zoom * 100)}% | Grid: {GRID_SIZE}px
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { Task, TaskStatus, TaskPriority } from '../types';
import { Search, Filter, LayoutGrid, List as ListIcon, Clock, AlertTriangle, CheckCircle, MoreHorizontal } from 'lucide-react';

export const TaskExplorer: React.FC = () => {
  const { tasks, completeTask } = useBPM();
  const [viewMode, setViewMode] = useState<'list' | 'grid'>('grid');
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');

  const filteredTasks = tasks.filter(t => {
     const matchesSearch = t.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           t.processName.toLowerCase().includes(searchTerm.toLowerCase()) ||
                           t.assignee.toLowerCase().includes(searchTerm.toLowerCase());
     const matchesStatus = statusFilter === 'All' ? true : t.status === statusFilter;
     return matchesSearch && matchesStatus;
  });

  const getStatusColor = (status: TaskStatus) => {
    switch (status) {
      case TaskStatus.PENDING: return 'bg-amber-100 text-amber-800';
      case TaskStatus.IN_PROGRESS: return 'bg-blue-100 text-blue-800';
      case TaskStatus.COMPLETED: return 'bg-green-100 text-green-800';
      case TaskStatus.REJECTED: return 'bg-red-100 text-red-800';
      default: return 'bg-slate-100 text-slate-800';
    }
  };

  const getPriorityBadge = (priority: TaskPriority) => {
     const colors = {
        [TaskPriority.LOW]: 'bg-slate-100 text-slate-600',
        [TaskPriority.MEDIUM]: 'bg-blue-50 text-blue-600',
        [TaskPriority.HIGH]: 'bg-orange-50 text-orange-600',
        [TaskPriority.CRITICAL]: 'bg-red-50 text-red-600',
     };
     return (
        <span className={`text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider ${colors[priority]}`}>
           {priority}
        </span>
     );
  };

  return (
    <div className="space-y-6 animate-fade-in pb-12">
       <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">Task Explorer</h2>
            <p className="text-slate-500">Global task management and operational oversight.</p>
          </div>
          <div className="flex items-center gap-2 bg-white p-1 rounded-lg border border-slate-200 shadow-sm">
             <button 
               onClick={() => setViewMode('list')}
               className={`p-2 rounded-md transition-colors ${viewMode === 'list' ? 'bg-slate-100 text-slate-800' : 'text-slate-400 hover:text-slate-600'}`}
             >
                <ListIcon size={20} />
             </button>
             <button 
               onClick={() => setViewMode('grid')}
               className={`p-2 rounded-md transition-colors ${viewMode === 'grid' ? 'bg-slate-100 text-slate-800' : 'text-slate-400 hover:text-slate-600'}`}
             >
                <LayoutGrid size={20} />
             </button>
          </div>
       </header>

       {/* Filters */}
       <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4 items-center">
          <div className="relative flex-1 w-full">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
             <input 
               type="text" 
               placeholder="Search by title, process, or assignee..." 
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
               className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-brand-500"
             />
          </div>
          <div className="flex items-center gap-2 w-full md:w-auto overflow-x-auto pb-2 md:pb-0">
             {['All', TaskStatus.PENDING, TaskStatus.COMPLETED, TaskStatus.REJECTED].map(status => (
                <button
                  key={status}
                  onClick={() => setStatusFilter(status)}
                  className={`px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-colors border ${
                     statusFilter === status 
                     ? 'bg-slate-800 text-white border-slate-800' 
                     : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'
                  }`}
                >
                   {status}
                </button>
             ))}
          </div>
       </div>

       {/* Content */}
       {viewMode === 'grid' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
             {filteredTasks.map(task => (
