class DBService {
  private db: IDBDatabase | null = null;

  private notify(action: string, detail: any, type: 'read' | 'write' | 'delete' | 'error' = 'read') {
    const event = new CustomEvent('nexflow-db-log', {
      detail: { action, detail, type }
    });
    window.dispatchEvent(event);
  }

  async open(): Promise<IDBDatabase> {
    if (this.db) return this.db;

    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;
        if (!db.objectStoreNames.contains('processes')) {
          db.createObjectStore('processes', { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains('instances')) {
          db.createObjectStore('instances', { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains('tasks')) {
          db.createObjectStore('tasks', { keyPath: 'id' });
        }
        this.notify('UPGRADE', `DB upgraded to version ${DB_VERSION}`, 'write');
      };

      request.onsuccess = (event) => {
        this.db = (event.target as IDBOpenDBRequest).result;

        this.db.onversionchange = () => {
          this.db?.close();
          this.db = null;
          console.warn('Database is outdated, please reload the page.');
        };

        resolve(this.db);
      };

      request.onerror = (event) => {
        const error = (event.target as IDBOpenDBRequest).error;
        this.notify('ERROR', `Failed to open DB: ${error?.message}`, 'error');
        console.error('IndexedDB Error:', event);
        reject(error);
      };
    });
  }

  async getAll<T>(storeName: string): Promise<T[]> {
    try {
      const db = await this.open();
      return new Promise((resolve, reject) => {
        const transaction = db.transaction(storeName, 'readonly');
        const store = transaction.objectStore(storeName);
        const request = store.getAll();

        request.onsuccess = () => {
          this.notify('READ_ALL', `Fetched ${request.result.length} items from ${storeName}`, 'read');
          resolve(request.result);
        };
        request.onerror = () => {
          this.notify('ERROR', `Failed to fetch from ${storeName}`, 'error');
          reject(request.error);
        };
      });
    } catch (e) {
      this.notify('ERROR', `Fatal DB Error: ${e}`, 'error');
      throw e;
    }
  }

  async add<T>(storeName: string, item: T): Promise<void> {
    try {
      const db = await this.open();
      return new Promise((resolve, reject) => {
        const transaction = db.transaction(storeName, 'readwrite');
        const store = transaction.objectStore(storeName);
        const request = store.put(item); // put handles add or update

        request.onsuccess = () => {
          this.notify('WRITE', `Saved to ${storeName}`, 'write');
          resolve();
        };
        request.onerror = () => {
          this.notify('ERROR', `Failed to save to ${storeName}`, 'error');
          reject(request.error);
        };
      });
    } catch (e) {
      this.notify('ERROR', `Fatal DB Error: ${e}`, 'error');
      throw e;
    }
  }

  async delete(storeName: string, id: string): Promise<void> {
    try {
      const db = await this.open();
      return new Promise((resolve, reject) => {
        const transaction = db.transaction(storeName, 'readwrite');
        const store = transaction.objectStore(storeName);
        const request = store.delete(id);

        request.onsuccess = () => {
          this.notify('DELETE', `Deleted ${id} from ${storeName}`, 'delete');
          resolve();
        };
        request.onerror = () => {
           this.notify('ERROR', `Failed to delete ${id} from ${storeName}`, 'error');
           reject(request.error);
        };
      });
    } catch (e) {
      this.notify('ERROR', `Fatal DB Error: ${e}`, 'error');
      throw e;
    }
  }

  async clearStore(storeName: string): Promise<void> {
    const db = await this.open();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(storeName, 'readwrite');
      const store = transaction.objectStore(storeName);
      const request = store.clear();

      request.onsuccess = () => {
        this.notify('CLEAR', `Cleared store ${storeName}`, 'delete');
        resolve();
      };
      request.onerror = () => reject(request.error);
    });
  }

  async reseed(): Promise<void> {
    this.notify('RESEED', 'Starting system reseed...', 'write');
    await this.clearStore('processes');
    await this.clearStore('instances');
    await this.clearStore('tasks');

    for (const p of MOCK_PROCESSES) await this.add('processes', p);
    for (const i of MOCK_INSTANCES) await this.add('instances', i);
    for (const t of MOCK_TASKS) await this.add('tasks', t);
    this.notify('RESEED', 'System reseed complete', 'write');
  }

  async resetDB(): Promise<void> {
    if (this.db) {
      this.db.close();
      this.db = null;
    }
    return new Promise((resolve, reject) => {
      const request = indexedDB.deleteDatabase(DB_NAME);
      request.onsuccess = () => {
        this.notify('RESET', 'Database deleted', 'delete');
        resolve();
      };
      request.onerror = () => reject(request.error);
    });
  }

  async exportData(): Promise<string> {
    this.notify('EXPORT', 'Generating backup...', 'read');
    const processes = await this.getAll<ProcessDefinition>('processes');
    const instances = await this.getAll<ProcessInstance>('instances');
    const tasks = await this.getAll<Task>('tasks');

    const dump = {
      timestamp: new Date().toISOString(),
      version: 1.0,
      data: { processes, instances, tasks }
    };
    return JSON.stringify(dump, null, 2);
  }

  async importData(jsonString: string): Promise<void> {
    try {
      this.notify('IMPORT', 'Starting data import...', 'write');
      const parsed = JSON.parse(jsonString);
      if (!parsed.data || !parsed.data.processes) throw new Error("Invalid backup format");

      await this.clearStore('processes');
      await this.clearStore('instances');
      await this.clearStore('tasks');

      for (const p of parsed.data.processes) await this.add('processes', p);
      for (const i of parsed.data.instances) await this.add('instances', i);
      for (const t of parsed.data.tasks) await this.add('tasks', t);
      this.notify('IMPORT', 'Import successful', 'write');
    } catch (e) {
      this.notify('ERROR', 'Import failed', 'error');
      console.error("Import failed", e);
      throw e;
    }
  }
}

