import { GoogleGenAI, Type } from "@google/genai";
import { ProcessStep } from '../types';

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API_KEY is missing. AI features will not work.");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const generateProcessWorkflow = async (prompt: string): Promise<ProcessStep[]> => {
  const ai = getClient();
  if (!ai) throw new Error("API Key not configured");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Create a business process workflow for the following request: "${prompt}". 
      Break it down into logical steps including Start, User Tasks (approvals, inputs), Service Tasks (automated actions), Decisions, and End.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              name: { type: Type.STRING },
              type: { type: Type.STRING, enum: ['start', 'user-task', 'service-task', 'decision', 'end', 'parallel-gateway'] },
              description: { type: Type.STRING },
              role: { type: Type.STRING, description: "The role responsible, e.g., Manager, System, HR" }
            },
            required: ["id", "name", "type", "description"]
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as ProcessStep[];
    }
    return [];
  } catch (error: any) {
    if (error.message?.includes("403") || error.message?.includes("PERMISSION_DENIED")) {
       console.warn("Gemini API Permission Denied. Check API Key or Billing.");
       // Fallback mock response for demo purposes so app doesn't break
       return [
         { id: 'start', name: 'Start', type: 'start', description: 'Process Started' },
         { id: 'task1', name: 'Manual Step', type: 'user-task', description: 'Created due to AI error' },
         { id: 'end', name: 'End', type: 'end', description: 'Process Ended' }
       ];
    }
    console.error("Failed to generate workflow:", error);
    throw error;
  }
};

export const analyzeProcessEfficiency = async (tasks: any[]): Promise<string> => {
  const ai = getClient();
  if (!ai) return "AI insights unavailable (Missing API Key).";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Analyze the following task data summary and provide executive insights on bottlenecks and efficiency improvements. Keep it professional and concise (max 3 sentences). Data: ${JSON.stringify(tasks.slice(0, 10))}`
    });
    return response.text || "No insights available.";
  } catch (error: any) {
    console.error("Analysis failed:", error);
    if (error.status === 403 || error.message?.includes("PERMISSION_DENIED")) {
      return "AI Access Restricted: Permission Denied. Please verify API Key.";
    }
    return "AI Analysis currently unavailable.";
  }
};

import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback } from 'react';
import { ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, TaskHistory, ProcessStep } from '../types';
import { dbService } from '../services/dbService';

interface BPMContextType {
  processes: ProcessDefinition[];
  instances: ProcessInstance[];
  tasks: Task[];
  loading: boolean;
  error: string | null;
  deployProcess: (process: Omit<ProcessDefinition, 'id' | 'createdAt'>) => Promise<void>;
  startProcess: (definitionId: string, inputData: any) => Promise<string>;
  completeTask: (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => Promise<void>;

  // Data Management
  resetSystem: () => Promise<void>;
  reseedSystem: () => Promise<void>;
  exportData: () => Promise<void>;
  importData: (file: File) => Promise<void>;
  refreshData: () => Promise<void>;
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [processes, setProcesses] = useState<ProcessDefinition[]>([]);
  const [instances, setInstances] = useState<ProcessInstance[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Initial Data Load
  const loadData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      // Ensure DB is open and populated if empty
      const existingProcs = await dbService.getAll<ProcessDefinition>('processes');
      if (existingProcs.length === 0) {
        await dbService.reseed();
      }

      const p = await dbService.getAll<ProcessDefinition>('processes');
      const i = await dbService.getAll<ProcessInstance>('instances');
      const t = await dbService.getAll<Task>('tasks');

      setProcesses(p);
      setInstances(i);
      setTasks(t);
    } catch (e: any) {
      console.error("Failed to load data from DB", e);
      setError(e.message || "Failed to initialize database");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const deployProcess = async (processData: Omit<ProcessDefinition, 'id' | 'createdAt'>) => {
    const newProcess: ProcessDefinition = {
      ...processData,
      id: `proc-${Date.now()}`,
      createdAt: new Date().toISOString(),
    };
    await dbService.add('processes', newProcess);
    setProcesses(prev => [...prev, newProcess]);
  };

  const startProcess = async (definitionId: string, inputData: any) => {
    const definition = processes.find(p => p.id === definitionId);
    if (!definition) throw new Error('Process definition not found');

    const instanceId = `inst-${Date.now()}`;
    const startStep = definition.steps.find(s => s.type === 'start') || definition.steps[0];

    const newInstance: ProcessInstance = {
      id: instanceId,
      definitionId,
      definitionName: definition.name,
      status: 'Active',
      activeStepIds: [startStep.id], // Initialize with start step
      startDate: new Date().toISOString(),
      history: [{
        id: `hist-${Date.now()}`,
        stepName: 'Start',
        action: 'Started',
        performer: 'User',
        timestamp: new Date().toISOString(),
        comments: inputData.summary
      }]
    };

    await dbService.add('instances', newInstance);
    setInstances(prev => [newInstance, ...prev]);

    // Kick off execution from the start step
    await advanceWorkflow(newInstance, definition, startStep.id);
    return instanceId;
  };

  const completeTask = async (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;

    // Update task status
    const updatedTask = { ...task, status: TaskStatus.COMPLETED };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));

    // Update Instance History
    const instance = instances.find(i => i.id === task.processInstanceId);
    if (instance) {
      const definition = processes.find(p => p.id === instance.definitionId);
      if (definition) {
        const historyEntry: TaskHistory = {
          id: `hist-${Date.now()}`,
          stepName: task.title,
          action: action,
          performer: 'CurrentUser',
          timestamp: new Date().toISOString(),
          comments
        };

        let updatedInstance = {
          ...instance,
          history: [...instance.history, historyEntry]
        };

        if (action === 'reject') {
           updatedInstance.status = 'Terminated';
           updatedInstance.endDate = new Date().toISOString();
           updatedInstance.activeStepIds = []; // Clear active steps on termination
           await dbService.add('instances', updatedInstance);
           setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));
           return;
        }

        await dbService.add('instances', updatedInstance);
        setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));

        // Continue workflow from the completed task's step ID
        await advanceWorkflow(updatedInstance, definition, task.stepId);
      }
    }
  };

  /**
   * Core Engine Logic
   * Handles Sequential, Parallel, and Service execution
   */
  const advanceWorkflow = async (instance: ProcessInstance, definition: ProcessDefinition, completedStepId: string) => {
    const currentStep = definition.steps.find(s => s.id === completedStepId);
    if (!currentStep) return;

    // Determine next step IDs
    let nextStepIds: string[] = [];

    // 1. Explicit Graph Links
    if (currentStep.nextStepIds && currentStep.nextStepIds.length > 0) {
      nextStepIds = currentStep.nextStepIds;
    } 
    // 2. Fallback: Sequential Array Index (Legacy/AI generated without links)
    else {
      const currentIndex = definition.steps.findIndex(s => s.id === completedStepId);
      if (currentIndex !== -1 && currentIndex < definition.steps.length - 1) {
        nextStepIds = [definition.steps[currentIndex + 1].id];
      }
    }

    // Update active tokens: Remove completed step, add next steps
    const newActiveStepIds = instance.activeStepIds.filter(id => id !== completedStepId).concat(nextStepIds);

    // Process each next step
    for (const nextId of nextStepIds) {
      const nextStep = definition.steps.find(s => s.id === nextId);
      if (!nextStep) continue;

      if (nextStep.type === 'end') {
         const remaining = newActiveStepIds.filter(id => id !== nextId);
         if (remaining.length === 0) {
            const completedInstance: ProcessInstance = { 
                ...instance, 
                activeStepIds: [],
                status: 'Completed', 
                endDate: new Date().toISOString()
            };
            await dbService.add('instances', completedInstance);
            setInstances(prev => prev.map(i => i.id === instance.id ? completedInstance : i));
            return; // Exit
         } else {
             // Just remove this path
             const updatedInstance = { ...instance, activeStepIds: remaining };
             await dbService.add('instances', updatedInstance);
             setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));
         }
         continue;
      }

      // Handle Parallel Gateway (Auto-pass through)
      if (nextStep.type === 'parallel-gateway') {
         // Recursively advance
         const updatedInstanceWithGateway = { ...instance, activeStepIds: newActiveStepIds };
         await advanceWorkflow(updatedInstanceWithGateway, definition, nextStep.id);
         continue; 
      }

      // Human Interaction Module (User Task)
      if (nextStep.type === 'user-task') {
        const newTask: Task = {
          id: `T-${Date.now()}-${Math.floor(Math.random() * 1000)}`,
          title: nextStep.name,
          processName: definition.name,
          processInstanceId: instance.id,
          assignee: nextStep.role || 'Unassigned',
          dueDate: new Date(Date.now() + 86400000 * 3).toISOString().split('T')[0],
          status: TaskStatus.PENDING,
          priority: TaskPriority.MEDIUM,
          description: nextStep.description,
          stepId: nextStep.id
        };
        await dbService.add('tasks', newTask);
        setTasks(prev => [newTask, ...prev]);

        // Persist the new active state
        const updatedInstance = { ...instance, activeStepIds: newActiveStepIds };
        await dbService.add('instances', updatedInstance);
        setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));
      } 

      // Sequential Processing Module (Service Task)
      else if (nextStep.type === 'service-task') {
         // Persist state first
         const updatedInstance = { ...instance, activeStepIds: newActiveStepIds };
         await dbService.add('instances', updatedInstance);
         setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));

         // Async Execution
         setTimeout(async () => {
             const historyEntry: TaskHistory = {
                 id: `hist-${Date.now()}`,
                 stepName: nextStep.name,
                 action: 'System Executed',
                 performer: 'System',
                 timestamp: new Date().toISOString()
             };
             // Fetch latest to avoid staleness
             const fresh = await dbService.getAll<ProcessInstance>('instances');
             const freshInstance = fresh.find(i => i.id === instance.id) || updatedInstance;

             const instanceWithHistory = {
                 ...freshInstance,
                 history: [...freshInstance.history, historyEntry]
             };
             await dbService.add('instances', instanceWithHistory);
             // Advance
             await advanceWorkflow(instanceWithHistory, definition, nextStep.id);
         }, 2000);
      }
    }
  };

  // --- Management Methods ---

  const resetSystem = async () => {
    setLoading(true);
    await dbService.resetDB();
    await loadData();
    setLoading(false);
  };

  const reseedSystem = async () => {
    setLoading(true);
    await dbService.reseed();
    await loadData();
    setLoading(false);
  };

  const exportData = async () => {
    const json = await dbService.exportData();
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `nexflow_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    setTimeout(() => URL.revokeObjectURL(url), 100); // Cleanup memory
  };

  const importData = async (file: File) => {
    return new Promise<void>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = async (e) => {
        try {
           const json = e.target?.result as string;
           await dbService.importData(json);
           await loadData();
           resolve();
        } catch (err) {
           reject(err);
        }
      };
      reader.onerror = reject;
      reader.readAsText(file);
    });
  };

  return (
    <BPMContext.Provider value={{ 
      processes, 
      instances, 
      tasks, 
      loading, 
      error,
      deployProcess, 
      startProcess, 
      completeTask,
      resetSystem,
      reseedSystem,
      exportData,
      importData,
      refreshData: loadData
    }}>
      {children}
    </BPMContext.Provider>
  );
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

