import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface Props {
  children: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

export class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = {
      hasError: false,
      error: null
    };
  }

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  private handleReload = () => {
    window.location.reload();
  };

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4">
          <div className="bg-white p-8 rounded-xl shadow-lg border border-slate-200 max-w-md w-full text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-4">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-800 mb-2">Something went wrong</h1>
            <p className="text-slate-500 mb-6 text-sm">
              The application encountered an unexpected error. Our engineering team has been notified.
            </p>
            <div className="bg-slate-50 p-3 rounded-lg text-xs font-mono text-left mb-6 overflow-auto max-h-32 border border-slate-200 text-slate-600">
               {this.state.error?.message || 'Unknown Error'}
            </div>
            <button
              onClick={this.handleReload}
              className="w-full py-2.5 bg-brand-600 text-white rounded-lg font-medium hover:bg-brand-700 transition-colors flex items-center justify-center gap-2"
            >
              <RefreshCw size={16} /> Reload Application
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

export enum TaskStatus {
  PENDING = 'Pending',
  IN_PROGRESS = 'In Progress',
  COMPLETED = 'Completed',
  REJECTED = 'Rejected'
}

export enum TaskPriority {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export interface Task {
  id: string;
  title: string;
  processName: string;
  processInstanceId: string;
  assignee: string;
  dueDate: string;
  status: TaskStatus;
  priority: TaskPriority;
  description?: string;
  stepId: string;
  data?: any;
}

export interface ProcessStep {
  id: string;
  name: string;
  type: 'start' | 'user-task' | 'service-task' | 'decision' | 'parallel-gateway' | 'end';
  description: string;
  role?: string;
  // Graph execution properties
  nextStepIds?: string[]; // Array to support 1-to-many connections
  position?: { x: number; y: number };
}

export interface ProcessDefinition {
  id: string;
  name: string;
  description: string;
  steps: ProcessStep[];
  createdAt: string;
  deployedBy: string;
  version?: number;
}

export interface TaskHistory {
  id: string;
  stepName: string;
  action: string;
  performer: string;
  timestamp: string;
  comments?: string;
}

export interface ProcessInstance {
  id: string;
  definitionId: string;
  definitionName: string;
  status: 'Active' | 'Completed' | 'Terminated' | 'Suspended';
  activeStepIds: string[]; // Supports parallel execution tokens
  startDate: string;
  endDate?: string;
  dueDate?: string; // SLA
  variables: Record<string, any>; // Runtime data storage
  priority: TaskPriority;
  history: TaskHistory[];
  comments: { user: string; text: string; timestamp: string }[];
}

export type ViewState = 'dashboard' | 'inbox' | 'explorer' | 'processes' | 'designer' | 'analytics' | 'settings' | 'instance-viewer';

import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback } from 'react';
import { ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, TaskHistory, ProcessStep } from '../types';
import { dbService } from '../services/dbService';

interface BPMContextType {
  processes: ProcessDefinition[];
  instances: ProcessInstance[];
  tasks: Task[];
  loading: boolean;
  error: string | null;
  deployProcess: (process: Omit<ProcessDefinition, 'id' | 'createdAt'>) => Promise<void>;
  startProcess: (definitionId: string, inputData: any) => Promise<string>;
  completeTask: (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => Promise<void>;

  // Admin / Advanced Features
  adminOverrideStep: (instanceId: string, targetStepId: string) => Promise<void>;
  updateInstanceVariables: (instanceId: string, variables: Record<string, any>) => Promise<void>;
  toggleInstanceSuspension: (instanceId: string) => Promise<void>;
  addInstanceComment: (instanceId: string, comment: string) => Promise<void>;

  // Data Management
  resetSystem: () => Promise<void>;
  reseedSystem: () => Promise<void>;
  exportData: () => Promise<void>;
  importData: (file: File) => Promise<void>;
  refreshData: () => Promise<void>;
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [processes, setProcesses] = useState<ProcessDefinition[]>([]);
  const [instances, setInstances] = useState<ProcessInstance[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Initial Data Load
  const loadData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const existingProcs = await dbService.getAll<ProcessDefinition>('processes');
      if (existingProcs.length === 0) {
        await dbService.reseed();
      }

      const p = await dbService.getAll<ProcessDefinition>('processes');
      const i = await dbService.getAll<ProcessInstance>('instances');
      const t = await dbService.getAll<Task>('tasks');

      setProcesses(p);
      setInstances(i);
      setTasks(t);
    } catch (e: any) {
      console.error("Failed to load data from DB", e);
      setError(e.message || "Failed to initialize database");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const deployProcess = async (processData: Omit<ProcessDefinition, 'id' | 'createdAt'>) => {
    const newProcess: ProcessDefinition = {
      ...processData,
      id: `proc-${Date.now()}`,
      createdAt: new Date().toISOString(),
      version: 1
    };
    await dbService.add('processes', newProcess);
    setProcesses(prev => [...prev, newProcess]);
  };

  const startProcess = async (definitionId: string, inputData: any) => {
    const definition = processes.find(p => p.id === definitionId);
    if (!definition) throw new Error('Process definition not found');

    const instanceId = `inst-${Date.now()}`;
    const startStep = definition.steps.find(s => s.type === 'start') || definition.steps[0];

    const newInstance: ProcessInstance = {
      id: instanceId,
      definitionId,
      definitionName: definition.name,
      status: 'Active',
      activeStepIds: [startStep.id], // Initialize with start step
      startDate: new Date().toISOString(),
      variables: inputData || {},
      priority: TaskPriority.MEDIUM,
      comments: [],
      history: [{
        id: `hist-${Date.now()}`,
        stepName: 'Start',
        action: 'Started',
        performer: 'User',
        timestamp: new Date().toISOString(),
        comments: inputData.summary
      }]
    };

    await dbService.add('instances', newInstance);
    setInstances(prev => [newInstance, ...prev]);

    await advanceWorkflow(newInstance, definition, startStep.id);
    return instanceId;
  };

  const completeTask = async (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;

    // Update task status
    const updatedTask = { ...task, status: TaskStatus.COMPLETED };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));

    // Update Instance History
    const instance = instances.find(i => i.id === task.processInstanceId);
    if (instance) {
      const definition = processes.find(p => p.id === instance.definitionId);
      if (definition) {
        const historyEntry: TaskHistory = {
          id: `hist-${Date.now()}`,
          stepName: task.title,
          action: action,
          performer: 'CurrentUser',
          timestamp: new Date().toISOString(),
          comments
        };

        let updatedInstance = {
          ...instance,
          history: [...instance.history, historyEntry]
        };

        if (action === 'reject') {
           updatedInstance.status = 'Terminated';
           updatedInstance.endDate = new Date().toISOString();
           updatedInstance.activeStepIds = []; // Clear active steps on termination
           await dbService.add('instances', updatedInstance);
           setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));
           return;
        }

        await dbService.add('instances', updatedInstance);
        setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));

        await advanceWorkflow(updatedInstance, definition, task.stepId);
      }
    }
  };

  // --- Admin / Advanced Logic ---

  const adminOverrideStep = async (instanceId: string, targetStepId: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;
    const definition = processes.find(p => p.id === instance.definitionId);
    if (!definition) return;
    const targetStep = definition.steps.find(s => s.id === targetStepId);
    if (!targetStep) return;

    // Close pending tasks for this instance (Force Complete)
    const pendingTasks = tasks.filter(t => t.processInstanceId === instanceId && t.status === TaskStatus.PENDING);
    for (const t of pendingTasks) {
       t.status = TaskStatus.COMPLETED;
       t.description = `${t.description} (Admin Override)`;
       await dbService.add('tasks', t);
    }
    setTasks(prev => prev.map(t => t.processInstanceId === instanceId ? { ...t, status: TaskStatus.COMPLETED } : t));

    // Move Token
    const updatedInstance: ProcessInstance = {
      ...instance,
      activeStepIds: [targetStepId],
      history: [...instance.history, {
        id: `hist-${Date.now()}`,
        stepName: 'Admin Override',
        action: 'Jumped',
        performer: 'Administrator',
        timestamp: new Date().toISOString(),
        comments: `Forced jump to ${targetStep.name}`
      }]
    };

    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));

    // Trigger workflow logic for the new step
    if (targetStep.type !== 'end') {
       // We "pretend" we just arrived here, but we need to generate tasks for THIS step, not the next one.
       // The advanceWorkflow logic usually takes "completedStepId" and finds NEXT.
       // We need to trigger logic for "targetStepId" immediately.
       await executeStepLogic(updatedInstance, definition, targetStep);
    }
  };

  const updateInstanceVariables = async (instanceId: string, variables: Record<string, any>) => {
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;

    const updatedInstance = { ...instance, variables };
    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));
  };

  const toggleInstanceSuspension = async (instanceId: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;

    const newStatus = instance.status === 'Suspended' ? 'Active' : 'Suspended';
    const updatedInstance = { ...instance, status: newStatus as any };

    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));
  };

  const addInstanceComment = async (instanceId: string, comment: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;

    const newComment = { user: 'Admin', text: comment, timestamp: new Date().toISOString() };
    const updatedInstance = { ...instance, comments: [...(instance.comments || []), newComment] };

    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));
  };

  // --- Engine Internals ---

  const advanceWorkflow = async (instance: ProcessInstance, definition: ProcessDefinition, completedStepId: string) => {
    const currentStep = definition.steps.find(s => s.id === completedStepId);
    if (!currentStep) return;

    let nextStepIds: string[] = [];
    if (currentStep.nextStepIds && currentStep.nextStepIds.length > 0) {
      nextStepIds = currentStep.nextStepIds;
    } else {
      const currentIndex = definition.steps.findIndex(s => s.id === completedStepId);
      if (currentIndex !== -1 && currentIndex < definition.steps.length - 1) {
        nextStepIds = [definition.steps[currentIndex + 1].id];
      }
    }

    const newActiveStepIds = instance.activeStepIds.filter(id => id !== completedStepId).concat(nextStepIds);

    // Persist new token state immediately before processing next steps
    // This ensures if a crash happens, we know where we are.
    let workingInstance = { ...instance, activeStepIds: newActiveStepIds };

    // Check for end of process
    if (newActiveStepIds.length === 0 || nextStepIds.some(id => definition.steps.find(s => s.id === id)?.type === 'end')) {
       const endStep = nextStepIds.find(id => definition.steps.find(s => s.id === id)?.type === 'end');
       if (endStep || newActiveStepIds.length === 0) {
         workingInstance.status = 'Completed';
         workingInstance.endDate = new Date().toISOString();
         workingInstance.activeStepIds = []; // Clear
         await dbService.add('instances', workingInstance);
         setInstances(prev => prev.map(i => i.id === instance.id ? workingInstance : i));
         return; 
       }
    }

    // Persist intermediate state
    await dbService.add('instances', workingInstance);
    setInstances(prev => prev.map(i => i.id === instance.id ? workingInstance : i));

    // Execute logic for next steps
    for (const nextId of nextStepIds) {
      const nextStep = definition.steps.find(s => s.id === nextId);
      if (nextStep) {
         await executeStepLogic(workingInstance, definition, nextStep);
      }
    }
  };

  const executeStepLogic = async (instance: ProcessInstance, definition: ProcessDefinition, step: ProcessStep) => {
     if (step.type === 'parallel-gateway') {
         // Auto-advance
         await advanceWorkflow(instance, definition, step.id);
     } else if (step.type === 'user-task') {
        const newTask: Task = {
          id: `T-${Date.now()}-${Math.floor(Math.random() * 1000)}`,
          title: step.name,
          processName: definition.name,
          processInstanceId: instance.id,
          assignee: step.role || 'Unassigned',
          dueDate: new Date(Date.now() + 86400000 * 3).toISOString().split('T')[0],
          status: TaskStatus.PENDING,
          priority: instance.priority || TaskPriority.MEDIUM,
          description: step.description,
          stepId: step.id
        };
        await dbService.add('tasks', newTask);
        setTasks(prev => [newTask, ...prev]);
     } else if (step.type === 'service-task') {
         setTimeout(async () => {
             const historyEntry: TaskHistory = {
                 id: `hist-${Date.now()}`,
                 stepName: step.name,
                 action: 'System Executed',
                 performer: 'System',
                 timestamp: new Date().toISOString()
             };
             const fresh = await dbService.getAll<ProcessInstance>('instances');
             const freshInstance = fresh.find(i => i.id === instance.id) || instance;
             const instanceWithHistory = {
                 ...freshInstance,
                 history: [...freshInstance.history, historyEntry]
             };
             await dbService.add('instances', instanceWithHistory);
             await advanceWorkflow(instanceWithHistory, definition, step.id);
         }, 2000);
     }
  };

  const resetSystem = async () => {
    setLoading(true);
    await dbService.resetDB();
    await loadData();
    setLoading(false);
  };

  const reseedSystem = async () => {
    setLoading(true);
    await dbService.reseed();
    await loadData();
    setLoading(false);
  };

  const exportData = async () => {
    const json = await dbService.exportData();
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `nexflow_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    setTimeout(() => URL.revokeObjectURL(url), 100);
  };

  const importData = async (file: File) => {
    return new Promise<void>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = async (e) => {
        try {
           const json = e.target?.result as string;
           await dbService.importData(json);
           await loadData();
           resolve();
        } catch (err) {
           reject(err);
        }
      };
      reader.onerror = reject;
      reader.readAsText(file);
    });
  };

  return (
    <BPMContext.Provider value={{ 
      processes, instances, tasks, loading, error,
      deployProcess, startProcess, completeTask,
      adminOverrideStep, updateInstanceVariables, toggleInstanceSuspension, addInstanceComment,
      resetSystem, reseedSystem, exportData, importData, refreshData: loadData
    }}>
      {children}
    </BPMContext.Provider>
  );
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

import React, { useState, useRef, useEffect } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { ProcessDefinition, ProcessInstance, ProcessStep } from '../types';
import { 
  Play, Pause, FastForward, CheckCircle, AlertTriangle, 
  MessageSquare, Save, Settings, X, Activity, ZoomIn, ZoomOut, User,
  FileJson, Calendar, Paperclip, Share2, MoreVertical
} from 'lucide-react';

interface Props {
  instanceId: string;
  onClose: () => void;
}

export const ProcessInstanceViewer: React.FC<Props> = ({ instanceId, onClose }) => {
  const { instances, processes, adminOverrideStep, updateInstanceVariables, toggleInstanceSuspension, addInstanceComment } = useBPM();

  const instance = instances.find(i => i.id === instanceId);
  const process = processes.find(p => p.id === instance?.definitionId);

  const [viewport, setViewport] = useState({ x: 0, y: 0, zoom: 1 });
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
  const [rightPanelTab, setRightPanelTab] = useState<'info' | 'variables' | 'comments'>('info');
  const [newComment, setNewComment] = useState('');
  const [variableJson, setVariableJson] = useState('');
  const [isJsonValid, setIsJsonValid] = useState(true);

  // Interaction Refs
  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const lastTouchDistance = useRef<number | null>(null);

  useEffect(() => {
    if (instance) {
      setVariableJson(JSON.stringify(instance.variables, null, 2));

      // Auto-center on active step
      if (process && instance.activeStepIds.length > 0) {
         const activeStep = process.steps.find(s => s.id === instance.activeStepIds[0]);
         if (activeStep && activeStep.position && canvasRef.current) {
            const centerX = canvasRef.current.clientWidth / 2;
            const centerY = canvasRef.current.clientHeight / 2;
            setViewport({
              x: centerX - (activeStep.position.x * 1) - 90, // Center offset
              y: centerY - (activeStep.position.y * 1) - 40,
              zoom: 1
            });
         }
      }
    }
  }, [instanceId, process]);

  if (!instance || !process) return <div className="p-8 text-center">Instance not found</div>;

  // --- Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    e.preventDefault();
    isDragging.current = true;
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    const dx = e.clientX - dragStart.current.x;
    const dy = e.clientY - dragStart.current.y;
    setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy }));
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerUp = () => { isDragging.current = false; };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (e.touches.length === 2) {
      e.preventDefault();
      const dist = Math.hypot(
        e.touches[0].clientX - e.touches[1].clientX,
        e.touches[0].clientY - e.touches[1].clientY
      );
      if (lastTouchDistance.current) {
        const delta = dist - lastTouchDistance.current;
        const zoomFactor = delta * 0.005;
        setViewport(prev => ({ ...prev, zoom: Math.min(Math.max(0.2, prev.zoom + zoomFactor), 3) }));
      }
      lastTouchDistance.current = dist;
    }
  };

  const handleAdminMove = async () => {
    if (selectedNodeId && confirm(`ADMIN: Force move token to step "${selectedNodeId}"? This will complete current tasks.`)) {
      if (navigator.vibrate) navigator.vibrate(50); // Haptic
      await adminOverrideStep(instance.id, selectedNodeId);
      setSelectedNodeId(null);
    }
  };

  const handleSaveVariables = async () => {
    try {
      const parsed = JSON.parse(variableJson);
      await updateInstanceVariables(instance.id, parsed);
      alert('Variables updated successfully');
    } catch (e) {
      alert('Invalid JSON');
    }
  };

  const handlePostComment = async () => {
    if (!newComment.trim()) return;
    await addInstanceComment(instance.id, newComment);
    setNewComment('');
  };

  // --- Render Helpers ---

  const getNodeStatus = (stepId: string) => {
    if (instance.activeStepIds.includes(stepId)) return 'active';
    // Check history to see if completed
    const wasVisited = instance.history.some(h => h.stepName === process.steps.find(s => s.id === stepId)?.name);
    return wasVisited ? 'completed' : 'pending';
  };

  const getNodeColor = (stepId: string, type: string) => {
    const status = getNodeStatus(stepId);
    if (status === 'active') return 'bg-white ring-4 ring-green-400 ring-opacity-50 border-green-500 shadow-lg z-10';
    if (status === 'completed') return 'bg-slate-50 border-slate-300 opacity-80 grayscale';
    return 'bg-white border-slate-300 opacity-60';
  };

  return (
    <div className="fixed inset-0 bg-slate-100 z-50 flex flex-col animate-fade-in">
      {/* Header */}
      <div className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 shadow-sm z-20">
        <div className="flex items-center gap-4">
           <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full text-slate-500">
             <X size={24} />
           </button>
           <div>
             <div className="flex items-center gap-2">
               <h2 className="font-bold text-slate-800">{process.name}</h2>
               <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${instance.status === 'Active' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                 {instance.status}
               </span>
               <span className="text-xs text-slate-400 bg-slate-100 px-2 rounded">v{process.version || 1}.0</span>
             </div>
             <div className="text-xs text-slate-500 flex items-center gap-3">
               <span>ID: {instance.id}</span>
               <span>Started: {new Date(instance.startDate).toLocaleDateString()}</span>
             </div>
           </div>
        </div>

        <div className="flex items-center gap-2">
           <button 
             onClick={() => toggleInstanceSuspension(instance.id)}
             className={`p-2 rounded-lg font-medium text-sm flex items-center gap-2 transition-colors ${instance.status === 'Suspended' ? 'bg-green-50 text-green-700' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
           >
             {instance.status === 'Suspended' ? <Play size={16}/> : <Pause size={16}/>}
             <span className="hidden md:inline">{instance.status === 'Suspended' ? 'Resume' : 'Suspend'}</span>
           </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        {/* Graph Canvas */}
        <div className="flex-1 relative bg-slate-50 overflow-hidden">
           <div 
             ref={canvasRef}
             className="absolute inset-0 touch-none cursor-move"
             onPointerDown={handlePointerDown}
             onPointerMove={handlePointerMove}
             onPointerUp={handlePointerUp}
             onTouchMove={handleTouchMove}
             style={{
               backgroundImage: 'radial-gradient(#cbd5e1 1px, transparent 1px)',
               backgroundSize: `${40 * viewport.zoom}px ${40 * viewport.zoom}px`,
               backgroundPosition: `${viewport.x}px ${viewport.y}px`
             }}
           >
              <div 
                style={{
                  transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`,
                  transformOrigin: '0 0',
                  width: '100%',
                  height: '100%'
                }}
              >
                 {/* Connections */}
                 <svg className="overflow-visible absolute top-0 left-0 pointer-events-none" style={{width: 1, height: 1}}>
                    {process.steps.flatMap(step => {
                      if (!step.nextStepIds || !step.position) return [];
                      return step.nextStepIds.map(targetId => {
                         const target = process.steps.find(s => s.id === targetId);
                         if (!target || !target.position) return null;

                         // Check if path is traversed (both source and target visited)
                         const sourceVisited = instance.history.some(h => h.stepName === step.name) || instance.activeStepIds.includes(step.id);
                         const targetVisited = instance.history.some(h => h.stepName === target.name) || instance.activeStepIds.includes(target.id);
                         const isPathActive = sourceVisited && targetVisited; // Simple approximation

                         const x1 = step.position.x + 180; 
                         const y1 = step.position.y + 40;  
                         const x2 = target.position.x;     
                         const y2 = target.position.y + 40;
                         const path = `M ${x1} ${y1} C ${x1 + 50} ${y1}, ${x2 - 50} ${y2}, ${x2} ${y2}`;

                         return (
                            <path 
                              key={`${step.id}-${target.id}`} 
                              d={path} 
                              stroke={isPathActive ? "#22c55e" : "#cbd5e1"} 
                              strokeWidth={isPathActive ? 3 : 2} 
                              fill="none" 
                              className="transition-colors duration-500"
                            />
                         );
                      });
                    })}
                 </svg>

                 {/* Nodes */}
                 {process.steps.map(step => {
                   const isActive = instance.activeStepIds.includes(step.id);
                   return (
                     <div 
                       key={step.id}
                       onClick={() => setSelectedNodeId(step.id)}
                       className={`absolute w-[180px] h-[80px] rounded-lg border-2 flex flex-col p-3 transition-all cursor-pointer ${getNodeColor(step.id, step.type)} ${selectedNodeId === step.id ? 'ring-2 ring-brand-500' : ''}`}
                       style={{
                          left: step.position?.x || 0,
                          top: step.position?.y || 0
                       }}
                     >
                        {isActive && (
                          <div className="absolute -top-3 -right-3 w-6 h-6 bg-red-500 rounded-full text-white flex items-center justify-center animate-bounce shadow-sm z-20">
                             <Activity size={14} />
                          </div>
                        )}
                        <div className="flex items-center gap-2 mb-1">
                           <span className="text-[10px] font-bold uppercase tracking-wide opacity-70">{step.type}</span>
                        </div>
                        <div className="font-semibold text-sm truncate">{step.name}</div>
                        <div className="mt-auto text-[10px] text-slate-500 truncate">{step.role || 'System'}</div>
                     </div>
                   );
                 })}
              </div>
           </div>

           {/* Floating Controls */}
           <div className="absolute bottom-6 left-6 flex flex-col gap-2">
              <button onClick={() => setViewport(v => ({...v, zoom: v.zoom + 0.1}))} className="bg-white p-2 rounded-lg shadow border border-slate-200 text-slate-600"><ZoomIn size={20}/></button>
              <button onClick={() => setViewport(v => ({...v, zoom: v.zoom - 0.1}))} className="bg-white p-2 rounded-lg shadow border border-slate-200 text-slate-600"><ZoomOut size={20}/></button>
           </div>

           {/* Active Step Toast */}
           {selectedNodeId && (
              <div className="absolute top-6 left-1/2 -translate-x-1/2 bg-white rounded-full shadow-lg border border-slate-200 px-6 py-2 flex items-center gap-4 z-30 animate-slide-in-up">
                 <span className="text-sm font-medium text-slate-700">Selected: {process.steps.find(s => s.id === selectedNodeId)?.name}</span>
                 <div className="h-4 w-px bg-slate-200"></div>
                 <button 
                   onClick={handleAdminMove}
                   className="text-xs font-bold text-red-600 hover:text-red-700 flex items-center gap-1 uppercase"
                 >
                   <FastForward size={14} /> Move Here
                 </button>
              </div>
           )}
        </div>

        {/* Right Admin Panel */}
        <div className="w-96 bg-white border-l border-slate-200 flex flex-col shadow-xl z-30">
           <div className="flex border-b border-slate-100">
              <button onClick={() => setRightPanelTab('info')} className={`flex-1 py-3 text-sm font-medium border-b-2 ${rightPanelTab === 'info' ? 'border-brand-500 text-brand-600' : 'border-transparent text-slate-500'}`}>Overview</button>
              <button onClick={() => setRightPanelTab('variables')} className={`flex-1 py-3 text-sm font-medium border-b-2 ${rightPanelTab === 'variables' ? 'border-brand-500 text-brand-600' : 'border-transparent text-slate-500'}`}>Data</button>
              <button onClick={() => setRightPanelTab('comments')} className={`flex-1 py-3 text-sm font-medium border-b-2 ${rightPanelTab === 'comments' ? 'border-brand-500 text-brand-600' : 'border-transparent text-slate-500'}`}>Comments</button>
           </div>

           <div className="flex-1 overflow-y-auto p-4 bg-slate-50/30">
              {rightPanelTab === 'info' && (
                <div className="space-y-6">
                   <div className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm">
                      <h4 className="text-xs font-bold text-slate-500 uppercase mb-3">SLA Status</h4>
                      <div className="flex items-center gap-3">
                         <div className="p-2 bg-amber-50 text-amber-600 rounded-lg">
                            <AlertTriangle size={20} />
                         </div>
                         <div>
                            <div className="text-sm font-bold text-slate-800">Due in 2 Days</div>
                            <div className="text-xs text-slate-500">Priority: {instance.priority}</div>
                         </div>
                      </div>
                   </div>

                   <div>
                      <h4 className="text-xs font-bold text-slate-500 uppercase mb-3">Audit Trail</h4>
                      <div className="space-y-4 relative pl-2">
                        <div className="absolute left-[7px] top-2 bottom-0 w-px bg-slate-200"></div>
                        {instance.history.map((h, i) => (
                           <div key={i} className="relative pl-6">
                              <div className="absolute left-0 top-1.5 w-3.5 h-3.5 bg-white border-2 border-slate-300 rounded-full"></div>
                              <div className="text-xs font-bold text-slate-700">{h.stepName}</div>
                              <div className="text-[10px] text-slate-500">{h.action} by {h.performer}</div>
                              <div className="text-[10px] text-slate-400">{new Date(h.timestamp).toLocaleString()}</div>
                           </div>
                        ))}
                      </div>
                   </div>
                </div>
              )}

              {rightPanelTab === 'variables' && (
                <div className="h-full flex flex-col">
                   <div className="flex items-center justify-between mb-2">
                      <span className="text-xs font-bold text-slate-500 uppercase">Process Variables (JSON)</span>
                      <button onClick={handleSaveVariables} className="text-brand-600 hover:text-brand-700"><Save size={16}/></button>
                   </div>
                   <textarea 
                     className="flex-1 w-full bg-slate-900 text-green-400 font-mono text-xs p-3 rounded-lg border border-slate-700 resize-none focus:outline-none focus:ring-1 focus:ring-brand-500"
                     value={variableJson}
                     onChange={e => {
                        setVariableJson(e.target.value);
                        try { JSON.parse(e.target.value); setIsJsonValid(true); } catch { setIsJsonValid(false); }
                     }}
                   />
                   {!isJsonValid && <div className="text-red-500 text-xs mt-1">Invalid JSON format</div>}
                </div>
              )}

              {rightPanelTab === 'comments' && (
                <div className="flex flex-col h-full">
                   <div className="flex-1 space-y-3 mb-4">
                      {instance.comments?.length === 0 && <div className="text-center text-slate-400 text-sm mt-10">No comments yet.</div>}
                      {instance.comments?.map((c, i) => (
                         <div key={i} className="bg-white p-3 rounded-lg border border-slate-200 shadow-sm">
                            <div className="flex justify-between items-center mb-1">
                               <span className="font-bold text-xs text-slate-700">{c.user}</span>
                               <span className="text-[10px] text-slate-400">{new Date(c.timestamp).toLocaleTimeString()}</span>
                            </div>
                            <p className="text-xs text-slate-600">{c.text}</p>
                         </div>
                      ))}
                   </div>
                   <div className="mt-auto">
                      <div className="relative">
                         <input 
                           className="w-full pl-3 pr-10 py-2 bg-white border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-brand-500 focus:outline-none"
                           placeholder="Type a note..."
                           value={newComment}
                           onChange={e => setNewComment(e.target.value)}
                           onKeyDown={e => e.key === 'Enter' && handlePostComment()}
                         />
                         <button onClick={handlePostComment} className="absolute right-2 top-1/2 -translate-y-1/2 text-brand-600 hover:text-brand-800">
                            <Share2 size={16} />
                         </button>
                      </div>
                   </div>
                </div>
              )}
           </div>
        </div>
      </div>
    </div>
  );
};

