import React, { useState, useRef, useEffect, useMemo } from 'react';
import { generateProcessWorkflow } from '../services/geminiService';
import { ProcessStep, ProcessLink } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { 
  Wand2, Save, Play, Settings, User, Cog, GitBranch, Flag, 
  Plus, Trash2, Split, Maximize, MousePointer2, Info, 
  AlertCircle, ChevronRight, Zap, History, Layout, StickyNote
} from 'lucide-react';

const GRID_SIZE = 20;
const SNAP_THRESHOLD = 40;

export const ProcessDesigner: React.FC = () => {
  const { deployProcess, startProcess } = useBPM();
  const [mode, setMode] = useState<'ai' | 'visual'>('visual');
  const [processName, setProcessName] = useState('New Enterprise Flow');

  // --- Visual Editor State ---
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [links, setLinks] = useState<ProcessLink[]>([]);
  const [viewport, setViewport] = useState({ x: 0, y: 0, zoom: 1 });
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isLassoing, setIsLassoing] = useState(false);
  const [lassoBox, setLassoBox] = useState<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  // Interaction Refs
  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'link' | 'lasso'>('viewport');
  const activeId = useRef<string | null>(null);
  const connectionLine = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  // --- Handlers ---

  const addNode = (type: ProcessStep['type']) => {
    const worldPos = screenToWorld(window.innerWidth / 2, window.innerHeight / 2);
    const snapX = Math.round(worldPos.x / GRID_SIZE) * GRID_SIZE;
    const snapY = Math.round(worldPos.y / GRID_SIZE) * GRID_SIZE;

    const newNode: ProcessStep = {
      id: `node-${Date.now()}`,
      name: type === 'parallel-gateway' ? 'Split' : `New ${type}`,
      type,
      description: '',
      position: { x: snapX, y: snapY },
      nextStepIds: []
    };
    setSteps(prev => [...prev, newNode]);
    setSelectedId(newNode.id);
    if (navigator.vibrate) navigator.vibrate(10);
  };

  const screenToWorld = (sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return {
      x: (sx - rect.left - viewport.x) / viewport.zoom,
      y: (sy - rect.top - viewport.y) / viewport.zoom
    };
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const handleEl = target.closest('[data-handle-id]');

    dragStart.current = { x: e.clientX, y: e.clientY };
    isDragging.current = true;

    if (handleEl) {
      dragTarget.current = 'link';
      activeId.current = handleEl.getAttribute('data-handle-id');
    } else if (nodeEl) {
      dragTarget.current = 'node';
      activeId.current = nodeEl.getAttribute('data-node-id');
      setSelectedId(activeId.current);
    } else {
      dragTarget.current = 'viewport';
      if (e.shiftKey) {
        dragTarget.current = 'lasso';
        const start = screenToWorld(e.clientX, e.clientY);
        setLassoBox({ x1: start.x, y1: start.y, x2: start.x, y2: start.y });
      }
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    const dx = (e.clientX - dragStart.current.x) / viewport.zoom;
    const dy = (e.clientY - dragStart.current.y) / viewport.zoom;

    if (dragTarget.current === 'viewport') {
      setViewport(prev => ({ ...prev, x: prev.x + (e.clientX - dragStart.current.x), y: prev.y + (e.clientY - dragStart.current.y) }));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } else if (dragTarget.current === 'node' && activeId.current) {
      setSteps(prev => prev.map(s => s.id === activeId.current ? { 
        ...s, 
        position: { x: (s.position?.x || 0) + dx, y: (s.position?.y || 0) + dy } 
      } : s));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } else if (dragTarget.current === 'link' && activeId.current) {
      const startNode = steps.find(s => s.id === activeId.current);
      if (startNode) {
        const world = screenToWorld(e.clientX, e.clientY);
        connectionLine.current = {
          x1: (startNode.position?.x || 0) + 180,
          y1: (startNode.position?.y || 0) + 40,
          x2: world.x,
          y2: world.y
        };
        setViewport(v => ({...v})); // Trigger render
      }
    } else if (dragTarget.current === 'lasso') {
      const current = screenToWorld(e.clientX, e.clientY);
      setLassoBox(prev => prev ? { ...prev, x2: current.x, y2: current.y } : null);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragTarget.current === 'link' && activeId.current) {
      const targetNodeEl = document.elementFromPoint(e.clientX, e.clientY)?.closest('[data-node-id]');
      if (targetNodeEl) {
        const targetId = targetNodeEl.getAttribute('data-node-id');
        if (targetId && targetId !== activeId.current) {
          const newLink: ProcessLink = { id: `link-${Date.now()}`, sourceId: activeId.current, targetId };
          setLinks(prev => [...prev, newLink]);
          if (navigator.vibrate) navigator.vibrate(20);
        }
      }
    }

    // Finalize Node Snapping
    if (dragTarget.current === 'node' && activeId.current) {
      setSteps(prev => prev.map(s => s.id === activeId.current ? {
        ...s,
        position: {
          x: Math.round((s.position?.x || 0) / GRID_SIZE) * GRID_SIZE,
          y: Math.round((s.position?.y || 0) / GRID_SIZE) * GRID_SIZE
        }
      } : s));
    }

    isDragging.current = false;
    connectionLine.current = null;
    setLassoBox(null);
    setViewport(v => ({...v}));
  };

  // --- Logic & Validation ---
  const validationErrors = useMemo(() => {
    const errors: string[] = [];
    if (!steps.some(s => s.type === 'start')) errors.push("Missing Start Event");
    if (!steps.some(s => s.type === 'end')) errors.push("Missing End Event");
    const orphans = steps.filter(s => s.type !== 'start' && !links.some(l => l.targetId === s.id));
    if (orphans.length > 0) errors.push(`${orphans.length} unreachable steps`);
    return errors;
  }, [steps, links]);

  // --- Rendering ---
  return (
    <div className="h-[calc(100vh-140px)] flex bg-white rounded-xl border border-slate-200 overflow-hidden shadow-inner">
      {/* Sidebar Palette */}
      <aside className="w-64 border-r border-slate-100 flex flex-col bg-slate-50/50 z-20">
        <div className="p-4 border-b border-slate-100 font-bold text-xs text-slate-500 uppercase tracking-widest flex items-center justify-between">
          <span>Component Library</span>
          <Zap size={14} className="text-brand-500" />
        </div>
        <div className="flex-1 p-4 space-y-4 overflow-y-auto">
          <div className="space-y-2">
            <h4 className="text-[10px] font-bold text-slate-400 uppercase">Events</h4>
            <div className="grid grid-cols-2 gap-2">
               <button onClick={() => addNode('start')} className="p-3 bg-white border border-slate-200 rounded-lg hover:border-brand-500 hover:shadow-sm transition-all flex flex-col items-center gap-1 group">
                 <Play size={18} className="text-green-500 group-hover:scale-110 transition-transform" />
                 <span className="text-[10px] font-medium">Start</span>
               </button>
               <button onClick={() => addNode('end')} className="p-3 bg-white border border-slate-200 rounded-lg hover:border-brand-500 hover:shadow-sm transition-all flex flex-col items-center gap-1 group">
                 <Flag size={18} className="text-slate-800 group-hover:scale-110 transition-transform" />
                 <span className="text-[10px] font-medium">End</span>
               </button>
            </div>
          </div>

          <div className="space-y-2">
            <h4 className="text-[10px] font-bold text-slate-400 uppercase">Tasks</h4>
            <div className="grid grid-cols-2 gap-2">
               <button onClick={() => addNode('user-task')} className="p-3 bg-white border border-slate-200 rounded-lg hover:border-brand-500 transition-all flex flex-col items-center gap-1 group">
                 <User size={18} className="text-blue-500 group-hover:scale-110" />
                 <span className="text-[10px] font-medium text-center leading-tight">User Task</span>
               </button>
               <button onClick={() => addNode('service-task')} className="p-3 bg-white border border-slate-200 rounded-lg hover:border-brand-500 transition-all flex flex-col items-center gap-1 group">
                 <Cog size={18} className="text-purple-500 group-hover:scale-110" />
                 <span className="text-[10px] font-medium text-center leading-tight">Automated</span>
               </button>
            </div>
          </div>

          <div className="space-y-2">
            <h4 className="text-[10px] font-bold text-slate-400 uppercase">Logic</h4>
            <div className="grid grid-cols-2 gap-2">
               <button onClick={() => addNode('decision')} className="p-3 bg-white border border-slate-200 rounded-lg hover:border-brand-500 transition-all flex flex-col items-center gap-1 group">
                 <GitBranch size={18} className="text-amber-500 group-hover:scale-110" />
                 <span className="text-[10px] font-medium text-center leading-tight">Decision</span>
               </button>
               <button onClick={() => addNode('parallel-gateway')} className="p-3 bg-white border border-slate-200 rounded-lg hover:border-brand-500 transition-all flex flex-col items-center gap-1 group">
                 <Split size={18} className="text-orange-500 group-hover:scale-110" />
                 <span className="text-[10px] font-medium text-center leading-tight">Parallel</span>
               </button>
            </div>
          </div>

          <div className="pt-4 border-t border-slate-100">
             <button onClick={() => addNode('note')} className="w-full p-3 bg-amber-50 border border-amber-200 rounded-lg hover:bg-amber-100 transition-all flex items-center gap-3">
               <StickyNote size={18} className="text-amber-600" />
               <span className="text-[10px] font-bold uppercase tracking-tight text-amber-800">Sticky Note</span>
             </button>
          </div>
        </div>

        {/* Validation Status */}
        <div className="p-4 bg-slate-100 border-t border-slate-200">
           <h4 className="text-[10px] font-bold text-slate-500 mb-2 uppercase">Designer Health</h4>
           {validationErrors.length === 0 ? (
             <div className="flex items-center gap-2 text-green-600 text-[10px] font-bold">
               <Zap size={12} /> ALL CLEAR
             </div>
           ) : (
             <div className="space-y-1">
               {validationErrors.map((err, i) => (
                 <div key={i} className="flex items-center gap-1.5 text-red-500 text-[10px] font-medium">
                   <AlertCircle size={10} /> {err}
                 </div>
               ))}
             </div>
           )}
