            {/* SVG Link Layer */}
            <svg className="overflow-visible absolute top-0 left-0 pointer-events-none" style={{width: 1, height: 1}}>
              <defs>
                <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="10" refY="3.5" orient="auto">
                  <polygon points="0 0, 10 3.5, 0 7" fill="#94a3b8" />
                </marker>
              </defs>
              {links.map(link => {
                const s = steps.find(n => n.id === link.sourceId);
                const t = steps.find(n => n.id === link.targetId);
                if (!s || !t) return null;
                const x1 = (s.position?.x || 0) + 180;
                const y1 = (s.position?.y || 0) + 40;
                const x2 = (t.position?.x || 0);
                const y2 = (t.position?.y || 0) + 40;
                return (
                  <path 
                    key={link.id} 
                    d={`M ${x1} ${y1} C ${x1 + 60} ${y1}, ${x2 - 60} ${y2}, ${x2} ${y2}`} 
                    stroke="#94a3b8" 
                    strokeWidth="2" 
                    fill="none" 
                    markerEnd="url(#arrowhead)"
                  />
                );
              })}
