                className={`absolute w-[180px] h-[80px] rounded-lg border-2 shadow-sm flex flex-col p-3 transition-shadow ${selectedId === step.id ? 'ring-2 ring-brand-500 border-brand-300' : 'bg-white border-slate-200'} ${step.type === 'note' ? 'bg-amber-50 border-amber-200 border-dashed w-[220px] h-[100px]' : ''}`}
                style={{ left: step.position?.x || 0, top: step.position?.y || 0 }}
