                <div className="flex items-center justify-between mb-1">
                  <div className="flex items-center gap-1.5">
                     {step.type === 'start' && <Play size={14} className="text-green-500" />}
                     {step.type === 'end' && <Flag size={14} className="text-slate-800" />}
                     {step.type === 'user-task' && <User size={14} className="text-blue-500" />}
                     {step.type === 'service-task' && <Cog size={14} className="text-purple-500" />}
                     {step.type === 'decision' && <GitBranch size={14} className="text-amber-500" />}
                     {step.type === 'note' && <StickyNote size={14} className="text-amber-500" />}
                     <span className="text-[9px] font-bold uppercase tracking-wider text-slate-400">{step.type}</span>
                  </div>
                  {step.slaDays && <div className="text-[8px] font-bold bg-amber-100 text-amber-700 px-1 rounded">SLA: {step.slaDays}d</div>}
