                >
                  <Plus size={12} className="text-slate-400" />
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Mini Map Overlay */}
        <div className="absolute bottom-6 right-6 w-48 h-32 bg-white/80 backdrop-blur-md border border-slate-200 rounded-lg shadow-lg pointer-events-none overflow-hidden hidden md:block z-40">
           <div className="p-1.5 border-b border-slate-100 flex items-center justify-between">
              <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Live Mini-Map</span>
              <Layout size={10} className="text-slate-300" />
           </div>
           <div className="relative w-full h-full scale-[0.05] origin-top-left p-10 opacity-40">
              {steps.map(s => (
                <div key={s.id} className="absolute bg-slate-800 w-[180px] h-[80px]" style={{ left: s.position?.x, top: s.position?.y }} />
              ))}
           </div>
        </div>

        {/* Context Sidebar (Properties) */}
        {selectedId && (
          <div className="absolute top-20 right-4 w-72 bg-white rounded-xl shadow-2xl border border-slate-200 p-5 z-40 animate-slide-in">
             <div className="flex items-center justify-between mb-6">
                <h3 className="font-bold text-slate-800 flex items-center gap-2">
                  <Info size={16} className="text-brand-500" /> Configuration
                </h3>
                <button onClick={() => { setSteps(prev => prev.filter(s => s.id !== selectedId)); setSelectedId(null); }} className="p-2 text-red-500 hover:bg-red-50 rounded-lg">
                  <Trash2 size={16} />
                </button>
             </div>

             <div className="space-y-4">
                <div>
                   <label className="text-[10px] font-bold text-slate-400 uppercase block mb-1">Step Description</label>
                   <textarea 
                     className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-xs min-h-[60px] focus:ring-1 focus:ring-brand-500 focus:outline-none"
                     value={steps.find(s => s.id === selectedId)?.description || ''}
                     onChange={e => setSteps(prev => prev.map(s => s.id === selectedId ? {...s, description: e.target.value} : s))}
                     placeholder="Enter operational instructions..."
                   />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-[10px] font-bold text-slate-400 uppercase block mb-1">Role/Actor</label>
                    <input 
                      className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-xs"
                      value={steps.find(s => s.id === selectedId)?.role || ''}
                      onChange={e => setSteps(prev => prev.map(s => s.id === selectedId ? {...s, role: e.target.value} : s))}
                    />
                  </div>
                  <div>
                    <label className="text-[10px] font-bold text-slate-400 uppercase block mb-1">SLA (Days)</label>
                    <input 
                      type="number"
                      className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-xs"
                      value={steps.find(s => s.id === selectedId)?.slaDays || 0}
                      onChange={e => setSteps(prev => prev.map(s => s.id === selectedId ? {...s, slaDays: parseInt(e.target.value)} : s))}
                    />
                  </div>
                </div>

                <div className="pt-4 border-t border-slate-100 flex gap-2">
                   <button onClick={() => setSelectedId(null)} className="flex-1 py-2 bg-slate-100 text-slate-600 rounded-lg font-bold text-xs uppercase hover:bg-slate-200">Close</button>
                   <button onClick={() => { /* Simulation logic */ alert("Running dry-run simulation for step: " + selectedId); }} className="flex-1 py-2 bg-brand-50 text-brand-700 rounded-lg font-bold text-xs uppercase hover:bg-brand-100 border border-brand-100">Simulate</button>
                </div>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { ProcessStep } from '../types';

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API_KEY is missing. AI features will not work.");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

// Generate complex business workflow logic using Gemini 3 Pro
export const generateProcessWorkflow = async (prompt: string): Promise<ProcessStep[]> => {
  const ai = getClient();
  if (!ai) throw new Error("API Key not configured");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Create a business process workflow for the following request: "${prompt}". 
      Break it down into logical steps including Start, User Tasks (approvals, inputs), Service Tasks (automated actions), Decisions, and End.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              name: { type: Type.STRING },
              type: { type: Type.STRING, enum: ['start', 'user-task', 'service-task', 'decision', 'end', 'parallel-gateway'] },
              description: { type: Type.STRING },
              role: { type: Type.STRING, description: "The role responsible, e.g., Manager, System, HR" }
            },
            required: ["id", "name", "type", "description"]
          }
        }
      }
    });

    // Access .text property directly as per latest guidelines
    if (response.text) {
      return JSON.parse(response.text) as ProcessStep[];
    }
    return [];
  } catch (error: any) {
    if (error.message?.includes("403") || error.message?.includes("PERMISSION_DENIED")) {
       console.warn("Gemini API Permission Denied. Check API Key or Billing.");
       // Fallback mock response for demo purposes so app doesn't break
       return [
         { id: 'start', name: 'Start', type: 'start', description: 'Process Started' },
         { id: 'task1', name: 'Manual Step', type: 'user-task', description: 'Created due to AI error' },
         { id: 'end', name: 'End', type: 'end', description: 'Process Ended' }
       ];
    }
    console.error("Failed to generate workflow:", error);
    throw error;
  }
};

// Analyze process efficiency using Gemini 3 Flash for high-speed insights
export const analyzeProcessEfficiency = async (tasks: any[]): Promise<string> => {
  const ai = getClient();
  if (!ai) return "AI insights unavailable (Missing API Key).";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze the following task data summary and provide executive insights on bottlenecks and efficiency improvements. Keep it professional and concise (max 3 sentences). Data: ${JSON.stringify(tasks.slice(0, 10))}`
    });
    // Access .text property directly
    return response.text || "No insights available.";
  } catch (error: any) {
    console.error("Analysis failed:", error);
    if (error.status === 403 || error.message?.includes("PERMISSION_DENIED")) {
      return "AI Access Restricted: Permission Denied. Please verify API Key.";
    }
    return "AI Analysis currently unavailable.";
  }
};

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

// Explicitly extending Component with typed Props and State to ensure TypeScript correctly resolves the 'props' member
export class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = {
      hasError: false,
      error: null
    };
  }

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  private handleReload = () => {
    window.location.reload();
  };

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4">
          <div className="bg-white p-8 rounded-xl shadow-lg border border-slate-200 max-w-md w-full text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-4">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-800 mb-2">Something went wrong</h1>
            <p className="text-slate-500 mb-6 text-sm">
              The application encountered an unexpected error. Our engineering team has been notified.
            </p>
            <div className="bg-slate-50 p-3 rounded-lg text-xs font-mono text-left mb-6 overflow-auto max-h-32 border border-slate-200 text-slate-600">
               {this.state.error?.message || 'Unknown Error'}
            </div>
            <button
              onClick={this.handleReload}
              className="w-full py-2.5 bg-brand-600 text-white rounded-lg font-medium hover:bg-brand-700 transition-colors flex items-center justify-center gap-2"
            >
              <RefreshCw size={16} /> Reload Application
            </button>
          </div>
        </div>
      );
    }

    return this.props.children || null;
  }
}

import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback } from 'react';
import { ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, TaskHistory, ProcessStep, ViewState } from '../types';
import { dbService } from '../services/dbService';

interface NavigationState {
  view: ViewState;
  selectedId?: string;
  filter?: string;
}

interface BPMContextType {
  processes: ProcessDefinition[];
  instances: ProcessInstance[];
  tasks: Task[];
  loading: boolean;
  error: string | null;

  // Navigation & Deep Linking
  nav: NavigationState;
  navigateTo: (view: ViewState, id?: string, filter?: string) => void;

  // Global Viewer State
  viewingInstanceId: string | null;
  openInstanceViewer: (instanceId: string) => void;
  closeInstanceViewer: () => void;

  deployProcess: (process: Omit<ProcessDefinition, 'id' | 'createdAt'>) => Promise<void>;
  startProcess: (definitionId: string, inputData: any) => Promise<string>;
  completeTask: (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => Promise<void>;

  adminOverrideStep: (instanceId: string, targetStepId: string) => Promise<void>;
  updateInstanceVariables: (instanceId: string, variables: Record<string, any>) => Promise<void>;
  toggleInstanceSuspension: (instanceId: string) => Promise<void>;
  addInstanceComment: (instanceId: string, comment: string) => Promise<void>;

  resetSystem: () => Promise<void>;
  reseedSystem: () => Promise<void>;
  exportData: () => Promise<void>;
  importData: (file: File) => Promise<void>;
  refreshData: () => Promise<void>;
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [processes, setProcesses] = useState<ProcessDefinition[]>([]);
  const [instances, setInstances] = useState<ProcessInstance[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [nav, setNav] = useState<NavigationState>({ view: 'dashboard' });
  const [viewingInstanceId, setViewingInstanceId] = useState<string | null>(null);

  const navigateTo = (view: ViewState, id?: string, filter?: string) => {
    setNav({ view, selectedId: id, filter });
  };

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const existingProcs = await dbService.getAll<ProcessDefinition>('processes');
      if (existingProcs.length === 0) await dbService.reseed();

      const p = await dbService.getAll<ProcessDefinition>('processes');
      const i = await dbService.getAll<ProcessInstance>('instances');
      const t = await dbService.getAll<Task>('tasks');

      setProcesses(p);
      setInstances(i);
      setTasks(t);
    } catch (e: any) {
      setError(e.message || "DB Error");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const deployProcess = async (processData: Omit<ProcessDefinition, 'id' | 'createdAt'>) => {
    const newProcess: ProcessDefinition = {
      ...processData,
      id: `proc-${Date.now()}`,
      createdAt: new Date().toISOString(),
      version: 1
    };
    await dbService.add('processes', newProcess);
    setProcesses(prev => [...prev, newProcess]);
    navigateTo('processes');
  };

  const startProcess = async (definitionId: string, inputData: any) => {
    const definition = processes.find(p => p.id === definitionId);
    if (!definition) throw new Error('Definition not found');

    const instanceId = `inst-${Date.now()}`;
    const startStep = definition.steps.find(s => s.type === 'start') || definition.steps[0];

    const newInstance: ProcessInstance = {
      id: instanceId,
      definitionId,
      definitionName: definition.name,
      status: 'Active',
      activeStepIds: [startStep.id],
      startDate: new Date().toISOString(),
      variables: inputData || {},
      priority: TaskPriority.MEDIUM,
      comments: [],
      history: [{
        id: `hist-${Date.now()}`,
        stepName: 'Start',
        action: 'Started',
        performer: 'User',
        timestamp: new Date().toISOString(),
        comments: inputData.summary
      }]
    };

    await dbService.add('instances', newInstance);
    setInstances(prev => [newInstance, ...prev]);
    await advanceWorkflow(newInstance, definition, startStep.id);
    return instanceId;
  };

  const completeTask = async (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;

    const updatedTask = { ...task, status: TaskStatus.COMPLETED };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));

    const instance = instances.find(i => i.id === task.processInstanceId);
    if (instance) {
      const definition = processes.find(p => p.id === instance.definitionId);
      if (definition) {
        const historyEntry: TaskHistory = {
          id: `hist-${Date.now()}`,
          stepName: task.title,
          action: action,
          performer: 'CurrentUser',
          timestamp: new Date().toISOString(),
          comments
        };

        let updatedInstance = {
          ...instance,
          history: [...instance.history, historyEntry]
        };

        if (action === 'reject') {
           updatedInstance.status = 'Terminated';
           updatedInstance.endDate = new Date().toISOString();
           updatedInstance.activeStepIds = [];
           await dbService.add('instances', updatedInstance);
           setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));
           return;
        }

        await dbService.add('instances', updatedInstance);
        setInstances(prev => prev.map(i => i.id === instance.id ? updatedInstance : i));
        await advanceWorkflow(updatedInstance, definition, task.stepId);
      }
    }
  };

  const advanceWorkflow = async (instance: ProcessInstance, definition: ProcessDefinition, completedStepId: string) => {
    const currentStep = definition.steps.find(s => s.id === completedStepId);
    if (!currentStep) return;

    let nextStepIds: string[] = [];
    if (currentStep.nextStepIds && currentStep.nextStepIds.length > 0) {
      nextStepIds = currentStep.nextStepIds;
    } else {
      const currentIndex = definition.steps.findIndex(s => s.id === completedStepId);
      if (currentIndex !== -1 && currentIndex < definition.steps.length - 1) {
        nextStepIds = [definition.steps[currentIndex + 1].id];
      }
    }

    const newActiveStepIds = instance.activeStepIds.filter(id => id !== completedStepId).concat(nextStepIds);
    let workingInstance = { ...instance, activeStepIds: newActiveStepIds };

    if (newActiveStepIds.length === 0 || nextStepIds.some(id => definition.steps.find(s => s.id === id)?.type === 'end')) {
       workingInstance.status = 'Completed';
       workingInstance.endDate = new Date().toISOString();
       workingInstance.activeStepIds = [];
       await dbService.add('instances', workingInstance);
       setInstances(prev => prev.map(i => i.id === instance.id ? workingInstance : i));
       return; 
    }

    await dbService.add('instances', workingInstance);
    setInstances(prev => prev.map(i => i.id === instance.id ? workingInstance : i));

    for (const nextId of nextStepIds) {
      const nextStep = definition.steps.find(s => s.id === nextId);
      if (nextStep) await executeStepLogic(workingInstance, definition, nextStep);
    }
  };

  const executeStepLogic = async (instance: ProcessInstance, definition: ProcessDefinition, step: ProcessStep) => {
     if (step.type === 'parallel-gateway') {
         await advanceWorkflow(instance, definition, step.id);
     } else if (step.type === 'user-task') {
        const newTask: Task = {
          id: `T-${Date.now()}-${Math.floor(Math.random() * 1000)}`,
          title: step.name,
          processName: definition.name,
          processInstanceId: instance.id,
          assignee: step.role || 'Unassigned',
          dueDate: new Date(Date.now() + 86400000 * 3).toISOString().split('T')[0],
          status: TaskStatus.PENDING,
          priority: instance.priority || TaskPriority.MEDIUM,
          description: step.description,
          stepId: step.id
        };
        await dbService.add('tasks', newTask);
        setTasks(prev => [newTask, ...prev]);
     } else if (step.type === 'service-task') {
         setTimeout(async () => {
             const fresh = await dbService.getAll<ProcessInstance>('instances');
             const freshInstance = fresh.find(i => i.id === instance.id) || instance;
             const instanceWithHistory = {
                 ...freshInstance,
                 history: [...freshInstance.history, { id: `hist-${Date.now()}`, stepName: step.name, action: 'Auto-Complete', performer: 'System', timestamp: new Date().toISOString() }]
             };
             await dbService.add('instances', instanceWithHistory);
             await advanceWorkflow(instanceWithHistory, definition, step.id);
         }, 1500);
     }
  };

  const adminOverrideStep = async (instanceId: string, targetStepId: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;
    const definition = processes.find(p => p.id === instance.definitionId);
    if (!definition) return;

    const updatedInstance: ProcessInstance = {
      ...instance,
      activeStepIds: [targetStepId],
      history: [...instance.history, {
        id: `hist-${Date.now()}`,
        stepName: 'Admin Override',
        action: 'Jumped',
        performer: 'Administrator',
        timestamp: new Date().toISOString()
      }]
    };

    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));
    const targetStep = definition.steps.find(s => s.id === targetStepId);
    if (targetStep) await executeStepLogic(updatedInstance, definition, targetStep);
  };

  const updateInstanceVariables = async (instanceId: string, variables: Record<string, any>) => {
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;
    const updatedInstance = { ...instance, variables };
    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));
  };

  const toggleInstanceSuspension = async (instanceId: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;
    const newStatus = instance.status === 'Suspended' ? 'Active' : 'Suspended';
    const updatedInstance = { ...instance, status: newStatus as any };
    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));
  };

  const addInstanceComment = async (instanceId: string, comment: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;
    const updatedInstance = { ...instance, comments: [...(instance.comments || []), { user: 'Admin', text: comment, timestamp: new Date().toISOString() }] };
    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));
  };

  const resetSystem = async () => { await dbService.resetDB(); await loadData(); };
  const reseedSystem = async () => { await dbService.reseed(); await loadData(); };
  const exportData = async () => {
    const json = await dbService.exportData();
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `nexflow_backup.json`;
    a.click();
  };
  const importData = async (file: File) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      await dbService.importData(e.target?.result as string);
      await loadData();
    };
    reader.readAsText(file);
  };

  return (
    <BPMContext.Provider value={{ 
      processes, instances, tasks, loading, error,
      nav, navigateTo,
      viewingInstanceId, openInstanceViewer: setViewingInstanceId, closeInstanceViewer: () => setViewingInstanceId(null),
      deployProcess, startProcess, completeTask,
      adminOverrideStep, updateInstanceVariables, toggleInstanceSuspension, addInstanceComment,
      resetSystem, reseedSystem, exportData, importData, refreshData: loadData
    }}>
      {children}
    </BPMContext.Provider>
  );
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { ProcessStep, ProcessLink } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { 
  Wand2, Save, Play, Settings, User, Cog, GitBranch, Flag, 
  Plus, Trash2, Split, Maximize, MousePointer2, Info, 
  AlertCircle, Zap, Layout, StickyNote, ChevronUp, ChevronDown, Menu
} from 'lucide-react';

const GRID_SIZE = 20;
const MAGNET_RADIUS = 50;

export const ProcessDesigner: React.FC = () => {
  const { deployProcess, nav } = useBPM();
  const [processName, setProcessName] = useState('New Enterprise Flow');

  // Mobile UI States
  const [isPaletteOpen, setIsPaletteOpen] = useState(window.innerWidth > 768);
  const [isPropertiesOpen, setIsPropertiesOpen] = useState(false);

  // Editor State
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [links, setLinks] = useState<ProcessLink[]>([]);
  const [viewport, setViewport] = useState({ x: 0, y: 0, zoom: 1 });
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // Interaction Refs
  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'link'>('viewport');
  const activeId = useRef<string | null>(null);
  const ghostLink = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  const screenToWorld = (sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return {
      x: (sx - rect.left - viewport.x) / viewport.zoom,
      y: (sy - rect.top - viewport.y) / viewport.zoom
    };
  };

  const addNode = (type: ProcessStep['type']) => {
    const world = screenToWorld(window.innerWidth / 2, window.innerHeight / 2);
    const newNode: ProcessStep = {
      id: `node-${Date.now()}`,
      name: `New ${type}`,
      type,
      description: '',
      position: { x: Math.round(world.x/GRID_SIZE)*GRID_SIZE, y: Math.round(world.y/GRID_SIZE)*GRID_SIZE },
      nextStepIds: []
    };
    setSteps(prev => [...prev, newNode]);
    setSelectedId(newNode.id);
    if (window.innerWidth <= 768) setIsPaletteOpen(false);
    if (navigator.vibrate) navigator.vibrate(10);
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const handleEl = target.closest('[data-handle-id]');

    dragStart.current = { x: e.clientX, y: e.clientY };
    isDragging.current = true;

    if (handleEl) {
      dragTarget.current = 'link';
      activeId.current = handleEl.getAttribute('data-handle-id');
    } else if (nodeEl) {
      dragTarget.current = 'node';
      activeId.current = nodeEl.getAttribute('data-node-id');
      setSelectedId(activeId.current);
      setIsPropertiesOpen(true);
    } else {
      dragTarget.current = 'viewport';
      setSelectedId(null);
      setIsPropertiesOpen(false);
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    const dx = (e.clientX - dragStart.current.x) / viewport.zoom;
    const dy = (e.clientY - dragStart.current.y) / viewport.zoom;

    if (dragTarget.current === 'viewport') {
      setViewport(prev => ({ ...prev, x: prev.x + (e.clientX - dragStart.current.x), y: prev.y + (e.clientY - dragStart.current.y) }));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } else if (dragTarget.current === 'node' && activeId.current) {
      setSteps(prev => prev.map(s => s.id === activeId.current ? { 
        ...s, 
        position: { x: (s.position?.x || 0) + dx, y: (s.position?.y || 0) + dy } 
      } : s));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } else if (dragTarget.current === 'link' && activeId.current) {
      const sNode = steps.find(s => s.id === activeId.current);
      if (sNode) {
        const world = screenToWorld(e.clientX, e.clientY);
        ghostLink.current = { x1: (sNode.position?.x||0)+180, y1: (sNode.position?.y||0)+40, x2: world.x, y2: world.y };
        setViewport(v => ({...v}));
      }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragTarget.current === 'link' && activeId.current) {
      const targetEl = document.elementFromPoint(e.clientX, e.clientY)?.closest('[data-node-id]');
      const tId = targetEl?.getAttribute('data-node-id');
      if (tId && tId !== activeId.current) {
        setLinks(prev => [...prev, { id: `link-${Date.now()}`, sourceId: activeId.current!, targetId: tId }]);
        if (navigator.vibrate) navigator.vibrate(20);
      }
    }

    if (dragTarget.current === 'node' && activeId.current) {
       setSteps(prev => prev.map(s => s.id === activeId.current ? {
         ...s,
         position: { x: Math.round((s.position?.x||0)/GRID_SIZE)*GRID_SIZE, y: Math.round((s.position?.y||0)/GRID_SIZE)*GRID_SIZE }
       } : s));
    }

    isDragging.current = false;
    ghostLink.current = null;
    setViewport(v => ({...v}));
  };

  const validation = useMemo(() => {
    const errs = [];
    if (!steps.find(s => s.type === 'start')) errs.push("Start node missing");
    if (!steps.find(s => s.type === 'end')) errs.push("End node missing");
    return errs;
  }, [steps]);

  const selectedStep = steps.find(s => s.id === selectedId);

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col md:flex-row bg-white rounded-xl border border-slate-200 overflow-hidden relative shadow-inner">
      {/* Mobile Header / Toggle */}
      <div className="md:hidden bg-slate-50 border-b p-3 flex justify-between items-center z-40">
         <button onClick={() => setIsPaletteOpen(!isPaletteOpen)} className="p-2 bg-white border rounded-lg shadow-sm text-slate-600">
           <Menu size={18} />
         </button>
         <h3 className="text-xs font-bold text-slate-500 uppercase tracking-tighter">NexFlow Designer</h3>
         <button onClick={() => deployProcess({ name: processName, steps, deployedBy: 'Admin', links })} className="bg-brand-600 text-white p-2 rounded-lg shadow-sm">
           <Save size={18} />
         </button>
      </div>

      {/* Palette (Responsive Sidebar/Drawer) */}
      <aside className={`absolute inset-y-0 left-0 w-64 bg-slate-50/95 backdrop-blur-md border-r border-slate-200 z-30 transition-transform duration-300 transform md:relative md:translate-x-0 ${isPaletteOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-4 border-b border-slate-200 font-bold text-xs text-slate-400 uppercase tracking-widest flex items-center justify-between">
          <span>Components</span>
          <button onClick={() => setIsPaletteOpen(false)} className="md:hidden text-slate-400"><ChevronDown className="rotate-90" size={16}/></button>
        </div>
        <div className="p-4 space-y-6 overflow-y-auto h-full pb-20">
           <div className="grid grid-cols-2 gap-2">
             <button onClick={() => addNode('start')} className="p-3 bg-white border rounded-lg hover:border-brand-500 flex flex-col items-center gap-1 group"><Play size={18} className="text-green-500" /><span className="text-[10px]">Start</span></button>
             <button onClick={() => addNode('end')} className="p-3 bg-white border rounded-lg hover:border-brand-500 flex flex-col items-center gap-1 group"><Flag size={18} className="text-slate-800" /><span className="text-[10px]">End</span></button>
             <button onClick={() => addNode('user-task')} className="p-3 bg-white border rounded-lg hover:border-brand-500 flex flex-col items-center gap-1 group"><User size={18} className="text-blue-500" /><span className="text-[10px]">User</span></button>
             <button onClick={() => addNode('service-task')} className="p-3 bg-white border rounded-lg hover:border-brand-500 flex flex-col items-center gap-1 group"><Cog size={18} className="text-purple-500" /><span className="text-[10px]">Auto</span></button>
             <button onClick={() => addNode('decision')} className="p-3 bg-white border rounded-lg hover:border-brand-500 flex flex-col items-center gap-1 group"><GitBranch size={18} className="text-amber-500" /><span className="text-[10px]">Logic</span></button>
             <button onClick={() => addNode('parallel-gateway')} className="p-3 bg-white border rounded-lg hover:border-brand-500 flex flex-col items-center gap-1 group"><Split size={18} className="text-orange-500" /><span className="text-[10px]">Fork</span></button>
           </div>

           <div className="p-3 bg-amber-50 border border-amber-100 rounded-lg">
              <h4 className="text-[10px] font-bold text-amber-700 uppercase mb-2">Designer Health</h4>
              {validation.length === 0 ? <div className="text-[10px] text-green-600 font-bold flex items-center gap-1"><Zap size={10}/> BPMN VALID</div> : <div className="text-[10px] text-red-500 font-medium">{validation[0]}</div>}
           </div>
        </div>
      </aside>

      {/* Canvas */}
      <div className="flex-1 relative overflow-hidden bg-slate-50 touch-none select-none">
        <div className="absolute top-4 left-4 z-20 hidden md:flex gap-2">
           <button onClick={() => setViewport({x:0, y:0, zoom:1})} className="p-2 bg-white border rounded-lg shadow-sm text-slate-500 hover:text-brand-600 transition-colors"><Maximize size={18}/></button>
           <button onClick={() => setViewport(v => ({...v, zoom: v.zoom+0.1}))} className="p-2 bg-white border rounded-lg shadow-sm text-slate-500">+</button>
           <button onClick={() => setViewport(v => ({...v, zoom: v.zoom-0.1}))} className="p-2 bg-white border rounded-lg shadow-sm text-slate-500">-</button>
        </div>

        <div 
          ref={canvasRef}
          className="absolute inset-0 cursor-crosshair"
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
          onPointerUp={handlePointerUp}
          style={{
            backgroundImage: 'radial-gradient(#cbd5e1 1px, transparent 1px)',
            backgroundSize: `${20*viewport.zoom}px ${20*viewport.zoom}px`,
            backgroundPosition: `${viewport.x}px ${viewport.y}px`
          }}
        >
          <div style={{ transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`, transformOrigin: '0 0' }}>
            <svg className="overflow-visible absolute top-0 left-0 pointer-events-none">
              <defs><marker id="arrow" viewBox="0 0 10 10" refX="10" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse"><path d="M 0 0 L 10 5 L 0 10 z" fill="#94a3b8"/></marker></defs>
              {links.map(l => {
                const s = steps.find(n => n.id === l.sourceId);
                const t = steps.find(n => n.id === l.targetId);
                if (!s || !t) return null;
                const x1=(s.position?.x||0)+180; const y1=(s.position?.y||0)+40;
                const x2=(t.position?.x||0); const y2=(t.position?.y||0)+40;
                return <path key={l.id} d={`M ${x1} ${y1} C ${x1+50} ${y1}, ${x2-50} ${y2}, ${x2} ${y2}`} stroke="#94a3b8" strokeWidth="2" fill="none" markerEnd="url(#arrow)"/>
              })}
              {ghostLink.current && <line x1={ghostLink.current.x1} y1={ghostLink.current.y1} x2={ghostLink.current.x2} y2={ghostLink.current.y2} stroke="#0ea5e9" strokeWidth="2" strokeDasharray="4,4"/>}
            </svg>

            {steps.map(step => (
              <div 
                key={step.id} data-node-id={step.id}
                className={`absolute w-[180px] h-[80px] bg-white rounded-xl border-2 shadow-sm p-3 flex flex-col transition-all ${selectedId === step.id ? 'border-brand-500 shadow-lg scale-105 z-10' : 'border-slate-200'}`}
                style={{ left: step.position?.x, top: step.position?.y }}
              >
                <div className="flex items-center justify-between opacity-50 mb-1">
                  <span className="text-[8px] font-black uppercase tracking-widest">{step.type}</span>
                  <div data-handle-id={step.id} className="w-5 h-5 bg-slate-100 border rounded-full flex items-center justify-center cursor-crosshair hover:bg-brand-50 hover:text-brand-500 transition-colors"><Plus size={10}/></div>
                </div>
                <div className="text-xs font-bold text-slate-800 truncate">{step.name}</div>
                <div className="mt-auto text-[8px] text-slate-400 font-mono uppercase">{step.id.slice(-6)}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Properties Drawer (Bottom Sheet on Mobile, Right Panel on Desktop) */}
      <aside className={`fixed inset-x-0 bottom-0 bg-white shadow-2xl border-t border-slate-200 z-50 transition-transform duration-500 md:relative md:inset-y-0 md:border-t-0 md:border-l md:w-80 md:translate-y-0 ${selectedId && isPropertiesOpen ? 'translate-y-0' : 'translate-y-full'}`}>
         <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
            <h3 className="font-bold text-slate-800 flex items-center gap-2"><Info size={16} className="text-brand-600"/> Configuration</h3>
            <div className="flex gap-2">
               <button onClick={() => { setSteps(steps.filter(s => s.id !== selectedId)); setSelectedId(null); }} className="p-2 text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={16}/></button>
               <button onClick={() => setIsPropertiesOpen(false)} className="p-2 text-slate-400 hover:bg-slate-100 rounded-lg"><ChevronDown size={18}/></button>
            </div>
         </div>
         {selectedStep && (
           <div className="p-5 space-y-4 pb-12 md:pb-5 overflow-y-auto max-h-[50vh] md:max-h-full">
              <div>
                <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Step Name</label>
                <input className="w-full p-2.5 bg-slate-50 border rounded-lg text-sm font-medium" value={selectedStep.name} onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, name: e.target.value} : s))}/>
              </div>
              <div>
                <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">Operational Role</label>
                <input className="w-full p-2.5 bg-slate-50 border rounded-lg text-sm" value={selectedStep.role || ''} onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, role: e.target.value} : s))}/>
              </div>
              <div>
                <label className="text-[10px] font-bold text-slate-400 uppercase mb-1 block">SLA (Days)</label>
                <input type="number" className="w-full p-2.5 bg-slate-50 border rounded-lg text-sm" value={selectedStep.slaDays || 0} onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, slaDays: parseInt(e.target.value)} : s))}/>
              </div>
           </div>
         )}
      </aside>

      {/* Deploy Button Floating (Desktop Only) */}
      <div className="hidden md:flex absolute top-4 right-4 z-40">
         <button onClick={() => deployProcess({ name: processName, steps, deployedBy: 'Admin', links })} className="bg-brand-600 text-white px-6 py-2.5 rounded-xl font-bold text-sm shadow-xl hover:bg-brand-700 flex items-center gap-2 transition-all active:scale-95">
           <Save size={20} /> Deploy Definition
         </button>
      </div>
    </div>
  );
};

