import React, { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

/**
 * ErrorBoundary class component to catch and handle runtime errors gracefully.
 * Fixed: Explicitly using React.Component with typed Props and State to resolve 'state' and 'props' member existence.
 */
export class ErrorBoundary extends React.Component<Props, State> {
  // Fixed: Initialize state as a public class field to ensure the type system recognizes it.
  public state: State = {
    hasError: false,
    error: null
  };

  constructor(props: Props) {
    super(props);
  }

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  private handleReload = () => {
    window.location.reload();
  };

  public render() {
    // Fixed: Accessed 'state' properties are now correctly resolved from the base React.Component.
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4">
          <div className="bg-white p-8 rounded-xl shadow-lg border border-slate-200 max-w-md w-full text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-4">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-800 mb-2">Something went wrong</h1>
            <p className="text-slate-500 mb-6 text-sm">
              The application encountered an unexpected error. Our engineering team has been notified.
            </p>
            <div className="bg-slate-50 p-3 rounded-lg text-xs font-mono text-left mb-6 overflow-auto max-h-32 border border-slate-200 text-slate-600">
               {this.state.error?.message || 'Unknown Error'}
            </div>
            <button
              onClick={this.handleReload}
              className="w-full py-2.5 bg-brand-600 text-white rounded-lg font-medium hover:bg-brand-700 transition-colors flex items-center justify-center gap-2"
            >
              <RefreshCw size={16} /> Reload Application
            </button>
          </div>
        </div>
      );
    }

    // Fixed: Accessed 'props' properties are now correctly resolved from the base React.Component.
    return this.props.children || null;
  }
}

export enum TaskStatus {
  PENDING = 'Pending',
  IN_PROGRESS = 'In Progress',
  COMPLETED = 'Completed',
  REJECTED = 'Rejected'
}

export enum TaskPriority {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export interface Task {
  id: string;
  title: string;
  processName: string;
  processInstanceId: string;
  assignee: string;
  dueDate: string;
  status: TaskStatus;
  priority: TaskPriority;
  description?: string;
  stepId: string;
  data?: any;
}

export interface ProcessStep {
  id: string;
  name: string;
  type: 'start' | 'user-task' | 'service-task' | 'decision' | 'parallel-gateway' | 'end' | 'note' | 'sub-process' | 'boundary-event';
  description: string;
  role?: string;
  laneId?: string; // Enterprise Swimlane support
  slaDays?: number;
  nextStepIds?: string[];
  position?: { x: number; y: number };
  isCollapsed?: boolean; // For sub-processes
  boundaryType?: 'timer' | 'error' | 'message';
}

export interface ProcessLink {
  id: string;
  sourceId: string;
  targetId: string;
  label?: string;
  condition?: string;
}

export interface Swimlane {
  id: string;
  name: string;
  height: number;
}

export interface ProcessDefinition {
  id: string;
  name: string;
  description: string;
  steps: ProcessStep[];
  links?: ProcessLink[];
  lanes?: Swimlane[]; // Enterprise pools/lanes
  createdAt: string;
  deployedBy: string;
  version?: number;
  history?: { timestamp: string; author: string; message: string }[];
}

export interface TaskHistory {
  id: string;
  stepName: string;
  action: string;
  performer: string;
  timestamp: string;
  comments?: string;
}

export interface ProcessInstance {
  id: string;
  definitionId: string;
  definitionName: string;
  status: 'Active' | 'Completed' | 'Terminated' | 'Suspended';
  activeStepIds: string[];
  startDate: string;
  endDate?: string;
  dueDate?: string;
  variables: Record<string, any>;
  priority: TaskPriority;
  history: TaskHistory[];
  comments: { user: string; text: string; timestamp: string }[];
}

export type ViewState = 'dashboard' | 'inbox' | 'explorer' | 'processes' | 'designer' | 'analytics' | 'settings' | 'instance-viewer';

import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback } from 'react';
import { ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, TaskHistory, ProcessStep, ViewState } from '../types';
import { dbService } from '../services/dbService';

interface NavigationState {
  view: ViewState;
  selectedId?: string;
  filter?: string;
  mode?: 'view' | 'edit';
}

interface BPMContextType {
  processes: ProcessDefinition[];
  instances: ProcessInstance[];
  tasks: Task[];
  loading: boolean;
  error: string | null;

  nav: NavigationState;
  navigateTo: (view: ViewState, id?: string, filter?: string, mode?: 'view' | 'edit') => void;

  viewingInstanceId: string | null;
  openInstanceViewer: (instanceId: string) => void;
  closeInstanceViewer: () => void;

  deployProcess: (process: Omit<ProcessDefinition, 'id' | 'createdAt'>) => Promise<void>;
  startProcess: (definitionId: string, inputData: any) => Promise<string>;
  completeTask: (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => Promise<void>;

  adminOverrideStep: (instanceId: string, targetStepId: string) => Promise<void>;
  updateInstanceVariables: (instanceId: string, variables: Record<string, any>) => Promise<void>;
  toggleInstanceSuspension: (instanceId: string) => Promise<void>;
  addInstanceComment: (instanceId: string, comment: string) => Promise<void>;

  resetSystem: () => Promise<void>;
  reseedSystem: () => Promise<void>;
  exportData: () => Promise<void>;
  importData: (file: File) => Promise<void>;
  refreshData: () => Promise<void>;
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [processes, setProcesses] = useState<ProcessDefinition[]>([]);
  const [instances, setInstances] = useState<ProcessInstance[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [nav, setNav] = useState<NavigationState>({ view: 'dashboard' });
  const [viewingInstanceId, setViewingInstanceId] = useState<string | null>(null);

  const navigateTo = (view: ViewState, id?: string, filter?: string, mode?: 'view' | 'edit') => {
    setNav({ view, selectedId: id, filter, mode });
  };

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const p = await dbService.getAll<ProcessDefinition>('processes');
      const i = await dbService.getAll<ProcessInstance>('instances');
      const t = await dbService.getAll<Task>('tasks');
      setProcesses(p);
      setInstances(i);
      setTasks(t);
    } catch (e: any) {
      setError(e.message || "DB Error");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const deployProcess = async (processData: Omit<ProcessDefinition, 'id' | 'createdAt'>) => {
    const newProcess: ProcessDefinition = {
      ...processData,
      id: `proc-${Date.now()}`,
      createdAt: new Date().toISOString(),
      version: 1
    };
    await dbService.add('processes', newProcess);
    setProcesses(prev => [...prev, newProcess]);
    navigateTo('processes');
  };

  const startProcess = async (definitionId: string, inputData: any) => {
    const definition = processes.find(p => p.id === definitionId);
    if (!definition) throw new Error('Definition not found');

    const instanceId = `inst-${Date.now()}`;
    const startStep = definition.steps.find(s => s.type === 'start') || definition.steps[0];

    const newInstance: ProcessInstance = {
      id: instanceId,
      definitionId,
      definitionName: definition.name,
      status: 'Active',
      activeStepIds: [startStep.id],
      startDate: new Date().toISOString(),
      variables: inputData || {},
      priority: TaskPriority.MEDIUM,
      comments: [],
      history: [{
        id: `hist-${Date.now()}`,
        stepName: 'Start',
        action: 'Started',
        performer: 'User',
        timestamp: new Date().toISOString(),
        comments: inputData.summary
      }]
    };

    await dbService.add('instances', newInstance);
    setInstances(prev => [newInstance, ...prev]);
    // Logic for auto-advancing would normally live in a backend engine, mocked here.
    return instanceId;
  };

  const completeTask = async (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;
    const updatedTask = { ...task, status: TaskStatus.COMPLETED };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));
    // Trigger workflow progression logic...
  };

  const adminOverrideStep = async (instanceId: string, targetStepId: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;
    const updatedInstance = { ...instance, activeStepIds: [targetStepId] };
    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));
  };

  const updateInstanceVariables = async (instanceId: string, variables: Record<string, any>) => {
    const instance = instances.find(i => i.id === instanceId);
    if (instance) {
      const updated = { ...instance, variables };
      await dbService.add('instances', updated);
      setInstances(prev => prev.map(i => i.id === instanceId ? updated : i));
    }
  };

  const toggleInstanceSuspension = async (instanceId: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (instance) {
      const updated = { ...instance, status: instance.status === 'Suspended' ? 'Active' : 'Suspended' } as any;
      await dbService.add('instances', updated);
      setInstances(prev => prev.map(i => i.id === instanceId ? updated : i));
    }
  };

  const addInstanceComment = async (instanceId: string, comment: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (instance) {
      const updated = { ...instance, comments: [...instance.comments, { user: 'Admin', text: comment, timestamp: new Date().toISOString() }] };
      await dbService.add('instances', updated);
      setInstances(prev => prev.map(i => i.id === instanceId ? updated : i));
    }
  };

  const resetSystem = async () => { await dbService.resetDB(); await loadData(); };
  const reseedSystem = async () => { await dbService.reseed(); await loadData(); };
  const exportData = async () => { /* Logic in dbService */ };
  const importData = async (file: File) => { /* Logic in dbService */ };

  return (
    <BPMContext.Provider value={{ 
      processes, instances, tasks, loading, error,
      nav, navigateTo,
      viewingInstanceId, openInstanceViewer: setViewingInstanceId, closeInstanceViewer: () => setViewingInstanceId(null),
      deployProcess, startProcess, completeTask,
      adminOverrideStep, updateInstanceVariables, toggleInstanceSuspension, addInstanceComment,
      resetSystem, reseedSystem, exportData, importData, refreshData: loadData
    }}>
      {children}
    </BPMContext.Provider>
  );
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { ProcessStep, ProcessLink, Swimlane } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { 
  Wand2, Save, Play, User, Cog, GitBranch, Flag, Plus, Trash2, 
  Split, Maximize, MousePointer2, Info, AlertCircle, Zap, Layout, 
  StickyNote, ChevronDown, Menu, Search, Box, History, Scissors, 
  Move, Layers, Ruler, CheckCircle, Smartphone, Monitor
} from 'lucide-react';

const GRID_SIZE = 20;
const SNAP_THRESHOLD = 15;

export const ProcessDesigner: React.FC = () => {
  const { deployProcess, nav, navigateTo } = useBPM();
  const [processName, setProcessName] = useState('New Enterprise Workflow');

  // -- UI States --
  const [isPaletteOpen, setIsPaletteOpen] = useState(window.innerWidth > 1024);
  const [isPropertiesOpen, setIsPropertiesOpen] = useState(false);
  const [isValidationOpen, setIsValidationOpen] = useState(false);
  const [showGrid, setShowGrid] = useState(true);
  const [isMobilePreview, setIsMobilePreview] = useState(window.innerWidth < 768);

  // -- Editor Core State --
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [links, setLinks] = useState<ProcessLink[]>([]);
  const [lanes, setLanes] = useState<Swimlane[]>([
    { id: 'lane-1', name: 'Operational Excellence', height: 250 },
    { id: 'lane-2', name: 'Management Approval', height: 250 }
  ]);
  const [viewport, setViewport] = useState({ x: 0, y: 0, zoom: 1 });
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Interaction Refs
  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'link' | 'lane'>('viewport');
  const activeId = useRef<string | null>(null);
  const ghostLink = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  // -- 1. Alignment & Snapping Logic --
  const snapToGrid = (val: number) => Math.round(val / GRID_SIZE) * GRID_SIZE;

  const screenToWorld = (sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return {
      x: (sx - rect.left - viewport.x) / viewport.zoom,
      y: (sy - rect.top - viewport.y) / viewport.zoom
    };
  };

  // -- 2. Feature: Node Library with Sub-processes --
  const addNode = (type: ProcessStep['type'], laneId?: string) => {
    const world = screenToWorld(window.innerWidth / 2, window.innerHeight / 2);
    const newNode: ProcessStep = {
      id: `node-${Date.now()}`,
      name: `New ${type.replace('-', ' ')}`,
      type,
      description: '',
      laneId: laneId || lanes[0].id,
      position: { x: snapToGrid(world.x), y: snapToGrid(world.y) },
      nextStepIds: []
    };
    setSteps(prev => [...prev, newNode]);
    setSelectedId(newNode.id);
    if (window.innerWidth < 768) {
      setIsPaletteOpen(false);
      setIsPropertiesOpen(true);
    }
    if (navigator.vibrate) navigator.vibrate(15);
  };

  // -- 3. Interaction Handlers (Mobile Friendly) --
  const handlePointerDown = (e: React.PointerEvent) => {
    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const handleEl = target.closest('[data-handle-id]');

    dragStart.current = { x: e.clientX, y: e.clientY };
    isDragging.current = true;

    if (handleEl) {
      dragTarget.current = 'link';
      activeId.current = handleEl.getAttribute('data-handle-id');
    } else if (nodeEl) {
      dragTarget.current = 'node';
      activeId.current = nodeEl.getAttribute('data-node-id');
      setSelectedId(activeId.current);
      setIsPropertiesOpen(true);
    } else {
      dragTarget.current = 'viewport';
      if (!isPropertiesOpen) setSelectedId(null);
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    const dx = (e.clientX - dragStart.current.x) / viewport.zoom;
    const dy = (e.clientY - dragStart.current.y) / viewport.zoom;

    if (dragTarget.current === 'viewport') {
      setViewport(prev => ({ ...prev, x: prev.x + (e.clientX - dragStart.current.x), y: prev.y + (e.clientY - dragStart.current.y) }));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } else if (dragTarget.current === 'node' && activeId.current) {
      setSteps(prev => prev.map(s => s.id === activeId.current ? { 
        ...s, 
        position: { x: (s.position?.x || 0) + dx, y: (s.position?.y || 0) + dy } 
      } : s));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } else if (dragTarget.current === 'link' && activeId.current) {
      const sNode = steps.find(s => s.id === activeId.current);
      if (sNode) {
        const world = screenToWorld(e.clientX, e.clientY);
        ghostLink.current = { x1: (sNode.position?.x||0)+180, y1: (sNode.position?.y||0)+40, x2: world.x, y2: world.y };
        setViewport(v => ({...v}));
      }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragTarget.current === 'link' && activeId.current) {
      const targetEl = document.elementFromPoint(e.clientX, e.clientY)?.closest('[data-node-id]');
      const tId = targetEl?.getAttribute('data-node-id');
      if (tId && tId !== activeId.current) {
        setLinks(prev => [...prev, { id: `link-${Date.now()}`, sourceId: activeId.current!, targetId: tId }]);
        if (navigator.vibrate) navigator.vibrate(25);
      }
    }

    if (dragTarget.current === 'node' && activeId.current) {
       setSteps(prev => prev.map(s => s.id === activeId.current ? {
         ...s,
         position: { x: snapToGrid(s.position?.x||0), y: snapToGrid(s.position?.y||0) }
       } : s));
    }

    isDragging.current = false;
    ghostLink.current = null;
    setViewport(v => ({...v}));
  };

  // -- 4. Enterprise Validation Engine --
  const validationErrors = useMemo(() => {
    const errs = [];
    if (!steps.some(s => s.type === 'start')) errs.push("Missing Start Event");
    if (!steps.some(s => s.type === 'end')) errs.push("Missing End Event");

    steps.forEach(s => {
      const hasOut = links.some(l => l.sourceId === s.id);
      const hasIn = links.some(l => l.targetId === s.id);
      if (s.type !== 'end' && !hasOut) errs.push(`Node '${s.name}' has no outgoing path`);
      if (s.type !== 'start' && !hasIn) errs.push(`Node '${s.name}' is unreachable`);
    });

    return errs;
  }, [steps, links]);

  // -- 5. Feature: Auto-Layout Tidy --
  const tidyLayout = () => {
    setSteps(prev => prev.map((s, i) => ({
      ...s,
      position: { x: 100 + (i * 220), y: 120 }
    })));
  };

  const selectedStep = steps.find(s => s.id === selectedId);

  return (
    <div className={`h-[calc(100vh-140px)] flex flex-col md:flex-row bg-slate-100 rounded-2xl border border-slate-200 overflow-hidden relative shadow-2xl transition-all ${isMobilePreview ? 'max-w-[420px] mx-auto ring-8 ring-slate-800' : 'w-full'}`}>

      {/* 1. Competitive Header: Global Search & Shortcuts */}
      <div className="bg-white border-b border-slate-200 p-3 flex justify-between items-center z-50">
        <div className="flex items-center gap-4">
          <button onClick={() => setIsPaletteOpen(!isPaletteOpen)} className="p-2 bg-slate-50 border rounded-lg hover:bg-slate-100"><Menu size={18}/></button>
          <div className="hidden md:flex relative w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14}/>
            <input 
              className="w-full pl-9 pr-4 py-1.5 bg-slate-50 border rounded-full text-xs" 
              placeholder="Search components or nodes..." 
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
            />
          </div>
        </div>

        <div className="flex items-center gap-2">
           <button onClick={tidyLayout} className="p-2 text-slate-500 hover:text-brand-600" title="Auto-Layout"><Layers size={18}/></button>
           <button onClick={() => setShowGrid(!showGrid)} className={`p-2 ${showGrid ? 'text-brand-600' : 'text-slate-400'}`} title="Toggle Grid"><Ruler size={18}/></button>
           <button onClick={() => setIsMobilePreview(!isMobilePreview)} className={`p-2 ${isMobilePreview ? 'text-brand-600' : 'text-slate-400'}`} title="Preview Device Mode"><Smartphone size={18}/></button>
           <div className="h-6 w-px bg-slate-200 mx-2"></div>
           <button onClick={() => deployProcess({ name: processName, steps, deployedBy: 'Admin', links, lanes })} className="bg-brand-600 text-white px-4 py-1.5 rounded-lg font-bold text-xs shadow-lg hover:bg-brand-700 flex items-center gap-2 transition-transform active:scale-95">
             <Save size={16}/> Deploy
           </button>
        </div>
      </div>

      {/* 2. Responsive Side Library */}
      <aside className={`absolute inset-y-0 left-0 w-72 bg-white/95 backdrop-blur-md border-r border-slate-200 z-40 transition-transform duration-300 transform md:relative md:translate-x-0 ${isPaletteOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'}`}>
        <div className="p-4 border-b border-slate-100 flex items-center justify-between">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Enterprise Library</span>
          <button onClick={() => setIsPaletteOpen(false)} className="md:hidden text-slate-400"><X size={16}/></button>
        </div>
        <div className="p-4 space-y-6 overflow-y-auto h-full pb-32 scrollbar-hide">
           <section className="space-y-2">
             <h4 className="text-[9px] font-bold text-slate-400 uppercase">Core Events</h4>
             <div className="grid grid-cols-2 gap-2">
                <button onClick={() => addNode('start')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1 group transition-all"><Play size={20} className="text-green-500 group-hover:scale-110"/><span className="text-[10px] font-bold">Start</span></button>
                <button onClick={() => addNode('end')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1 group transition-all"><Flag size={20} className="text-slate-800 group-hover:scale-110"/><span className="text-[10px] font-bold">End</span></button>
             </div>
           </section>

           <section className="space-y-2">
             <h4 className="text-[9px] font-bold text-slate-400 uppercase">Activities</h4>
             <div className="grid grid-cols-2 gap-2">
                <button onClick={() => addNode('user-task')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1 group transition-all"><User size={20} className="text-blue-500 group-hover:scale-110"/><span className="text-[10px] font-bold">User Task</span></button>
                <button onClick={() => addNode('service-task')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1 group transition-all"><Cog size={20} className="text-purple-500 group-hover:scale-110"/><span className="text-[10px] font-bold">Automated</span></button>
                <button onClick={() => addNode('sub-process')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1 group transition-all"><Box size={20} className="text-indigo-500 group-hover:scale-110"/><span className="text-[10px] font-bold">Sub-Flow</span></button>
                <button onClick={() => addNode('note')} className="p-3 bg-amber-50 border border-amber-200 rounded-xl hover:border-amber-500 flex flex-col items-center gap-1 group transition-all"><StickyNote size={20} className="text-amber-500 group-hover:scale-110"/><span className="text-[10px] font-bold">Annotation</span></button>
             </div>
           </section>

           <section className="space-y-2">
             <h4 className="text-[9px] font-bold text-slate-400 uppercase">Gateways & Logic</h4>
             <div className="grid grid-cols-2 gap-2">
                <button onClick={() => addNode('decision')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1 group transition-all"><GitBranch size={20} className="text-amber-500 group-hover:scale-110"/><span className="text-[10px] font-bold">Gateway</span></button>
                <button onClick={() => addNode('parallel-gateway')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1 group transition-all"><Split size={20} className="text-orange-500 group-hover:scale-110"/><span className="text-[10px] font-bold">Parallel</span></button>
             </div>
           </section>

           <div className="pt-4 border-t border-slate-100">
             <button onClick={() => setIsValidationOpen(!isValidationOpen)} className={`w-full p-3 rounded-xl border flex items-center justify-between transition-all ${validationErrors.length > 0 ? 'bg-red-50 border-red-200 text-red-700' : 'bg-green-50 border-green-200 text-green-700'}`}>
               <div className="flex items-center gap-2 font-bold text-xs"><Zap size={14}/> {validationErrors.length > 0 ? 'VALIDATION' : 'HEALTHY'}</div>
               <span className="text-xs">{validationErrors.length} issues</span>
             </button>
             {isValidationOpen && validationErrors.length > 0 && (
               <div className="mt-3 space-y-2">
                 {validationErrors.map((e, i) => (
                   <div key={i} className="flex gap-2 text-[10px] font-medium text-red-500"><AlertCircle size={12}/> {e}</div>
                 ))}
               </div>
             )}
           </div>
        </div>
      </aside>

      {/* 3. Main Design Canvas (Swimlane Support) */}
      <div className="flex-1 relative overflow-hidden bg-slate-50 touch-none select-none">

        {/* Navigation Toolbar */}
        <div className="absolute top-4 left-4 z-30 hidden md:flex flex-col gap-2">
           <button onClick={() => setViewport({x:0, y:0, zoom:1})} className="p-2 bg-white border rounded-lg shadow-sm text-slate-400 hover:text-brand-600"><Maximize size={18}/></button>
           <button onClick={() => setViewport(v => ({...v, zoom: v.zoom + 0.1}))} className="p-2 bg-white border rounded-lg shadow-sm text-slate-400">+</button>
           <button onClick={() => setViewport(v => ({...v, zoom: v.zoom - 0.1}))} className="p-2 bg-white border rounded-lg shadow-sm text-slate-400">-</button>
        </div>

        <div 
          ref={canvasRef}
          className="absolute inset-0 cursor-crosshair"
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
          onPointerUp={handlePointerUp}
          style={{
            backgroundImage: showGrid ? 'radial-gradient(#cbd5e1 1.5px, transparent 1.5px)' : 'none',
            backgroundSize: `${20 * viewport.zoom}px ${20 * viewport.zoom}px`,
            backgroundPosition: `${viewport.x}px ${viewport.y}px`
