              })}
              {ghostLink.current && <line x1={ghostLink.current.x1} y1={ghostLink.current.y1} x2={ghostLink.current.x2} y2={ghostLink.current.y2} stroke="#0ea5e9" strokeWidth="2" strokeDasharray="4,4"/>}
            </svg>

            {steps.map(step => (
              <div 
                key={step.id} data-node-id={step.id}
                className={`absolute w-[180px] h-[80px] bg-white rounded-xl border-2 shadow-sm p-3 flex flex-col transition-all active:scale-95 active:rotate-1 ${selectedId === step.id ? 'border-brand-500 shadow-2xl scale-105 z-30' : 'border-slate-200'} ${step.type === 'note' ? 'bg-amber-50 border-amber-300 border-dashed italic' : ''}`}
                style={{ left: step.position?.x, top: step.position?.y }}
              >
                <div className="flex items-center justify-between opacity-50 mb-1">
                  <span className="text-[8px] font-black uppercase tracking-widest text-slate-400">{step.type}</span>
                  <div data-handle-id={step.id} className="w-5 h-5 bg-slate-100 border rounded-full flex items-center justify-center cursor-crosshair hover:bg-brand-50 hover:text-brand-500 transition-colors shadow-sm"><Plus size={10}/></div>
