                   {step.role && <div className="text-[7px] bg-slate-100 px-1 rounded text-slate-500 font-bold">{step.role}</div>}
                </div>
                {/* Boundary Event Marker Placeholder */}
                {step.type === 'user-task' && <div className="absolute -bottom-2 right-4 w-5 h-5 bg-amber-400 rounded-full border-2 border-white shadow-sm flex items-center justify-center"><Cog size={10} className="text-white"/></div>}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* 4. Competitive Properties Sheet (Mobile Friendly Drawer) */}
      <aside className={`fixed inset-x-0 bottom-0 bg-white/95 backdrop-blur-xl shadow-[0_-20px_50px_rgba(0,0,0,0.1)] border-t border-slate-200 z-[100] transition-transform duration-500 cubic-bezier(0.16, 1, 0.3, 1) md:relative md:inset-y-0 md:border-t-0 md:border-l md:w-96 md:translate-y-0 ${selectedId && isPropertiesOpen ? 'translate-y-0' : 'translate-y-full'}`}>
         <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
            <h3 className="font-bold text-slate-800 flex items-center gap-2"><Info size={16} className="text-brand-600"/> Modeler Properties</h3>
            <div className="flex gap-2">
               <button onClick={() => { setSteps(prev => prev.filter(s => s.id !== selectedId)); setSelectedId(null); }} className="p-2 text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={16}/></button>
               <button onClick={() => setIsPropertiesOpen(false)} className="p-2 text-slate-400 hover:bg-slate-100 rounded-lg"><ChevronDown size={18}/></button>
            </div>
         </div>
         {selectedStep && (
           <div className="p-6 space-y-6 pb-20 md:pb-6 overflow-y-auto max-h-[70vh] md:max-h-full scrollbar-hide">
