                  value={selectedStep.name} 
                  onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, name: e.target.value} : s))}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">Actor Role</label>
