                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm" 
                    placeholder="e.g. Accountant"
                    value={selectedStep.role || ''} 
                    onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, role: e.target.value} : s))}
                  />
