                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">SLA Threshold</label>
                  <div className="flex items-center gap-2">
                    <input 
                      type="number" 
                      className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm" 
                      value={selectedStep.slaDays || 0} 
                      onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, slaDays: parseInt(e.target.value)} : s))}
                    />
                    <span className="text-[10px] font-bold text-slate-400">DAYS</span>
                  </div>
                </div>
              </div>

              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">Description / Documentation</label>
                <textarea 
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm h-24 focus:ring-2 focus:ring-brand-500" 
                  placeholder="Business process instructions..."
                  value={selectedStep.description}
                  onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, description: e.target.value} : s))}
                />
              </div>

              <div className="pt-4 border-t border-slate-100 flex gap-3">
                 <button className="flex-1 py-3 bg-slate-900 text-white rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-slate-800">Advanced Logic</button>
                 <button className="flex-1 py-3 bg-brand-50 text-brand-700 border border-brand-200 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-brand-100">Integrations</button>
              </div>
           </div>
         )}
      </aside>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
