import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

/**
 * ErrorBoundary class component to catch and handle runtime errors gracefully.
 * Fixed: Explicitly using Component from 'react' with typed Props and State to resolve 'state' and 'props' member existence.
 */
export class ErrorBoundary extends Component<Props, State> {
  // Fixed: Initialize state as a public class field to ensure the type system recognizes it.
  public state: State = {
    hasError: false,
    error: null
  };

  constructor(props: Props) {
    super(props);
  }

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  private handleReload = () => {
    window.location.reload();
  };

  public render() {
    // Fixed: Accessed properties via destructuring to ensure TypeScript correctly resolves inherited members.
    const { hasError, error } = this.state;
    const { children } = this.props;

    if (hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4">
          <div className="bg-white p-8 rounded-xl shadow-lg border border-slate-200 max-w-md w-full text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-4">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-800 mb-2">Something went wrong</h1>
            <p className="text-slate-500 mb-6 text-sm">
              The application encountered an unexpected error. Our engineering team has been notified.
            </p>
            <div className="bg-slate-50 p-3 rounded-lg text-xs font-mono text-left mb-6 overflow-auto max-h-32 border border-slate-200 text-slate-600">
               {error?.message || 'Unknown Error'}
            </div>
            <button
              onClick={this.handleReload}
              className="w-full py-2.5 bg-brand-600 text-white rounded-lg font-medium hover:bg-brand-700 transition-colors flex items-center justify-center gap-2"
            >
              <RefreshCw size={16} /> Reload Application
            </button>
          </div>
        </div>
      );
    }

    // Fixed: Accessed 'children' from destructured 'props'.
    return children || null;
  }
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProcessStep } from '../types';

// Circuit Breaker State
let isServiceHealthy = true;
let lastErrorTime = 0;
const COOLDOWN_PERIOD = 30000; // 30 seconds

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return null;

  // Circuit Breaker logic: If service failed recently, don't try again immediately
  if (!isServiceHealthy && (Date.now() - lastErrorTime < COOLDOWN_PERIOD)) {
    console.warn("AI Circuit Breaker active. Using fallbacks.");
    return null;
  }

  return new GoogleGenAI({ apiKey });
};

const handleServiceError = (error: any) => {
  console.error("Gemini Service Error:", error);
  isServiceHealthy = false;
  lastErrorTime = Date.now();
};

export const generateProcessWorkflow = async (prompt: string): Promise<ProcessStep[]> => {
  const ai = getClient();

  const fallback: ProcessStep[] = [
    { id: 'start', name: 'Start', type: 'start', description: 'Process Started' },
    { id: 'task1', name: 'Initial Review', type: 'user-task', role: 'Operator', description: 'Manual verification of input' },
    { id: 'end', name: 'End', type: 'end', description: 'Process Ended' }
  ];

  if (!ai) return fallback;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Design a professional enterprise BPMN 2.0 workflow for: "${prompt}". 
      Requirements: 
      1. Logic-heavy steps.
      2. Clear roles (Management, IT, Finance).
      3. Precise descriptions.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              name: { type: Type.STRING },
              type: { type: Type.STRING, enum: ['start', 'user-task', 'service-task', 'decision', 'end', 'parallel-gateway'] },
              description: { type: Type.STRING },
              role: { type: Type.STRING }
            },
            required: ["id", "name", "type", "description"]
          }
        }
      }
    });

    isServiceHealthy = true; // Reset circuit breaker on success
    if (response.text) {
      return JSON.parse(response.text) as ProcessStep[];
    }
    return fallback;
  } catch (error: any) {
    handleServiceError(error);
    return fallback;
  }
};

export const analyzeProcessEfficiency = async (tasks: any[]): Promise<string> => {
  const ai = getClient();
  if (!ai) return "AI insights temporarily offline (Circuit Breaker). Optimize throughput by reducing parallel gateway bottlenecks.";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Executive Analysis: ${JSON.stringify(tasks.slice(0, 5))}. Provide 3 short bullet points on efficiency.`
    });
    isServiceHealthy = true;
    return response.text || "No insights available.";
  } catch (error: any) {
    handleServiceError(error);
    return "Analyzing operational buffers... focus on SLA compliance in core service tasks.";
  }
};

import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback, useRef } from 'react';
import { ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, TaskHistory, ProcessStep, ViewState } from '../types';
import { dbService } from '../services/dbService';

interface NavigationState {
  view: ViewState;
  selectedId?: string;
  filter?: string;
  mode?: 'view' | 'edit';
}

interface BPMContextType {
  processes: ProcessDefinition[];
  instances: ProcessInstance[];
  tasks: Task[];
  loading: boolean;
  error: string | null;
  nav: NavigationState;
  navigateTo: (view: ViewState, id?: string, filter?: string, mode?: 'view' | 'edit') => void;
  viewingInstanceId: string | null;
  openInstanceViewer: (instanceId: string) => void;
  closeInstanceViewer: () => void;
  deployProcess: (process: Omit<ProcessDefinition, 'id' | 'createdAt'>) => Promise<void>;
  startProcess: (definitionId: string, inputData: any) => Promise<string>;
  completeTask: (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => Promise<void>;
  adminOverrideStep: (instanceId: string, targetStepId: string) => Promise<void>;
  updateInstanceVariables: (instanceId: string, variables: Record<string, any>) => Promise<void>;
  toggleInstanceSuspension: (instanceId: string) => Promise<void>;
  addInstanceComment: (instanceId: string, comment: string) => Promise<void>;
  resetSystem: () => Promise<void>;
  reseedSystem: () => Promise<void>;
  exportData: () => Promise<void>;
  importData: (file: File) => Promise<void>;
  refreshData: () => Promise<void>;
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [processes, setProcesses] = useState<ProcessDefinition[]>([]);
  const [instances, setInstances] = useState<ProcessInstance[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [nav, setNav] = useState<NavigationState>({ view: 'dashboard' });
  const [viewingInstanceId, setViewingInstanceId] = useState<string | null>(null);

  // Use ref to prevent stale closures in async workflow logic
  const stateRef = useRef({ processes, instances, tasks });
  useEffect(() => {
    stateRef.current = { processes, instances, tasks };
  }, [processes, instances, tasks]);

  const navigateTo = (view: ViewState, id?: string, filter?: string, mode?: 'view' | 'edit') => {
    setNav({ view, selectedId: id, filter, mode });
  };

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const [p, i, t] = await Promise.all([
        dbService.getAll<ProcessDefinition>('processes'),
        dbService.getAll<ProcessInstance>('instances'),
        dbService.getAll<Task>('tasks')
      ]);
      setProcesses(p);
      setInstances(i);
      setTasks(t);
    } catch (e: any) {
      setError(e.message || "DB Error");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const deployProcess = async (processData: Omit<ProcessDefinition, 'id' | 'createdAt'>) => {
    const newProcess: ProcessDefinition = {
      ...processData,
      id: `proc-${Date.now()}`,
      createdAt: new Date().toISOString(),
      version: 1
    };
    await dbService.add('processes', newProcess);
    setProcesses(prev => [...prev, newProcess]);
    navigateTo('processes');
  };

  const advanceWorkflow = async (instanceId: string, completedStepId: string, action: string) => {
    const { processes, instances } = stateRef.current;
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;

    const definition = processes.find(p => p.id === instance.definitionId);
    if (!definition) return;

    // Logic for finding next steps via Links
    const outgoingLinks = definition.links?.filter(l => l.sourceId === completedStepId) || [];
    let nextStepIds: string[] = [];

    if (outgoingLinks.length > 0) {
      nextStepIds = outgoingLinks.map(l => l.targetId);
    } else {
      // Fallback: sequential progression
      const currentIndex = definition.steps.findIndex(s => s.id === completedStepId);
      if (currentIndex !== -1 && currentIndex < definition.steps.length - 1) {
        nextStepIds = [definition.steps[currentIndex + 1].id];
      }
    }

    const newActiveStepIds = instance.activeStepIds.filter(id => id !== completedStepId).concat(nextStepIds);
    let updatedInstance = { ...instance, activeStepIds: newActiveStepIds };

    // Terminal condition
    if (nextStepIds.length === 0 || nextStepIds.some(id => definition.steps.find(s => s.id === id)?.type === 'end')) {
      updatedInstance.status = 'Completed';
      updatedInstance.endDate = new Date().toISOString();
      updatedInstance.activeStepIds = [];
    }

    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));

    // Execute next steps logic
    for (const stepId of nextStepIds) {
      const step = definition.steps.find(s => s.id === stepId);
      if (step) await executeStepLogic(updatedInstance, definition, step);
    }
  };

  const executeStepLogic = async (instance: ProcessInstance, definition: ProcessDefinition, step: ProcessStep) => {
    if (step.type === 'service-task') {
      // Simulate enterprise service execution
      setTimeout(async () => {
        const hist: TaskHistory = {
          id: `h-${Date.now()}`,
          stepName: step.name,
          action: 'Auto-Complete',
          performer: 'System',
          timestamp: new Date().toISOString()
        };
        const fresh = await dbService.getAll<ProcessInstance>('instances');
        const inst = fresh.find(i => i.id === instance.id)!;
        const updated = { ...inst, history: [...inst.history, hist] };
        await dbService.add('instances', updated);
        await advanceWorkflow(instance.id, step.id, 'system_complete');
      }, 1200);
    } else if (step.type === 'user-task') {
      const newTask: Task = {
        id: `T-${Date.now()}`,
        title: step.name,
        processName: definition.name,
        processInstanceId: instance.id,
        assignee: step.role || 'Unassigned',
        dueDate: new Date(Date.now() + 86400000 * 2).toISOString().split('T')[0],
        status: TaskStatus.PENDING,
        priority: instance.priority,
        description: step.description,
        stepId: step.id
      };
      await dbService.add('tasks', newTask);
      setTasks(prev => [newTask, ...prev]);
    } else if (step.type === 'decision' || step.type === 'parallel-gateway') {
      // Automatic through-put
      await advanceWorkflow(instance.id, step.id, 'auto_pass');
    }
  };

  const startProcess = async (definitionId: string, inputData: any) => {
    const definition = processes.find(p => p.id === definitionId);
    if (!definition) throw new Error('Definition not found');

    const instanceId = `inst-${Date.now()}`;
    const startStep = definition.steps.find(s => s.type === 'start') || definition.steps[0];

    const newInstance: ProcessInstance = {
      id: instanceId,
      definitionId,
      definitionName: definition.name,
      status: 'Active',
      activeStepIds: [startStep.id],
      startDate: new Date().toISOString(),
      variables: inputData || {},
      priority: TaskPriority.MEDIUM,
      comments: [],
      history: [{
        id: `hist-${Date.now()}`,
        stepName: 'Start',
        action: 'Started',
        performer: 'User',
        timestamp: new Date().toISOString()
      }]
    };

    await dbService.add('instances', newInstance);
    setInstances(prev => [newInstance, ...prev]);
    await advanceWorkflow(instanceId, startStep.id, 'started');
    return instanceId;
  };

  const completeTask = async (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;

    const updatedTask = { ...task, status: TaskStatus.COMPLETED };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));

    const instance = instances.find(i => i.id === task.processInstanceId);
    if (instance) {
      const hist: TaskHistory = {
        id: `h-${Date.now()}`,
        stepName: task.title,
        action,
        performer: 'User',
        timestamp: new Date().toISOString(),
        comments
      };
      const updatedInst = { ...instance, history: [...instance.history, hist] };
      await dbService.add('instances', updatedInst);
      setInstances(prev => prev.map(i => i.id === instance.id ? updatedInst : i));

      if (action !== 'reject') {
        await advanceWorkflow(instance.id, task.stepId, action);
      } else {
        const terminated = { ...updatedInst, status: 'Terminated' as any, activeStepIds: [] };
        await dbService.add('instances', terminated);
        setInstances(prev => prev.map(i => i.id === instance.id ? terminated : i));
      }
    }
  };

  const adminOverrideStep = async (instanceId: string, targetStepId: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;
    const updatedInstance: ProcessInstance = {
      ...instance,
      activeStepIds: [targetStepId],
      history: [...instance.history, {
        id: `hist-${Date.now()}`,
        stepName: 'Admin Move',
        action: 'Override',
        performer: 'Administrator',
        timestamp: new Date().toISOString()
      }]
    };
    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));
  };

  const updateInstanceVariables = async (instanceId: string, variables: Record<string, any>) => {
    const instance = instances.find(i => i.id === instanceId);
    if (instance) {
      const updated = { ...instance, variables };
      await dbService.add('instances', updated);
      setInstances(prev => prev.map(i => i.id === instanceId ? updated : i));
    }
  };

  const toggleInstanceSuspension = async (instanceId: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (instance) {
      const updated = { ...instance, status: instance.status === 'Suspended' ? 'Active' : 'Suspended' } as any;
      await dbService.add('instances', updated);
      setInstances(prev => prev.map(i => i.id === instanceId ? updated : i));
    }
  };

  const addInstanceComment = async (instanceId: string, comment: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (instance) {
      const updated = { ...instance, comments: [...instance.comments, { user: 'Admin', text: comment, timestamp: new Date().toISOString() }] };
      await dbService.add('instances', updated);
      setInstances(prev => prev.map(i => i.id === instanceId ? updated : i));
    }
  };

  const resetSystem = async () => { await dbService.resetDB(); await loadData(); };
  const reseedSystem = async () => { await dbService.reseed(); await loadData(); };
  const exportData = async () => {
    const json = await dbService.exportData();
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `nexflow_backup_${Date.now()}.json`;
    a.click();
  };
  const importData = async (file: File) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      await dbService.importData(e.target?.result as string);
      await loadData();
    };
    reader.readAsText(file);
  };

  return (
    <BPMContext.Provider value={{ 
      processes, instances, tasks, loading, error,
      nav, navigateTo,
      viewingInstanceId, openInstanceViewer: setViewingInstanceId, closeInstanceViewer: () => setViewingInstanceId(null),
      deployProcess, startProcess, completeTask,
      adminOverrideStep, updateInstanceVariables, toggleInstanceSuspension, addInstanceComment,
      resetSystem, reseedSystem, exportData, importData, refreshData: loadData
    }}>
      {children}
    </BPMContext.Provider>
  );
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { ProcessStep, ProcessLink, Swimlane } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { 
  Wand2, Save, Play, User, Cog, GitBranch, Flag, Plus, Trash2, 
  Split, Maximize, MousePointer2, Info, AlertCircle, Zap, Layout, 
  StickyNote, ChevronDown, Menu, Search, Box, History, Scissors, 
  Move, Layers, Ruler, CheckCircle, Smartphone, Monitor, X
} from 'lucide-react';

const GRID_SIZE = 20;

export const ProcessDesigner: React.FC = () => {
  const { deployProcess, nav, navigateTo } = useBPM();
  const [processName, setProcessName] = useState('New Enterprise Workflow');

  // -- UI States --
  const [isPaletteOpen, setIsPaletteOpen] = useState(window.innerWidth > 1024);
  const [isPropertiesOpen, setIsPropertiesOpen] = useState(false);
  const [isValidationOpen, setIsValidationOpen] = useState(false);
  const [showGrid, setShowGrid] = useState(true);
  const [isMobilePreview, setIsMobilePreview] = useState(window.innerWidth < 768);

  // -- Editor Core State --
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [links, setLinks] = useState<ProcessLink[]>([]);
  const [lanes, setLanes] = useState<Swimlane[]>([
    { id: 'lane-1', name: 'Sales & Operations', height: 250 },
    { id: 'lane-2', name: 'Management Control', height: 250 }
  ]);
  const [viewport, setViewport] = useState({ x: 0, y: 0, zoom: 1 });
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Interaction Refs
  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'link' | 'lane'>('viewport');
  const activeId = useRef<string | null>(null);
  const ghostLink = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  // -- Snapping Logic --
  const snapToGrid = (val: number) => Math.round(val / GRID_SIZE) * GRID_SIZE;

  const screenToWorld = (sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return {
      x: (sx - rect.left - viewport.x) / viewport.zoom,
      y: (sy - rect.top - viewport.y) / viewport.zoom
    };
  };

  const addNode = (type: ProcessStep['type']) => {
    const world = screenToWorld(window.innerWidth / 2, window.innerHeight / 2);
    const newNode: ProcessStep = {
      id: `node-${Date.now()}`,
      name: `New ${type.replace('-', ' ')}`,
      type,
      description: '',
      laneId: lanes[0].id,
      position: { x: snapToGrid(world.x), y: snapToGrid(world.y) },
      nextStepIds: []
    };
    setSteps(prev => [...prev, newNode]);
    setSelectedId(newNode.id);
    if (window.innerWidth < 768) {
      setIsPaletteOpen(false);
      setIsPropertiesOpen(true);
    }
    if (navigator.vibrate) navigator.vibrate(10);
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const handleEl = target.closest('[data-handle-id]');

    dragStart.current = { x: e.clientX, y: e.clientY };
    isDragging.current = true;

    if (handleEl) {
      dragTarget.current = 'link';
      activeId.current = handleEl.getAttribute('data-handle-id');
    } else if (nodeEl) {
      dragTarget.current = 'node';
      activeId.current = nodeEl.getAttribute('data-node-id');
      setSelectedId(activeId.current);
      setIsPropertiesOpen(true);
    } else {
      dragTarget.current = 'viewport';
      if (!isPropertiesOpen) setSelectedId(null);
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    const dx = (e.clientX - dragStart.current.x) / viewport.zoom;
    const dy = (e.clientY - dragStart.current.y) / viewport.zoom;

    if (dragTarget.current === 'viewport') {
      setViewport(prev => ({ ...prev, x: prev.x + (e.clientX - dragStart.current.x), y: prev.y + (e.clientY - dragStart.current.y) }));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } else if (dragTarget.current === 'node' && activeId.current) {
      setSteps(prev => prev.map(s => s.id === activeId.current ? { 
        ...s, 
        position: { x: (s.position?.x || 0) + dx, y: (s.position?.y || 0) + dy } 
      } : s));
      dragStart.current = { x: e.clientX, y: e.clientY };
    } else if (dragTarget.current === 'link' && activeId.current) {
      const sNode = steps.find(s => s.id === activeId.current);
      if (sNode) {
        const world = screenToWorld(e.clientX, e.clientY);
        ghostLink.current = { x1: (sNode.position?.x||0)+180, y1: (sNode.position?.y||0)+40, x2: world.x, y2: world.y };
        setViewport(v => ({...v}));
      }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragTarget.current === 'link' && activeId.current) {
      const targetEl = document.elementFromPoint(e.clientX, e.clientY)?.closest('[data-node-id]');
      const tId = targetEl?.getAttribute('data-node-id');
      if (tId && tId !== activeId.current) {
        setLinks(prev => [...prev, { id: `link-${Date.now()}`, sourceId: activeId.current!, targetId: tId }]);
        if (navigator.vibrate) navigator.vibrate(20);
      }
    }

    if (dragTarget.current === 'node' && activeId.current) {
       setSteps(prev => prev.map(s => s.id === activeId.current ? {
         ...s,
         position: { x: snapToGrid(s.position?.x||0), y: snapToGrid(s.position?.y||0) }
       } : s));
    }

    isDragging.current = false;
    ghostLink.current = null;
    setViewport(v => ({...v}));
  };

  const validationErrors = useMemo(() => {
    const errs = [];
    if (!steps.some(s => s.type === 'start')) errs.push("Missing Start Event");
    if (!steps.some(s => s.type === 'end')) errs.push("Missing End Event");
    steps.forEach(s => {
      if (s.type !== 'end' && !links.some(l => l.sourceId === s.id)) errs.push(`Node '${s.name}' has no exit`);
      if (s.type !== 'start' && !links.some(l => l.targetId === s.id)) errs.push(`Node '${s.name}' is isolated`);
    });
    return errs;
  }, [steps, links]);

  const selectedStep = steps.find(s => s.id === selectedId);

  return (
    <div className={`h-[calc(100vh-140px)] flex flex-col md:flex-row bg-slate-100 rounded-2xl border border-slate-200 overflow-hidden relative shadow-2xl transition-all ${isMobilePreview ? 'max-w-[420px] mx-auto ring-8 ring-slate-800' : 'w-full'}`}>

      {/* Dynamic Header */}
      <div className="bg-white border-b border-slate-200 p-3 flex justify-between items-center z-50">
        <div className="flex items-center gap-4">
          <button onClick={() => setIsPaletteOpen(!isPaletteOpen)} className="p-2 bg-slate-50 border rounded-lg hover:bg-slate-100"><Menu size={18}/></button>
          <div className="hidden md:flex relative w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14}/>
            <input className="w-full pl-9 pr-4 py-1.5 bg-slate-50 border rounded-full text-xs" placeholder="Search components..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)}/>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <button onClick={() => setShowGrid(!showGrid)} className={`p-2 ${showGrid ? 'text-brand-600' : 'text-slate-400'}`}><Ruler size={18}/></button>
           <button onClick={() => setIsMobilePreview(!isMobilePreview)} className={`p-2 ${isMobilePreview ? 'text-brand-600' : 'text-slate-400'}`}><Smartphone size={18}/></button>
           <div className="h-6 w-px bg-slate-200 mx-2"></div>
           <button onClick={() => deployProcess({ name: processName, description: 'Enterprise Workflow', steps, links, lanes, deployedBy: 'Admin' })} className="bg-brand-600 text-white px-4 py-1.5 rounded-lg font-bold text-xs shadow-lg hover:bg-brand-700 flex items-center gap-2">
             <Save size={16}/> Deploy
           </button>
        </div>
      </div>

      {/* Palette */}
      <aside className={`absolute inset-y-0 left-0 w-72 bg-white/95 backdrop-blur-md border-r border-slate-200 z-40 transition-transform duration-300 transform md:relative md:translate-x-0 ${isPaletteOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'}`}>
        <div className="p-4 border-b flex justify-between items-center">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Repository</span>
          <button onClick={() => setIsPaletteOpen(false)} className="md:hidden"><X size={16}/></button>
        </div>
        <div className="p-4 space-y-6 overflow-y-auto h-full scrollbar-hide pb-20">
           <section className="space-y-2">
             <h4 className="text-[9px] font-bold text-slate-400 uppercase">Core Controls</h4>
             <div className="grid grid-cols-2 gap-2">
                <button onClick={() => addNode('start')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1"><Play size={20} className="text-green-500"/><span className="text-[10px] font-bold">Start</span></button>
                <button onClick={() => addNode('end')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1"><Flag size={20} className="text-slate-800"/><span className="text-[10px] font-bold">End</span></button>
                <button onClick={() => addNode('user-task')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1"><User size={20} className="text-blue-500"/><span className="text-[10px] font-bold">Activity</span></button>
                <button onClick={() => addNode('service-task')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1"><Cog size={20} className="text-purple-500"/><span className="text-[10px] font-bold">Service</span></button>
                <button onClick={() => addNode('decision')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1"><GitBranch size={20} className="text-amber-500"/><span className="text-[10px] font-bold">Gate</span></button>
                <button onClick={() => addNode('sub-process')} className="p-3 bg-slate-50 border rounded-xl hover:border-brand-500 flex flex-col items-center gap-1"><Box size={20} className="text-indigo-500"/><span className="text-[10px] font-bold">Scope</span></button>
             </div>
           </section>

           <div className="pt-4 border-t">
             <button onClick={() => setIsValidationOpen(!isValidationOpen)} className={`w-full p-3 rounded-xl border flex items-center justify-between ${validationErrors.length > 0 ? 'bg-red-50 border-red-200 text-red-700' : 'bg-green-50 border-green-200 text-green-700'}`}>
               <div className="flex items-center gap-2 font-bold text-xs"><Zap size={14}/> {validationErrors.length > 0 ? 'FIX NEEDED' : 'OPTIMAL'}</div>
               <span className="text-xs">{validationErrors.length}</span>
             </button>
             {isValidationOpen && validationErrors.length > 0 && (
               <div className="mt-3 space-y-1">
                 {validationErrors.map((e, i) => <div key={i} className="text-[9px] text-red-500 font-medium">• {e}</div>)}
               </div>
             )}
           </div>
        </div>
      </aside>

      {/* Canvas */}
      <div className="flex-1 relative overflow-hidden bg-slate-50 touch-none select-none">
        <div ref={canvasRef} className="absolute inset-0 cursor-crosshair" onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp}
          style={{ backgroundImage: showGrid ? 'radial-gradient(#cbd5e1 1.5px, transparent 1.5px)' : 'none', backgroundSize: `${20*viewport.zoom}px ${20*viewport.zoom}px`, backgroundPosition: `${viewport.x}px ${viewport.y}px` }}>
          <div style={{ transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`, transformOrigin: '0 0' }}>
            {/* Swimlanes */}
            <div className="absolute top-0 left-0 w-[5000px] pointer-events-none">
              {lanes.map(lane => (
                <div key={lane.id} className="border-b border-slate-200 relative flex bg-white/30" style={{ height: lane.height }}>
                   <div className="w-10 bg-slate-100 border-r flex items-center justify-center pointer-events-auto">
                      <span className="[writing-mode:vertical-lr] rotate-180 text-[9px] font-black text-slate-400">{lane.name}</span>
                   </div>
                </div>
              ))}
            </div>

            <svg className="overflow-visible absolute top-0 left-0 pointer-events-none">
              <defs><marker id="arrow" viewBox="0 0 10 10" refX="10" refY="5" markerWidth="6" markerHeight="6" orient="auto"><path d="M 0 0 L 10 5 L 0 10 z" fill="#94a3b8"/></marker></defs>
              {links.map(l => {
                const s = steps.find(n => n.id === l.sourceId);
                const t = steps.find(n => n.id === l.targetId);
                if (!s || !t) return null;
                const x1=(s.position?.x||0)+180; const y1=(s.position?.y||0)+40;
                const x2=(t.position?.x||0); const y2=(t.position?.y||0)+40;
                return <path key={l.id} d={`M ${x1} ${y1} C ${x1+60} ${y1}, ${x2-60} ${y2}, ${x2} ${y2}`} stroke="#94a3b8" strokeWidth="2" fill="none" markerEnd="url(#arrow)"/>
              })}
              {ghostLink.current && <line x1={ghostLink.current.x1} y1={ghostLink.current.y1} x2={ghostLink.current.x2} y2={ghostLink.current.y2} stroke="#0ea5e9" strokeWidth="2" strokeDasharray="4,4"/>}
            </svg>

            {steps.map(step => (
              <div key={step.id} data-node-id={step.id}
                className={`absolute w-[180px] h-[80px] bg-white rounded-xl border-2 shadow-sm p-3 flex flex-col transition-all active:scale-95 ${selectedId === step.id ? 'border-brand-500 shadow-xl z-30 scale-105' : 'border-slate-200'}`}
                style={{ left: step.position?.x, top: step.position?.y }}>
                <div className="flex items-center justify-between opacity-50 mb-1">
                  <span className="text-[8px] font-black uppercase text-slate-400">{step.type}</span>
                  <div data-handle-id={step.id} className="w-5 h-5 bg-slate-100 border rounded-full flex items-center justify-center cursor-crosshair hover:bg-brand-500 hover:text-white transition-colors"><Plus size={10}/></div>
                </div>
                <div className="text-xs font-bold text-slate-800 truncate">{step.name}</div>
                <div className="mt-auto flex justify-between items-center text-[7px] font-bold text-slate-400">
                   <span>{step.id.slice(-4)}</span>
                   {step.role && <span className="bg-slate-100 px-1 rounded uppercase">{step.role}</span>}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Mobile Drawer / Property Panel */}
      <aside className={`fixed inset-x-0 bottom-0 bg-white shadow-2xl z-[60] border-t transition-transform duration-500 md:relative md:inset-y-0 md:border-t-0 md:border-l md:w-96 md:translate-y-0 ${selectedId && isPropertiesOpen ? 'translate-y-0' : 'translate-y-full'}`}>
         <div className="p-4 border-b flex items-center justify-between">
            <h3 className="font-bold text-slate-800 text-xs uppercase tracking-widest">Properties</h3>
            <button onClick={() => setIsPropertiesOpen(false)} className="p-2 text-slate-400 hover:bg-slate-100 rounded-lg"><ChevronDown size={18}/></button>
         </div>
         {selectedStep && (
           <div className="p-6 space-y-6 overflow-y-auto max-h-[70vh] md:max-h-full scrollbar-hide">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">Activity Name</label>
                <input className="w-full p-3 bg-slate-50 border rounded-xl text-sm font-bold focus:ring-2 focus:ring-brand-500" value={selectedStep.name} onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, name: e.target.value} : s))}/>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">Responsible Role</label>
                  <input className="w-full p-3 bg-slate-50 border rounded-xl text-sm" placeholder="Manager" value={selectedStep.role || ''} onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, role: e.target.value} : s))}/>
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">SLA Target (Days)</label>
                  <input type="number" className="w-full p-3 bg-slate-50 border rounded-xl text-sm" value={selectedStep.slaDays || 0} onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, slaDays: parseInt(e.target.value)} : s))}/>
                </div>
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase mb-1.5 block">Operational Details</label>
                <textarea className="w-full p-3 bg-slate-50 border rounded-xl text-sm h-24" placeholder="Instructions..." value={selectedStep.description} onChange={e => setSteps(steps.map(s => s.id === selectedId ? {...s, description: e.target.value} : s))}/>
              </div>
              <div className="pt-4 border-t flex gap-3">
                 <button onClick={() => { setSteps(prev => prev.filter(s => s.id !== selectedId)); setLinks(prev => prev.filter(l => l.sourceId !== selectedId && l.targetId !== selectedId)); setSelectedId(null); }} className="flex-1 py-3 bg-red-50 text-red-700 rounded-xl font-bold text-xs uppercase">Delete Node</button>
                 <button className="flex-1 py-3 bg-brand-600 text-white rounded-xl font-bold text-xs uppercase">Commit Logic</button>
              </div>
           </div>
         )}
      </aside>
    </div>
  );
};

import React, { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

/**
 * ErrorBoundary class component to catch and handle runtime errors gracefully.
 */
// Fix: Explicitly using React.Component to ensure inherited 'props' and 'state' properties are correctly typed and accessible by the TypeScript compiler.
export class ErrorBoundary extends React.Component<Props, State> {
  // Fix: Move state initialization to the constructor to adhere to standard React class component implementation and resolve potential member existence issues.
  constructor(props: Props) {
    super(props);
    this.state = {
      hasError: false,
      error: null
    };
  }

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  private handleReload = () => {
    window.location.reload();
  };

  public render() {
    const { hasError, error } = this.state;
    const { children } = this.props;

    if (hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4">
          <div className="bg-white p-8 rounded-xl shadow-lg border border-slate-200 max-w-md w-full text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-4">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold text-slate-800 mb-2">Something went wrong</h1>
            <p className="text-slate-500 mb-6 text-sm">
              The application encountered an unexpected error. Our engineering team has been notified.
            </p>
            <div className="bg-slate-50 p-3 rounded-lg text-xs font-mono text-left mb-6 overflow-auto max-h-32 border border-slate-200 text-slate-600">
               {error?.message || 'Unknown Error'}
            </div>
            <button
              onClick={this.handleReload}
              className="w-full py-2.5 bg-brand-600 text-white rounded-lg font-medium hover:bg-brand-700 transition-colors flex items-center justify-center gap-2"
            >
              <RefreshCw size={16} /> Reload Application
            </button>
          </div>
        </div>
      );
    }

    return children || null;
  }
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProcessStep } from '../types';

// Circuit Breaker State
let isServiceHealthy = true;
let lastErrorTime = 0;
const COOLDOWN_PERIOD = 30000; // 30 seconds

// Fix: Directly use process.env.API_KEY when initializing the GoogleGenAI instance for strict compliance with the SDK guidelines.
const getClient = () => {
  if (!process.env.API_KEY) return null;

  // Circuit Breaker logic: If service failed recently, don't try again immediately
  if (!isServiceHealthy && (Date.now() - lastErrorTime < COOLDOWN_PERIOD)) {
    console.warn("AI Circuit Breaker active. Using fallbacks.");
    return null;
  }

  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const handleServiceError = (error: any) => {
  console.error("Gemini Service Error:", error);
  isServiceHealthy = false;
  lastErrorTime = Date.now();
};

export const generateProcessWorkflow = async (prompt: string): Promise<ProcessStep[]> => {
  const ai = getClient();

  const fallback: ProcessStep[] = [
    { id: 'start', name: 'Start', type: 'start', description: 'Process Started' },
    { id: 'task1', name: 'Initial Review', type: 'user-task', role: 'Operator', description: 'Manual verification of input' },
    { id: 'end', name: 'End', type: 'end', description: 'Process Ended' }
  ];

  if (!ai) return fallback;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Design a professional enterprise BPMN 2.0 workflow for: "${prompt}". 
      Requirements: 
      1. Logic-heavy steps.
      2. Clear roles (Management, IT, Finance).
      3. Precise descriptions.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              name: { type: Type.STRING },
              type: { type: Type.STRING, enum: ['start', 'user-task', 'service-task', 'decision', 'end', 'parallel-gateway'] },
              description: { type: Type.STRING },
              role: { type: Type.STRING }
            },
            required: ["id", "name", "type", "description"]
          }
        }
      }
    });

    isServiceHealthy = true; // Reset circuit breaker on success
    if (response.text) {
      return JSON.parse(response.text) as ProcessStep[];
    }
    return fallback;
  } catch (error: any) {
    handleServiceError(error);
    return fallback;
  }
};

export const analyzeProcessEfficiency = async (tasks: any[]): Promise<string> => {
  const ai = getClient();
  if (!ai) return "AI insights temporarily offline (Circuit Breaker). Optimize throughput by reducing parallel gateway bottlenecks.";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Executive Analysis: ${JSON.stringify(tasks.slice(0, 5))}. Provide 3 short bullet points on efficiency.`
    });
    isServiceHealthy = true;
    // Fix: Access .text property directly as it is a getter, not a method.
    return response.text || "No insights available.";
  } catch (error: any) {
    handleServiceError(error);
    return "Analyzing operational buffers... focus on SLA compliance in core service tasks.";
  }
};

export enum TaskStatus {
