export type ViewState = 'dashboard' | 'inbox' | 'explorer' | 'processes' | 'designer' | 'analytics' | 'governance' | 'settings' | 'instance-viewer';

import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback, useRef } from 'react';
import { ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, TaskHistory, ProcessStep, ViewState, AuditLog, Comment } from '../types';
import { dbService } from '../services/dbService';

interface NavigationState {
  view: ViewState;
  selectedId?: string;
  filter?: string;
  mode?: 'view' | 'edit';
}

interface BPMContextType {
  processes: ProcessDefinition[];
  instances: ProcessInstance[];
  tasks: Task[];
  auditLogs: AuditLog[];
  loading: boolean;
  error: string | null;
  nav: NavigationState;
  navigateTo: (view: ViewState, id?: string, filter?: string, mode?: 'view' | 'edit') => void;
  viewingInstanceId: string | null;
  openInstanceViewer: (instanceId: string) => void;
  closeInstanceViewer: () => void;

  // Enterprise Actions
  deployProcess: (process: Omit<ProcessDefinition, 'id' | 'createdAt' | 'version' | 'isActive'>) => Promise<void>;
  startProcess: (definitionId: string, inputData: any) => Promise<string>;

  // Human-Centric Task Management
  claimTask: (taskId: string) => Promise<void>;
  releaseTask: (taskId: string) => Promise<void>;
  completeTask: (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => Promise<void>;
  addTaskComment: (taskId: string, text: string) => Promise<void>;

  // Governance & Admin
  adminOverrideStep: (instanceId: string, targetStepId: string) => Promise<void>;
  updateInstanceVariables: (instanceId: string, variables: Record<string, any>) => Promise<void>;
  toggleInstanceSuspension: (instanceId: string) => Promise<void>;
  addInstanceComment: (instanceId: string, text: string) => Promise<void>;

  // System
  resetSystem: () => Promise<void>;
  reseedSystem: () => Promise<void>;
  exportData: () => Promise<void>;
  importData: (file: File) => Promise<void>;
  refreshData: () => Promise<void>;
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [processes, setProcesses] = useState<ProcessDefinition[]>([]);
  const [instances, setInstances] = useState<ProcessInstance[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [nav, setNav] = useState<NavigationState>({ view: 'dashboard' });
  const [viewingInstanceId, setViewingInstanceId] = useState<string | null>(null);

  const stateRef = useRef({ processes, instances, tasks, auditLogs });
  useEffect(() => {
    stateRef.current = { processes, instances, tasks, auditLogs };
  }, [processes, instances, tasks, auditLogs]);

  const logAudit = async (action: string, entityType: AuditLog['entityType'], entityId: string, details: string, severity: AuditLog['severity'] = 'Info') => {
    const log: AuditLog = {
      id: `log-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      timestamp: new Date().toISOString(),
      userId: 'admin-user',
      action,
      entityType,
      entityId,
      details,
      severity
    };
    await dbService.add('auditLogs', log);
    setAuditLogs(prev => [log, ...prev]);
  };

  const navigateTo = (view: ViewState, id?: string, filter?: string, mode?: 'view' | 'edit') => {
    setNav({ view, selectedId: id, filter, mode });
  };

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const [p, i, t, al] = await Promise.all([
        dbService.getAll<ProcessDefinition>('processes'),
        dbService.getAll<ProcessInstance>('instances'),
        dbService.getAll<Task>('tasks'),
        dbService.getAll<AuditLog>('auditLogs')
      ]);
      setProcesses(p);
      setInstances(i);
      setTasks(t);
      setAuditLogs(al || []);
    } catch (e: any) {
      setError(e.message || "DB Error");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const deployProcess = async (processData: Omit<ProcessDefinition, 'id' | 'createdAt' | 'version' | 'isActive'>) => {
    const existing = processes.find(p => p.name === processData.name);
    const newVersion = existing ? existing.version + 1 : 1;

    // Governance: Deactivate previous versions
    if (existing) {
      const updatedExisting = { ...existing, isActive: false };
      await dbService.add('processes', updatedExisting);
    }

    const newProcess: ProcessDefinition = {
      ...processData,
      id: `proc-${Date.now()}`,
      createdAt: new Date().toISOString(),
      version: newVersion,
      isActive: true,
      complianceLevel: processData.complianceLevel || 'Standard'
    };

    await dbService.add('processes', newProcess);
    await logAudit('DEPLOY', 'Process', newProcess.id, `Deployed version ${newVersion} of ${newProcess.name}`);

    setProcesses(prev => [newProcess, ...prev.map(p => p.name === processData.name ? { ...p, isActive: false } : p)]);
    navigateTo('processes');
  };

  const advanceWorkflow = async (instanceId: string, completedStepId: string, action: string) => {
    const { processes, instances } = stateRef.current;
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;

    const definition = processes.find(p => p.id === instance.definitionId);
    if (!definition) return;

    const outgoingLinks = definition.links?.filter(l => l.sourceId === completedStepId) || [];
    let nextStepIds: string[] = [];

    if (outgoingLinks.length > 0) {
      nextStepIds = outgoingLinks.map(l => l.targetId);
    } else {
      const currentIndex = definition.steps.findIndex(s => s.id === completedStepId);
      if (currentIndex !== -1 && currentIndex < definition.steps.length - 1) {
        nextStepIds = [definition.steps[currentIndex + 1].id];
      }
    }

    const newActiveStepIds = instance.activeStepIds.filter(id => id !== completedStepId).concat(nextStepIds);
    let updatedInstance = { ...instance, activeStepIds: newActiveStepIds };

    if (nextStepIds.length === 0 || nextStepIds.some(id => definition.steps.find(s => s.id === id)?.type === 'end')) {
      updatedInstance.status = 'Completed';
      updatedInstance.endDate = new Date().toISOString();
      updatedInstance.activeStepIds = [];
      await logAudit('FINISH', 'Instance', instance.id, `Process instance completed: ${definition.name}`);
    }

    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));

    for (const stepId of nextStepIds) {
      const step = definition.steps.find(s => s.id === stepId);
      if (step) await executeStepLogic(updatedInstance, definition, step);
    }
  };

  const executeStepLogic = async (instance: ProcessInstance, definition: ProcessDefinition, step: ProcessStep) => {
    if (step.type === 'service-task') {
      setTimeout(async () => {
        const hist: TaskHistory = {
          id: `h-${Date.now()}`,
          stepName: step.name,
          action: 'Auto-Complete',
          performer: 'System',
          timestamp: new Date().toISOString()
        };
        const fresh = await dbService.getAll<ProcessInstance>('instances');
        const inst = fresh.find(i => i.id === instance.id)!;
        const updated = { ...inst, history: [...inst.history, hist] };
        await dbService.add('instances', updated);
        await advanceWorkflow(instance.id, step.id, 'system_complete');
      }, 1000);
    } else if (step.type === 'user-task') {
      const newTask: Task = {
        id: `T-${Date.now()}`,
        title: step.name,
        processName: definition.name,
        processInstanceId: instance.id,
        assignee: 'Unassigned',
        candidateRoles: step.role ? [step.role] : ['Employee'],
        dueDate: new Date(Date.now() + 86400000 * (step.slaDays || 2)).toISOString().split('T')[0],
        status: TaskStatus.PENDING,
        priority: instance.priority,
        description: step.description,
        stepId: step.id,
        comments: [],
        attachments: []
      };
      await dbService.add('tasks', newTask);
      setTasks(prev => [newTask, ...prev]);
    } else if (step.type === 'decision' || step.type === 'parallel-gateway') {
      await advanceWorkflow(instance.id, step.id, 'auto_pass');
    }
  };

  const startProcess = async (definitionId: string, inputData: any) => {
    const definition = processes.find(p => p.id === definitionId);
    if (!definition) throw new Error('Definition not found');

    const instanceId = `inst-${Date.now()}`;
    const startStep = definition.steps.find(s => s.type === 'start') || definition.steps[0];

    const newInstance: ProcessInstance = {
      id: instanceId,
      definitionId,
      definitionName: definition.name,
      status: 'Active',
      activeStepIds: [startStep.id],
      startDate: new Date().toISOString(),
      variables: inputData || {},
      priority: TaskPriority.MEDIUM,
      comments: [],
      history: [{
        id: `hist-${Date.now()}`,
        stepName: 'Start',
        action: 'Started',
        performer: 'User',
        timestamp: new Date().toISOString()
      }],
      complianceVerified: definition.complianceLevel === 'Standard'
    };

    await dbService.add('instances', newInstance);
    setInstances(prev => [newInstance, ...prev]);
    await logAudit('START', 'Instance', instanceId, `Started instance of ${definition.name}`);
    await advanceWorkflow(instanceId, startStep.id, 'started');
    return instanceId;
  };

  const claimTask = async (taskId: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;
    const updatedTask = { ...task, status: TaskStatus.CLAIMED, assignee: 'Principal Admin' };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));
    await logAudit('CLAIM', 'Task', taskId, `Task claimed by Principal Admin`);
  };

  const releaseTask = async (taskId: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;
    const updatedTask = { ...task, status: TaskStatus.PENDING, assignee: 'Unassigned' };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));
    await logAudit('RELEASE', 'Task', taskId, `Task released to candidate pool`);
  };

  const completeTask = async (taskId: string, action: 'approve' | 'reject' | 'submit', comments?: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;

    const updatedTask = { ...task, status: TaskStatus.COMPLETED };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));

    const instance = instances.find(i => i.id === task.processInstanceId);
    if (instance) {
      const hist: TaskHistory = {
        id: `h-${Date.now()}`,
        stepName: task.title,
        action,
        performer: 'Principal Admin',
        timestamp: new Date().toISOString(),
        comments
      };
      const updatedInst = { ...instance, history: [...instance.history, hist] };
      await dbService.add('instances', updatedInst);
      setInstances(prev => prev.map(i => i.id === instance.id ? updatedInst : i));

      await logAudit('COMPLETE', 'Task', taskId, `Task completed with action: ${action}`);
      if (action !== 'reject') {
        await advanceWorkflow(instance.id, task.stepId, action);
      } else {
        const terminated = { ...updatedInst, status: 'Terminated' as any, activeStepIds: [] };
        await dbService.add('instances', terminated);
        setInstances(prev => prev.map(i => i.id === instance.id ? terminated : i));
        await logAudit('TERMINATE', 'Instance', instance.id, `Process terminated due to rejection at ${task.title}`);
      }
    }
  };

  const addTaskComment = async (taskId: string, text: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;
    const newComment: Comment = {
      id: `c-${Date.now()}`,
      userId: 'admin-user',
      userName: 'Principal Admin',
      text,
      timestamp: new Date().toISOString()
    };
    const updatedTask = { ...task, comments: [...task.comments, newComment] };
    await dbService.add('tasks', updatedTask);
    setTasks(prev => prev.map(t => t.id === taskId ? updatedTask : t));
  };

  const adminOverrideStep = async (instanceId: string, targetStepId: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (!instance) return;
    const updatedInstance: ProcessInstance = {
      ...instance,
      activeStepIds: [targetStepId],
      history: [...instance.history, {
        id: `hist-${Date.now()}`,
        stepName: 'Admin Move',
        action: 'Override',
        performer: 'Administrator',
        timestamp: new Date().toISOString()
      }]
    };
    await dbService.add('instances', updatedInstance);
    setInstances(prev => prev.map(i => i.id === instanceId ? updatedInstance : i));
    await logAudit('OVERRIDE', 'Instance', instanceId, `Admin moved execution pointer to ${targetStepId}`, 'Warning');
  };

  const updateInstanceVariables = async (instanceId: string, variables: Record<string, any>) => {
    const instance = instances.find(i => i.id === instanceId);
    if (instance) {
      const updated = { ...instance, variables };
      await dbService.add('instances', updated);
      setInstances(prev => prev.map(i => i.id === instanceId ? updated : i));
      await logAudit('UPDATE', 'Instance', instanceId, `State variables modified by administrator`);
    }
  };

  const toggleInstanceSuspension = async (instanceId: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (instance) {
      const updated = { ...instance, status: instance.status === 'Suspended' ? 'Active' : 'Suspended' } as any;
      await dbService.add('instances', updated);
      setInstances(prev => prev.map(i => i.id === instanceId ? updated : i));
      await logAudit('SUSPEND', 'Instance', instanceId, `Instance suspension toggled`);
    }
  };

  const addInstanceComment = async (instanceId: string, text: string) => {
    const instance = instances.find(i => i.id === instanceId);
    if (instance) {
      const newComment: Comment = {
        id: `c-${Date.now()}`,
        userId: 'admin-user',
        userName: 'Principal Admin',
        text,
        timestamp: new Date().toISOString()
      };
      const updated = { ...instance, comments: [...instance.comments, newComment] };
      await dbService.add('instances', updated);
      setInstances(prev => prev.map(i => i.id === instanceId ? updated : i));
    }
  };

  const resetSystem = async () => { 
    await dbService.resetDB(); 
    await logAudit('RESET', 'System', 'nexflow', 'Total system factory reset performed', 'Alert');
    await loadData(); 
  };

  const reseedSystem = async () => { 
    await dbService.reseed(); 
    await logAudit('RESEED', 'System', 'nexflow', 'System reseeded with demo data');
    await loadData(); 
  };

  const exportData = async () => {
    const json = await dbService.exportData();
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `nexflow_backup_${Date.now()}.json`;
    a.click();
    await logAudit('EXPORT', 'System', 'nexflow', 'System database exported for backup');
  };

  const importData = async (file: File) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      await dbService.importData(e.target?.result as string);
      await logAudit('IMPORT', 'System', 'nexflow', 'System database imported from backup', 'Warning');
      await loadData();
    };
    reader.readAsText(file);
  };

  return (
    <BPMContext.Provider value={{ 
      processes, instances, tasks, auditLogs, loading, error,
      nav, navigateTo,
      viewingInstanceId, openInstanceViewer: setViewingInstanceId, closeInstanceViewer: () => setViewingInstanceId(null),
      deployProcess, startProcess, claimTask, releaseTask, completeTask, addTaskComment,
      adminOverrideStep, updateInstanceVariables, toggleInstanceSuspension, addInstanceComment,
      resetSystem, reseedSystem, exportData, importData, refreshData: loadData
    }}>
      {children}
    </BPMContext.Provider>
  );
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

