        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-300 bg-slate-50/30">
            <div className="w-20 h-20 rounded-full bg-white border-4 border-slate-100 flex items-center justify-center mb-4">
              <CheckSquare size={32} />
